const e=[{id:"finance-0001",location:"finance",arc:"finance-t0-a0",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:"The bank boss says the country is running out of money fast, but you have been pretending you have more. He says people will find out the truth soon.",left:{id:"a",label:"Keep pretending you have lots of money.",tooltip:"Confidence is a currency too.",reveal:"The headline reserves look calm; importers and rating agencies quietly stop believing you, and the black-market dollar climbs.",effects:{FI:3,GL:-13,EN:-6}},right:{id:"b",label:"Tell the truth about having less money.",tooltip:"A lie in the books is a run waiting to happen.",reveal:"The honesty stings the markets for a week, then steadies them. The IMF, reassured by candour, eases the next tranche.",effects:{FI:-10,GL:8,MI:-6}}},{id:"finance-0002",location:"finance",arc:"finance-t0-a0",stage:1,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:"You are spending all the country's savings to make your money look strong. The bank boss says you must stop, even if it makes things very expensive.",left:{id:"a",label:"Stop spending savings and let prices go up.",tooltip:"Better a fair price than an empty vault.",reveal:"The taka drops; exporters and remitters cheer while every imported good — fuel, food, medicine — jumps overnight. The streets feel it instantly.",effects:{FI:6,GL:5,EN:-18}},right:{id:"b",label:"Keep spending savings to look strong.",tooltip:"A cliff-edge devaluation would break the poor.",reveal:"You hold the line a while longer at the cost of the vault. The reserves thin toward the danger mark and the market sniffs the weakness.",effects:{FI:-16,EN:5,GL:-6}}},{id:"finance-0003",location:"finance",arc:"finance-t0-a0",stage:2,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:"You are out of money. A big global bank will give you emergency money, but only if you make gas prices very high right now. Your helpers say angry people will fill the streets.",left:{id:"a",label:"Take the money and raise gas prices.",tooltip:"Solvency now, anger managed later.",reveal:"Dollars refill the vault as fuel and power prices spike. The crisis on the balance sheet becomes a crisis in the bazaars.",effects:{FI:10,GL:6,EN:-18,MI:-6}},right:{id:"b",label:"Say no and look for money somewhere else.",tooltip:"I will not detonate prices on a foreign schedule.",reveal:"You borrow from friendly capitals instead — costlier, with strings of their own. The subsidy holds; the debt stack grows more dangerous.",effects:{FI:3,GL:-6,EN:5,RE:-6}}},{id:"finance-0004",location:"finance",arc:"finance-t0-a1",stage:0,speaker:"Bank Reform Commissioner",portrait:"official",tags:["banks","default-loans","cronies"],prompt:"Rich families who give you money are secretly stealing from the banks. If you tell the truth, the banks will look broken. If you hide it, the banks will rot from the inside.",left:{id:"a",label:"Keep hiding it so the banks look fine.",tooltip:"These men keep the party funded.",reveal:"The books stay pretty and the donors stay loyal. The hole grows in the dark, and one bank's collapse could pull down the rest.",effects:{FI:5,FA:3,GL:-13,EN:-6}},right:{id:"b",label:"Tell the truth and make them pay it back.",tooltip:"A looted bank is a tax on every saver.",reveal:"You name the defaulters and freeze their rolling. The donors revolt and the books look grim — but depositors, and the IMF, exhale.",effects:{FI:-13,GL:8,MI:-6,FA:-10}}},{id:"finance-0005",location:"finance",arc:"finance-t0-a1",stage:1,speaker:"Bank Reform Commissioner",portrait:"official",tags:["banks","default-loans","cronies"],prompt:"You caught the biggest bank thief, but he owns TV stations and helps your team. He offers to pay back a little bit and say nice things about you on TV if you let him go.",left:{id:"a",label:"Take the deal and the nice TV news.",tooltip:"Half a recovery and a friendly press is no small thing.",reveal:"He repays a fraction and his channels glow for you. Every other defaulter learns the price of getting caught is merely negotiable.",effects:{FI:3,FA:5,GL:-10,MI:3}},right:{id:"b",label:"Make him pay back every penny, no matter what.",tooltip:"The law cannot have a discount for the loud.",reveal:"You break him publicly. His networks turn on you nightly — but the message lands that the era of free money is over.",effects:{FI:6,GL:5,FA:-13,MI:-10}}},{id:"finance-0006",location:"finance",arc:"finance-t0-a2",stage:0,speaker:"Expatriate Welfare Secretary",portrait:"official",tags:["remittances","hundi","diaspora"],prompt:"Workers in other countries are sending money home secretly because it's cheaper. This means your government doesn't get to count it. You can offer them a bonus to send it legally.",left:{id:"a",label:"Pay them a bonus to send money legally.",tooltip:"Buy the dollars back into the system.",reveal:"Formal inflows jump and the reserves breathe — at a real fiscal cost, and with smugglers adapting their margins fast.",effects:{FI:6,EN:3,GL:3}},right:{id:"b",label:"Send police to stop the secret money networks.",tooltip:"Punish the channel, not subsidise the rival.",reveal:"Raids disrupt the networks briefly. The operators reroute through crypto and gold; workers, harassed, trust the banks even less.",effects:{FI:-6,MI:5,GL:-6}}},{id:"finance-0007",location:"finance",arc:"finance-t0-a3",stage:0,speaker:"Garment Buyers' Consortium",portrait:"official",tags:["rmg","exports","wages"],prompt:"People who buy your country's clothes say you must pay workers more and make factories safer, or they will stop buying. Factory owners say paying more will ruin them.",left:{id:"a",label:"Force the owners to pay workers more.",tooltip:"Cheap labour is a race we lose anyway.",reveal:"Wages rise; the buyers stay and the workers quiet. Marginal factories shutter, and the owners — your donors — are furious.",effects:{GL:6,EN:6,FI:-13,FA:-6}},right:{id:"b",label:"Protect the owners and keep wages low.",tooltip:"Mills closed help no worker at all.",reveal:"The owners are grateful and the lines keep running. Some buyers quietly diversify away, and the wage protests build.",effects:{FI:6,FA:5,EN:-16,GL:-10}}},{id:"finance-0008",location:"finance",arc:"finance-t0-a4",stage:0,speaker:"Megaproject Coordinator",portrait:"official",tags:["debt","infrastructure","china"],prompt:"You built giant bridges and trains using borrowed money. Now you must pay it back, but you don't have enough. One lender wants to own your boat docks if you can't pay.",left:{id:"a",label:"Let them own the boat docks so you get more time.",tooltip:"Keep the cranes turning at any cost.",reveal:"The repayment is rescheduled and construction continues. A strategic port is now partly mortgaged to a foreign creditor.",effects:{FI:5,RE:-10,GL:-13,MI:-6}},right:{id:"b",label:"Stop building new things and pay the money back now.",tooltip:"No more monuments we cannot afford.",reveal:"You freeze the ribbon-cuttings to service the debt. The optics dull and contractors grumble, but the balance sheet stops bleeding.",effects:{FI:6,GL:3,EN:-6,FA:-6}}},{id:"finance-0009",location:"finance",arc:"finance-t0-a5",stage:0,speaker:"Financial Intelligence Chief",portrait:"official",tags:["laundering","capital-flight","elite"],prompt:"Rich people who complain about the country are secretly hiding their money in other countries. Many of them are your friends.",left:{id:"a",label:"Hide the secret so your friends don't get in trouble.",tooltip:"These are the people who hold the regime up.",reveal:"The list disappears and the friends stay close. The reserves keep leaking out the back door you chose not to lock.",effects:{FI:-10,FA:5,GL:-10}},right:{id:"b",label:"Tell everyone and freeze your friends' money.",tooltip:"Patriotism that flees with the money is none.",reveal:"You name and freeze. The elite is enraged and the courts will be slow — but capital flight stutters and the public roars approval.",effects:{FI:6,EN:5,GL:5,FA:-13}}},{id:"finance-0010",location:"finance",arc:"finance-t0-a6",stage:0,speaker:"Trade & Prices Adviser",portrait:"people",tags:["inflation","subsidies","food"],prompt:"Food is too expensive and people are hungry and angry. You can buy cheap food from other countries to help, but it will cost the government a lot of money.",left:{id:"a",label:"Buy the cheap food from outside to help people.",tooltip:"An empty plate topples governments faster than deficits.",reveal:"Prices ease at the bazaar and tempers cool. The deficit widens and local farmers, undercut, send their own anger upward.",effects:{EN:8,FI:-13,RE:-6}},right:{id:"b",label:"Do not buy it, and tell people to eat less.",tooltip:"Cheap imports today, dead farms tomorrow.",reveal:"The farmers keep their margins and the budget holds. Urban households seethe as the kitchen stays expensive.",effects:{FI:5,RE:3,EN:-16,FA:-6}}},{id:"finance-0011",location:"finance",arc:"finance-t0-a7",stage:0,speaker:"Sovereign Ratings Analyst",portrait:"ambassador",tags:["rating","markets","confidence"],prompt:"A judge who grades your country's money is going to give you a bad grade. He hints he will give you a good grade if you secretly give him gifts.",left:{id:"a",label:"Secretly give him gifts to get a good grade.",tooltip:"A friendly rating is cheaper than a downgrade.",reveal:"The downgrade is shelved this cycle. The fix is fragile and faintly corrupt; the next analyst may not be so amenable.",effects:{FI:5,GL:-10,EN:-6}},right:{id:"b",label:"Show him the honest truth and accept a bad grade.",tooltip:"I will not bribe my way out of arithmetic.",reveal:"You bare the fiscal accounts honestly. The downgrade may come, but investors who reward candour begin, cautiously, to return.",effects:{FI:-10,GL:6,MI:-3}}},{id:"finance-0012",location:"finance",arc:"finance-t0-a8",stage:0,speaker:"NBR Chairman",portrait:"official",tags:["tax","nbr","informal"],prompt:"Almost nobody pays taxes. Your helper wants to force shopkeepers to pay, but those shopkeepers give you money for your campaigns.",left:{id:"a",label:"Force the shopkeepers to pay taxes.",tooltip:"A state cannot run on 2% of its people.",reveal:"Revenue creeps up and the IMF nods — while market associations declare a shutter-down strike against you.",effects:{FI:10,GL:5,EN:-13,FA:-6}},right:{id:"b",label:"Be nice to them and don't force them.",tooltip:"Do not squeeze the people who keep me standing.",reveal:"The committees stay loyal and the books stay thin. The tax-to-GDP ratio remains among the lowest on earth.",effects:{FA:6,FI:-13,GL:-10}}},{id:"finance-0013",location:"finance",arc:"finance-t0-a9",stage:0,speaker:"Budget Adviser",portrait:"official",tags:["black-money","whitening","budget"],prompt:"People are hiding stolen money. You can let them keep it if they pay a tiny tax, and you won't ask any questions. This rewards bad guys but gives you some money.",left:{id:"a",label:"Let them keep the stolen money and pay a tiny tax.",tooltip:"Better the money home than abroad.",reveal:"Hidden fortunes surface and the deficit eases. Honest taxpayers fume that crime pays a lower rate than they do.",effects:{FI:10,EN:-13,GL:-10}},right:{id:"b",label:"Say no to this bad rule.",tooltip:"I will not legislate a discount for thieves.",reveal:"You close the loophole on principle. The flagged billions stay offshore, and the budget must find them elsewhere.",effects:{GL:5,EN:5,FI:-16}}},{id:"finance-0014",location:"finance",arc:"finance-t0-a10",stage:0,speaker:"Stock Exchange Chair",portrait:"official",tags:["dse","market","retail"],prompt:"The stock market is crashing and normal people are losing their money. They are very angry. Your helper wants to create a fake rule to stop prices from dropping.",left:{id:"a",label:"Make the fake rule to stop prices from dropping.",tooltip:"Stop the bleeding on the screens.",reveal:"The index steadies on paper; trading dries up as no one will buy a price that cannot fall. Foreign funds flee the frozen market.",effects:{EN:5,FI:-10,GL:-13}},right:{id:"b",label:"Let the prices fall naturally and teach people how it works.",tooltip:"A propped market is a trap with a delay.",reveal:"The index overshoots down, then finds a real bottom. The pain is sharp and the recovery, when it comes, is trusted.",effects:{GL:5,FI:3,EN:-13}}},{id:"finance-0015",location:"finance",arc:"finance-t0-a10",stage:1,speaker:"Stock Exchange Chair",portrait:"official",tags:["dse","market","retail"],prompt:"The stock market is broken. A very rich man says he will fix it, but only if you give him a free bank and a phone company in return.",left:{id:"a",label:"Give him the bank and phone company so he fixes it.",tooltip:"A white knight asks his price.",reveal:"Shares rally on his buying spree. You have sold public assets to paper over a market panic, and he now owns a piece of the state.",effects:{FI:6,EN:3,GL:-13,FA:3}},right:{id:"b",label:"Say no and let the market fix itself slowly.",tooltip:"I will not ransom the bourse to one man.",reveal:"The market mends slowly without a saviour. The tycoon turns his media against you for the snub.",effects:{GL:5,FI:-10,MI:-6}}},{id:"finance-0016",location:"finance",arc:"finance-t0-a11",stage:0,speaker:"Debt Management Chief",portrait:"official",tags:["eurobond","debt","markets"],prompt:"You need money fast. You can borrow a lot of money from the world, but you will have to pay back way too much extra money for ten years.",left:{id:"a",label:"Borrow the money right now.",tooltip:"Cash today is worth the coupon.",reveal:"Dollars arrive and the reserves breathe. The expensive interest bill compounds quietly for ten years.",effects:{FI:8,GL:3,EN:-6}},right:{id:"b",label:"Wait for a better time and stop buying things.",tooltip:"I will not borrow dear out of panic.",reveal:"You squeeze import demand to hold the line. It bites at home now, but spares the country a decade of costly debt.",effects:{FI:-6,EN:-10,GL:3}}},{id:"finance-0017",location:"finance",arc:"finance-t0-a12",stage:0,speaker:"Agriculture Secretary",portrait:"official",tags:["subsidy","fertiliser","farmers"],prompt:"Plant food for farmers is very expensive now. If you don't help pay for it, the crops will die. But helping will cost almost all your money.",left:{id:"a",label:"Pay for the plant food so crops can grow.",tooltip:"A failed harvest is a famine and a fall.",reveal:"The fields stay green and the farmers bless you. The deficit balloons and the IMF frowns at the next review.",effects:{EN:8,RE:3,FI:-16}},right:{id:"b",label:"Pay for just a little bit to save your money.",tooltip:"The books must balance somewhere.",reveal:"You please the creditors and thin the subsidy. Input costs hit the villages, and rural anger ferments.",effects:{FI:6,GL:3,EN:-16,FA:-6}}},{id:"finance-0018",location:"finance",arc:"finance-t0-a13",stage:0,speaker:"Pension Authority Head",portrait:"official",tags:["pension","welfare","funding"],prompt:"You promised to give old people money when they retire, and everyone loves it. But secretly, you don't have enough money to pay them later.",left:{id:"a",label:"Keep making the promise and worry about the money later.",tooltip:"The promise wins this decade's votes.",reveal:"Millions sign up to applause. You have built a magnificent liability your successors will curse.",effects:{EN:8,FA:3,FI:-13}},right:{id:"b",label:"Stop making promises until you actually have the money.",tooltip:"A pension that bounces is a betrayal.",reveal:"You cap the scheme to make it real. The rollout looks timid, but the cheque will clear when it comes due.",effects:{FI:5,GL:3,EN:-13}}},{id:"finance-0019",location:"finance",arc:"finance-t0-a14",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["banks","merger","weak-banks"],prompt:"Five banks are completely broken but pretending to be okay. You can force them to join good banks, but your rich friends will lose their jobs there.",left:{id:"a",label:"Force them to join the good banks.",tooltip:"Let the dead banks be buried.",reveal:"The rot is consolidated and capped. The ousted directors — several are donors — swear vengeance.",effects:{FI:8,GL:5,FA:-13}},right:{id:"b",label:"Let them pretend to be okay a little longer.",tooltip:"Not before the election, not these names.",reveal:"The zombies shuffle on, draining liquidity. The reckoning is postponed and made larger.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0020",location:"finance",arc:"finance-t0-a15",stage:0,speaker:"Mobile Finance Regulator",portrait:"official",tags:["mfs","bkash","fintech"],prompt:"Poor people use their phones to get their paychecks. The big phone company wants to charge them more money to get their cash.",left:{id:"a",label:"Stop the company from charging more money.",tooltip:"The garment girl should keep her wage.",reveal:"The fee cap eases millions of small lives. The operator threatens to cut rural agents in protest.",effects:{EN:8,FA:3,FI:-10}},right:{id:"b",label:"Let the company charge whatever they want.",tooltip:"A profitable rail keeps expanding.",reveal:"The network grows and invests; the daily skim off the poor grows with it.",effects:{FI:5,GL:3,EN:-13}}},{id:"finance-0021",location:"finance",arc:"finance-t0-a16",stage:0,speaker:"Customs Intelligence Chief",portrait:"shadow",tags:["misinvoicing","laundering","trade"],prompt:"People are sneaking billions of dollars out of the country using fake shopping bills. The worst bad guys are friends with your leaders.",left:{id:"a",label:"Stop the fake bills and catch everyone.",tooltip:"Plug the hole in the hull.",reveal:"Customs tightens and capital flight slows. Powerful importers, exposed, fund your rivals overnight.",effects:{FI:8,GL:5,FA:-13}},right:{id:"b",label:"Let them keep doing it quietly.",tooltip:"Some hulls are best left unexamined.",reveal:"The trade continues and the friends stay close. The reserves keep leaking out the side the cameras never see.",effects:{FA:5,FI:-10,GL:-10}}},{id:"finance-0022",location:"finance",arc:"finance-t0-a17",stage:0,speaker:"Fuel Pricing Board",portrait:"official",tags:["fuel","bpc","subsidy"],prompt:"The government sells gas for cars super cheap and loses money every day. You can make a rule so the price changes automatically, so you don't have to be the bad guy.",left:{id:"a",label:"Make the automatic price rule.",tooltip:"Take the politics out of the pump.",reveal:"The oil company stops bleeding; fuel jumps with every global tick, and transport strikes follow each rise.",effects:{FI:8,GL:5,EN:-16}},right:{id:"b",label:"Keep the price cheap and lose money.",tooltip:"Cheap diesel keeps the country moving.",reveal:"Buses and irrigation pumps run cheap. The subsidy drains the budget and distorts every market it touches.",effects:{EN:6,FI:-16,RE:-6}}},{id:"finance-0023",location:"finance",arc:"finance-t0-a18",stage:0,speaker:"Treasury Economist",portrait:"official",tags:["currency","dual-rate","taka"],prompt:"The official price of your country's money is fake, so people use a secret black market. You can fix the official price, but it will make everything cost more for everyone at once.",left:{id:"a",label:"Fix the price and make things cost more.",tooltip:"One honest price beats two dishonest ones.",reveal:"The black market shrinks and exporters cheer; every imported good leaps in price the same morning.",effects:{FI:6,GL:5,EN:-16}},right:{id:"b",label:"Keep the fake price and try to control things.",tooltip:"A sudden devaluation would break the poor.",reveal:"You keep the headline rate and dole out scarce dollars by favour — a system that breeds its own corruption.",effects:{FI:-10,EN:3,GL:-10}}},{id:"finance-0024",location:"finance",arc:"finance-t0-a19",stage:0,speaker:"Foreign Loans Director",portrait:"official",tags:["china","debt","geopolitics"],prompt:"China wants to give you cheap money to build a cool new road. Your enemies say it is a trap to make you owe China forever.",left:{id:"a",label:"Take China's money to build the road.",tooltip:"Cheap concrete is cheap concrete.",reveal:"The ring road rises on easy terms. The 'debt-trap' headlines and Western coolness are the price of the bargain.",effects:{FI:8,RE:5,GL:-13}},right:{id:"b",label:"Say no and ask other places for money instead.",tooltip:"I will not mortgage the capital to one capital.",reveal:"You pay more for diversified financing and Western goodwill. The project crawls; the books strain.",effects:{GL:5,FI:-13,RE:-6}}},{id:"finance-0025",location:"finance",arc:"finance-t0-a20",stage:0,speaker:"Pay Commission Head",portrait:"official",tags:["wages","civil-service","budget"],prompt:"Millions of government workers want a big pay raise. If you pay them, they will love you, but it will use up all the money meant for building schools and hospitals.",left:{id:"a",label:"Give them a giant pay raise.",tooltip:"A happy bureaucracy is a working one.",reveal:"The files move and the clerks smile. The recurring wage bill devours the money meant for bridges and clinics.",effects:{MI:5,FA:3,FI:-16,EN:-6}},right:{id:"b",label:"Give them a small raise you can actually afford.",tooltip:"The state cannot be a charity for itself.",reveal:"You protect the development budget. A sullen civil service slow-walks everything for a season.",effects:{FI:6,EN:3,MI:-10}}},{id:"finance-0026",location:"finance",arc:"finance-t0-a21",stage:0,speaker:"Export Promotion Chief",portrait:"official",tags:["rmg","incentive","exports"],prompt:"You give extra money to people who sell clothes to other countries. The world bank says this is unfair and you must stop. The clothes makers will be very angry.",left:{id:"a",label:"Keep giving them the extra money.",tooltip:"Do not gift our orders to Hanoi.",reveal:"The looms keep their edge and the dollars keep coming. The IMF marks another unmet condition against you.",effects:{FI:5,GL:-10,EN:3,FA:3}},right:{id:"b",label:"Stop giving them the extra money like you promised.",tooltip:"A crutch carried too long becomes a cast.",reveal:"You please the lenders and prod exporters to compete on merit. Margins thin; some marginal factories fold.",effects:{GL:6,FI:-10,EN:-10}}},{id:"finance-0027",location:"finance",arc:"finance-t0-a22",stage:0,speaker:"Deficit Financing Officer",portrait:"official",tags:["printing","inflation","central-bank"],prompt:"You don't have enough money to pay your bills. A helper says you can just print fake money to pay them. It feels easy now, but will make everything super expensive later.",left:{id:"a",label:"Print fake money to pay the bills.",tooltip:"No one feels it this quarter.",reveal:"The gap is filled with fresh notes. Inflation stirs in the months ahead, a tax no one voted for.",effects:{FI:6,EN:-16,GL:-6}},right:{id:"b",label:"Say no and borrow real money honestly.",tooltip:"I will not pay tomorrow's prices for today's gap.",reveal:"You raise the money through bonds, dearer but cleaner. The deficit is honest and the taka steadier.",effects:{GL:5,FI:-6,EN:3}}},{id:"finance-0028",location:"finance",arc:"finance-t0-a23",stage:0,speaker:"e-Commerce Victims' Delegation",portrait:"people",tags:["scam","ecommerce","refunds"],prompt:"A fake online store stole money from thousands of families. They are crying outside your office and want their money back.",left:{id:"a",label:"Use government money to pay them back.",tooltip:"The state failed to police it; the state pays.",reveal:"Families recover a fraction of their savings. The treasury absorbs a scam it did not commit, and others ask why they were not bailed out too.",effects:{EN:8,FA:3,FI:-16}},right:{id:"b",label:"Try to catch the bad guys, but don't give the families money.",tooltip:"I will jail the thieves, not reward the gamble.",reveal:"You freeze assets and prosecute. The recovered crumbs disappoint the crowd, but the precedent of no-bailout holds.",effects:{GL:3,FI:3,EN:-13}}},{id:"finance-0029",location:"finance",arc:"finance-t0-a24",stage:0,speaker:"Revenue Reform Adviser",portrait:"official",tags:["wealth-tax","surcharge","elite"],prompt:"A helper says you should charge very rich people a big new tax. Normal people will cheer, but your rich friends will be furious.",left:{id:"a",label:"Charge the rich people the big new tax.",tooltip:"Those with the most can give the most.",reveal:"Public revenue and approval both rise. The moneyed class opens its war chest against you and its front pages turn cold.",effects:{FI:8,EN:6,FA:-13}},right:{id:"b",label:"Do not charge them, to keep your rich friends happy.",tooltip:"I cannot fight the people who fund me.",reveal:"The fortunes stay untaxed and the donors stay sweet. The street notes whose interests the budget serves.",effects:{FA:5,FI:-10,EN:-10}}},{id:"finance-0030",location:"finance",arc:"finance-t0-a25",stage:0,speaker:"Import Policy Officer",portrait:"official",tags:["lc","luxury","reserves"],prompt:"To save money, you can stop stores from buying fancy things like cars and makeup from other countries. Rich people will be mad when the shelves are empty.",left:{id:"a",label:"Stop the fancy things from coming in.",tooltip:"Dollars are for medicine, not Mercedes.",reveal:"Reserves stop bleeding on baubles. The affluent grumble about scarcity, and some smuggling reroutes the trade.",effects:{FI:6,GL:3,EN:-6,FA:-6}},right:{id:"b",label:"Keep the fancy things coming so people don't get mad.",tooltip:"Empty shelves photograph badly.",reveal:"The shops stay stocked and the rich content. The reserves keep draining on things the country need not buy.",effects:{FA:3,FI:-13,GL:-6}}},{id:"finance-0031",location:"finance",arc:"finance-t0-a26",stage:0,speaker:"Loan Classification Board",portrait:"official",tags:["rescheduling","defaulters","banks"],prompt:"People who borrow money and never pay it back want you to change the rules so they look like good guys again. This makes the banks look good but rewards bad behavior.",left:{id:"a",label:"Change the rules to make them look like good guys.",tooltip:"A pretty balance sheet calms the market.",reveal:"Default ratios drop on paper overnight. The rot deepens in the dark, and the honest borrower wonders why he bothers.",effects:{FI:5,GL:-10,FA:3}},right:{id:"b",label:"Keep strict rules and show who the bad guys are.",tooltip:"Call a bad loan a bad loan.",reveal:"The true scale of default is finally visible. It looks ugly and frightens markets briefly — but the cleanup can begin.",effects:{GL:5,FI:-10,EN:3,FA:-6}}},{id:"finance-0032",location:"finance",arc:"finance-t0-a27",stage:0,speaker:"Privatisation Commissioner",portrait:"official",tags:["privatisation","jute","state-firms"],prompt:"Old government factories lose money every single year, but they give jobs to many people. Your helper wants to close them.",left:{id:"a",label:"Close the old factories.",tooltip:"Nostalgia is not a business plan.",reveal:"The hemorrhage stops and buyers move in. Thousands of mill workers and their unions march on your gate.",effects:{FI:8,GL:3,EN:-16,MI:-6}},right:{id:"b",label:"Keep the factories open using government money.",tooltip:"These looms built the nation.",reveal:"The jobs and the heritage survive on subsidy. The losses recur, year after year, a line item that never dies.",effects:{EN:5,FA:3,FI:-16}}},{id:"finance-0033",location:"finance",arc:"finance-t0-a28",stage:0,speaker:"National Savings Director",portrait:"official",tags:["sanchayapatra","savings","rates"],prompt:"You give old people a really good deal when they save money with the government. But it costs the government too much.",left:{id:"a",label:"Stop giving them the really good deal.",tooltip:"The treasury cannot subsidise every saver.",reveal:"The interest bill eases. Pensioners and widows who counted on that return feel the floor drop, and say so loudly.",effects:{FI:8,GL:3,EN:-13}},right:{id:"b",label:"Keep giving them the really good deal.",tooltip:"The widow's certificate is sacred.",reveal:"You shield the small savers and eat the cost. The high-rollers exploit the same window, and the bill grows.",effects:{EN:6,FA:3,FI:-16}}},{id:"finance-0034",location:"finance",arc:"finance-t0-a29",stage:0,speaker:"Special Economic Zone Director",portrait:"official",tags:["sez","tax-holiday","investment"],prompt:"A foreign company wants to build a big factory and create jobs. But they want you to promise they don't have to pay taxes for a very long time.",left:{id:"a",label:"Promise they don't have to pay taxes for a long time.",tooltip:"Jobs now, taxes eventually.",reveal:"The cranes arrive and employment rises. The treasury forgoes a fortune for fifteen years to win the ribbon-cutting.",effects:{EN:6,FI:-10,GL:5,RE:3}},right:{id:"b",label:"Tell them they only get a short time without paying taxes.",tooltip:"I will host investment, not subsidise it forever.",reveal:"You drive a harder bargain. The consortium hesitates and shrinks the project — but the state keeps a slice of the upside.",effects:{FI:5,GL:-6,EN:-6}}},{id:"finance-0035",location:"finance",arc:"finance-t0-a30",stage:0,speaker:"Anti-Tobacco Coalition",portrait:"people",tags:["tobacco","tax","health"],prompt:"Doctors want you to put a huge tax on cigarettes to stop people from getting sick. But cigarette makers pay you a lot of money and many farmers grow the plants.",left:{id:"a",label:"Put a huge tax on cigarettes.",tooltip:"A cigarette tax is a life saved and a taka earned.",reveal:"Revenue and public health both rise. The tobacco lobby and its farming districts turn sharply against you.",effects:{FI:6,EN:6,FA:-10}},right:{id:"b",label:"Keep the tax on cigarettes very low.",tooltip:"Do not gut a top taxpayer and a voting belt.",reveal:"The companies stay sweet and the leaf districts loyal. The wards fill with the slow harvest of that bargain.",effects:{FI:3,FA:3,EN:-16}}},{id:"finance-0036",location:"finance",arc:"finance-t0-a31",stage:0,speaker:"Land Registration Reformer",portrait:"official",tags:["real-estate","black-money","registration"],prompt:"People lie about how much their houses cost on paper so they don't have to pay taxes. If you use computers to fix this, powerful people will be caught.",left:{id:"a",label:"Use computers to fix it and catch them.",tooltip:"Drag the land market into the light.",reveal:"Registration revenue surges and a laundering channel narrows. Builders and land barons — and their political patrons — howl.",effects:{FI:8,EN:3,GL:3,FA:-13}},right:{id:"b",label:"Let them keep lying on paper.",tooltip:"Some ledgers are best left yellowed.",reveal:"The cosy undervaluation continues. Black money keeps flowing into bricks while the treasury watches it pass.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0037",location:"finance",arc:"finance-t0-a32",stage:0,speaker:"Hajj Management Director",portrait:"cleric",tags:["hajj","pilgrims","cost"],prompt:"Airplanes cost too much for poor families to take their big religious trip. You can use government money to pay for part of their tickets.",left:{id:"a",label:"Pay for part of their tickets.",tooltip:"Let the faithful afford the journey.",reveal:"Grateful pilgrims bless your name from Mecca. The treasury and the secular press both wince at the bill.",effects:{FA:5,EN:5,FI:-13,GL:-6}},right:{id:"b",label:"Don't pay, but make the travel agents charge less.",tooltip:"Faith should not be a fiscal line.",reveal:"You squeeze the middlemen instead of the budget. The devout are mildly disappointed; the books stay clean.",effects:{FI:5,GL:3,EN:-6,FA:-6}}},{id:"finance-0038",location:"finance",arc:"finance-t0-a33",stage:0,speaker:"Climate Fund Auditor",portrait:"official",tags:["climate","fund","graft"],prompt:"The money meant to help save the earth from storms was stolen by your own team members. You can investigate and take it back, but it will embarrass your team.",left:{id:"a",label:"Investigate and take the stolen money back.",tooltip:"Stolen flood money is blood money.",reveal:"Recovered crores return to the embankments. The implicated party officials become loud, wounded enemies.",effects:{EN:6,GL:6,FI:3,FA:-13}},right:{id:"b",label:"Hide the secret to protect your team.",tooltip:"Do not hand the donors a scandal.",reveal:"The leak stays hidden and the party intact. The embankments stay thin, and the next flood collects the difference.",effects:{FA:5,EN:-16,GL:-10}}},{id:"finance-0039",location:"finance",arc:"finance-t0-a34",stage:0,speaker:"Sovereign Fund Proponent",portrait:"official",tags:["reserves","sovereign-fund","investment"],prompt:"A helper wants to take your emergency money from the bank and spend it to build big things at home. It is brave, but if an emergency happens, you will have no money.",left:{id:"a",label:"Take the emergency money and build big things.",tooltip:"Idle reserves should build the country.",reveal:"Grand projects get cheap money and momentum. The reserve buffer thins, and a future shock will find less cushion.",effects:{RE:5,EN:5,FI:-10,GL:-6}},right:{id:"b",label:"Keep the emergency money safe in the bank.",tooltip:"Reserves are the wall against the storm.",reveal:"You guard the buffer and pass on the projects. Critics call it timid; the next currency scare proves it wise.",effects:{FI:6,GL:3,EN:-6}}},{id:"finance-0040",location:"finance",arc:"finance-t0-a35",stage:0,speaker:"VAT Online Director",portrait:"official",tags:["vat","digitisation","compliance"],prompt:"Shopkeepers are putting tax money in their own pockets. You can force them to use smart computers to stop this, but millions of them will be angry and vote against you.",left:{id:"a",label:"Force them to use the smart computers.",tooltip:"An honest till funds an honest state.",reveal:"Consumption-tax revenue climbs steadily. A million shopkeepers grumble about the machine watching every sale.",effects:{FI:8,GL:3,EN:-6,FA:-6}},right:{id:"b",label:"Let them keep collecting taxes the old way.",tooltip:"Do not put a meter on every shop counter.",reveal:"The shopkeepers stay content and the leakage continues. The treasury collects a fraction of what it is owed.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0041",location:"finance",arc:"finance-t0-a36",stage:0,speaker:"Garment Buyers' Auditor",portrait:"ambassador",tags:["rmg","compliance","wages"],prompt:"Buyers from other countries want proof that your factories pay workers fairly. Being fair costs owners money. Faking the proof risks losing the buyers forever.",left:{id:"a",label:"Force the owners to be completely fair.",tooltip:"The market is worth more than the margin.",reveal:"Buyers are reassured and orders hold; the workers are paid in full. Factory owners — your donors — bristle at the cost.",effects:{GL:6,EN:6,FI:-10,FA:-6}},right:{id:"b",label:"Help the owners fake the proof.",tooltip:"Protect the owners who keep the lines running.",reveal:"The audit is smoothed over and margins protected. One leaked payslip could bring the whole edifice down.",effects:{FI:5,FA:3,GL:-13,EN:-10}}},{id:"finance-0042",location:"finance",arc:"finance-t0-a37",stage:0,speaker:"Revenue Board Chairman",portrait:"fixer",tags:["black-money","tax","whitening"],prompt:"Bad guys have hidden, stolen money. You can pass a rule that lets them keep it safely if they pay a tiny tax. Honest people think this is very unfair.",left:{id:"a",label:"Let them keep it safely for a tiny tax.",tooltip:"Better the black money working here than hiding abroad.",reveal:"The clause passes and laundered crores flood into property and banks. The reserves and the books improve, and every honest taxpayer learns that cheating, in the end, is rewarded.",effects:{FI:8,FA:2,EN:-13,GL:-10}},right:{id:"b",label:"Say no to this unfair rule.",tooltip:"A state that pardons theft for a fee invites more theft.",reveal:"You kill the whitening clause. The hidden money stays hidden or flees abroad, and the budget is thinner for it, but the tax system keeps a shred of fairness and credibility.",effects:{GL:5,EN:5,FI:-13}}},{id:"finance-0043",location:"finance",arc:"finance-t0-a38",stage:0,speaker:"Securities Regulator",portrait:"official",tags:["stock-market","crash","retail"],prompt:"Bad guys tricked normal people into losing all their money in the stock market. You can spend government money to pay the normal people back and punish the bad guys.",left:{id:"a",label:"Pay the normal people back and punish the bad guys.",tooltip:"A market that eats its small fish breeds no trust.",reveal:"You cushion the retail losses and go after the big manipulators. The bailout is costly and the syndicates fight back, but the small investor sees the state will not abandon them to the wolves.",effects:{EN:6,GL:3,FI:-13,FA:-6}},right:{id:"b",label:"Let the normal people lose their money.",tooltip:"A gambler who loses cannot bill the state.",reveal:"You let the crash run its course. The treasury is spared, the manipulators keep their gains, and a generation of small savers swears off the market that fleeced them.",effects:{FI:3,EN:-13,GL:-3}}},{id:"finance-0044",location:"finance",arc:"finance-t0-a39",stage:0,speaker:"Privatisation Commission Chief",portrait:"official",tags:["soe","privatisation","jobs"],prompt:"The government owns old factories and airplanes that lose money every day. You can shut them down, or keep them running just so workers keep their jobs.",left:{id:"a",label:"Shut them down and stop losing money.",tooltip:"A factory that only makes losses makes nothing.",reveal:"You sell or close the bleeding enterprises and stem the subsidy. The freed budget is real, but tens of thousands of workers lose their jobs and turn their fury on you.",effects:{FI:6,GL:3,EN:-13}},right:{id:"b",label:"Keep them running to save the jobs.",tooltip:"A wage lost is a household sunk.",reveal:"You keep the loss-makers running for the workers and the patronage. The jobs and the votes are safe, and the subsidy keeps draining money that schools and clinics will never see.",effects:{EN:5,FA:3,FI:-13}}},{id:"finance-0045",location:"finance",arc:"finance-t0-a40",stage:0,speaker:"Pension Authority Director",portrait:"people",tags:["pension","welfare","future"],prompt:"You want to help poor workers save money for when they get old. You can use government money to help them, or force them to use only their own money.",left:{id:"a",label:"Use government money to help them save.",tooltip:"An old age without dignity is a society's shame.",reveal:"You build a pension reaching even the poorest with heavy state top-ups. The fiscal burden is enormous and permanent, but a generation of the elderly is lifted out of destitution.",effects:{EN:10,GL:3,FI:-16}},right:{id:"b",label:"Make them use only their own money.",tooltip:"A promise I cannot fund is a betrayal deferred.",reveal:"You launch a modest, mainly contribution-based scheme. It is fiscally sound but reaches the poorest thinly, and the informal workers who most need it can least afford to join.",effects:{FI:3,EN:3,GL:2}}},{id:"finance-0046",location:"finance",arc:"finance-t0-a41",stage:0,speaker:"IMF Programme Negotiator",portrait:"ambassador",tags:["imf","subsidy","austerity"],prompt:"A big bank will give you important money, but only if you stop helping people pay for gas and electricity. The people will be very angry if prices go up.",left:{id:"a",label:"Stop helping people pay so you can get the bank's money.",tooltip:"The fund's money keeps the lights on at all.",reveal:"You slash the subsidies and unlock the tranche. The reserves and the lenders are reassured, and the price of transport, food, and power detonates in every household.",effects:{FI:6,GL:5,EN:-18}},right:{id:"b",label:"Keep helping people pay and lose the bank's money.",tooltip:"I will not buy a loan with my people's hunger.",reveal:"You shield the subsidies and the IMF talks stall. The street is spared the shock, but the reserves keep bleeding and the lifeline you turned down may not be offered twice.",effects:{EN:6,FI:-13,GL:-6}}},{id:"finance-0047",location:"finance",arc:"finance-t0-a42",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["currency","float","devaluation"],prompt:"You are burning up all your savings to pretend your country's money is worth a lot. The bank boss says to stop and tell the truth, even if things get expensive.",left:{id:"a",label:"Tell the truth and let things get expensive.",tooltip:"A currency defended past its worth bankrupts the defender.",reveal:"You float the taka and the black-market premium vanishes. Import prices and inflation jump painfully, but the ruinous reserve drain stops and the market finds honest footing.",effects:{FI:5,GL:3,EN:-13}},right:{id:"b",label:"Burn up more savings to keep pretending.",tooltip:"A falling taka is a falling government.",reveal:"You keep defending the rate. The official price holds and the public is spared the shock for now, but the reserves drain toward empty and the black market thrives in the gap.",effects:{EN:3,FI:-13,GL:-3}}},{id:"finance-0048",location:"finance",arc:"finance-t0-a43",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["banks","merger","npl"],prompt:"Some banks are broken because bad bosses stole from them. You can force good banks to mix with the bad ones to save people's money, but it rewards the bad bosses.",left:{id:"a",label:"Mix the banks to save the people's money.",tooltip:"A bank run is a fire that spreads.",reveal:"You merge the zombie banks into stronger ones and depositors are saved. The looters who gutted them walk away clean, and the healthy banks inherit a mountain of toxic debt.",effects:{FI:3,EN:2,GL:-3,FA:-3}},right:{id:"b",label:"Let the bad banks fail so they learn a lesson.",tooltip:"A bank that is never allowed to die never learns to live.",reveal:"You let one rotten bank collapse. Depositors panic and the system shudders, but for once the looters lose their bank, and every other board suddenly takes risk seriously.",effects:{GL:3,FI:-10,EN:-6}}},{id:"finance-0049",location:"finance",arc:"finance-t0-a44",stage:0,speaker:"Banking Division Secretary",portrait:"fixer",tags:["loans","defaulters","favours"],prompt:"Rich people who never pay back their bank loans want you to give them a super easy deal again. It makes the banks look okay on paper, but lets the bad guys win.",left:{id:"a",label:"Give them the super easy deal.",tooltip:"A defaulter's empire employs thousands; do not topple it.",reveal:"You let the big defaulters reschedule on featherbed terms. The banks' books look healthier on paper, the connected tycoons stay afloat, and the rot in the banking system deepens out of sight.",effects:{FI:3,FA:3,EN:-10,GL:-10}},right:{id:"b",label:"Force them to pay back what they owe.",tooltip:"A willful defaulter is a thief with a balance sheet.",reveal:"You refuse the rescheduling and move to recover or seize. The tycoons rage and call in their political chips, but billions in dead loans start, painfully, to come back.",effects:{GL:5,FI:3,EN:3,FA:-10}}},{id:"finance-0050",location:"finance",arc:"finance-t0-a45",stage:0,speaker:"Debt Management Director",portrait:"ambassador",tags:["eurobond","debt","markets"],prompt:"You can borrow a huge amount of money from the world right now. But you will owe them so much extra money that it will hurt your country for a long time.",left:{id:"a",label:"Borrow the huge amount of money.",tooltip:"Market money comes with no master attached.",reveal:"The bond raises the cash quickly and string-free. The high coupon settles onto future budgets, and your fortunes are now hostage to the moods of distant bond markets.",effects:{FI:5,GL:2,RE:2}},right:{id:"b",label:"Say no to borrowing the money.",tooltip:"A bond at usurer's rates is a trap with a ribbon.",reveal:"You skip the expensive bond and live within tighter means. The development plans shrink and the cash crunch bites, but you do not mortgage the next decade to the markets.",effects:{GL:2,FI:-6,EN:-3}}},{id:"finance-0051",location:"finance",arc:"finance-t0-a46",stage:0,speaker:"Trading Corporation Chief",portrait:"shadow",tags:["inflation","syndicate","food"],prompt:"Bad sellers are hiding food to make it cost more. Some of them give you money.",left:{id:"a",label:"Stop the bad sellers and bring in cheap food.",tooltip:"A cartel that taxes every plate must be smashed.",reveal:"You raid the hoarders and flood the market with state imports. Prices ease and the public exhales, but the cartel bosses — your financiers — turn on you with their wallets shut.",effects:{EN:8,FI:-6,FA:-10}},right:{id:"b",label:"Protect the bad sellers and let food stay expensive.",tooltip:"The men who fund the party are not lightly raided.",reveal:"You spare the syndicate and the hoarding continues. The financiers stay loyal and generous, and the cost of a meal climbs out of reach for the families who can least bear it.",effects:{FI:3,FA:5,EN:-16}}},{id:"finance-0052",location:"finance",arc:"finance-t0-a47",stage:0,speaker:"Customs Commissioner",portrait:"fixer",tags:["customs","ports","corruption"],prompt:"Guards at the boat docks are taking secret money instead of charging the right taxes.",left:{id:"a",label:"Use computers to stop them from stealing.",tooltip:"A bribed customs house robs the whole nation.",reveal:"You digitise clearance and audit the postings hard. Duty revenue jumps and the rackets wither, and the officers who paid fortunes for the lucrative postings turn bitterly against you.",effects:{FI:6,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Let the guards keep taking secret money.",tooltip:"The men in the customs houses have powerful patrons.",reveal:"You leave the ports' shadow economy intact. The patronage flows smoothly and the postings stay golden, and the treasury keeps collecting a fraction of the duty it is owed.",effects:{FI:-6,FA:3,EN:-6,GL:-3}}},{id:"finance-0053",location:"finance",arc:"finance-t0-a48",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["tax","elite","evasion"],prompt:"Rich people are not paying their taxes, so normal workers have to pay more.",left:{id:"a",label:"Force the rich people to pay their taxes.",tooltip:"A state funded by clerks while tycoons skate is doomed.",reveal:"You target the rich evaders, audits reaching into donor and dynastic ledgers. The revenue base broadens and the public cheers, but the powerful you have dunned plot their revenge.",effects:{FI:6,EN:6,GL:3,FA:-13}},right:{id:"b",label:"Keep making the normal workers pay.",tooltip:"The easy taxpayer is the one who cannot run.",reveal:"You leave the rich alone and lean harder on the salaried. The revenue is reliable and the donors content, and the shrinking middle class learns exactly whose shoulders the state rests on.",effects:{FI:3,FA:3,EN:-13}}},{id:"finance-0054",location:"finance",arc:"finance-t0-a49",stage:0,speaker:"Digital Finance Adviser",portrait:"official",tags:["mobile-money","remittances","inclusion"],prompt:"Paying with phones can help people send money safely, but regular banks don't like it.",left:{id:"a",label:"Help people use their phones to send money safely.",tooltip:"A phone in every hand is a bank in every village.",reveal:"You push incentives for mobile remittances and the formal channels swell. The banks and the hundi networks both lose ground and grumble, but billions enter the legal economy and the unbanked gain access.",effects:{FI:6,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Help the regular banks instead.",tooltip:"The banks are the system; do not undercut them.",reveal:"You shield the banks and leave the mobile push half-hearted. The hundi networks keep their grip on remittances, the reserves miss the inflows, and the village stays unbanked.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0055",location:"finance",arc:"finance-t0-a50",stage:0,speaker:"Pay Commission Chair",portrait:"official",tags:["salaries","bureaucracy","budget"],prompt:"Government workers want a giant raise. If you pay them, they will be happy, but you won't have money for other things.",left:{id:"a",label:"Give them the giant raise.",tooltip:"A well-paid official is a loyal, honest one.",reveal:"You award the generous hike and the bureaucracy is delighted and bound to you. Petty bribery eases, but the wage bill swells permanently, crowding out the development budget for years.",effects:{MI:2,FA:3,FI:-13,EN:-3}},right:{id:"b",label:"Give them a small raise you can afford.",tooltip:"A salary I cannot sustain is a strike deferred.",reveal:"You give a restrained increase the budget can bear. The civil servants grumble at the modesty and some petty corruption persists, but the fiscal hole stays survivable.",effects:{FI:3,EN:2,FA:-3}}},{id:"finance-0056",location:"finance",arc:"finance-t0-a51",stage:0,speaker:"Financial Intelligence Chief",portrait:"shadow",tags:["laundering","over-invoicing","capital-flight"],prompt:"Your rich friends are secretly sending their money to other countries.",left:{id:"a",label:"Build a strong team to stop them.",tooltip:"A river of stolen money flowing abroad bleeds us white.",reveal:"You stand up real trade-laundering enforcement and the outflows slow. The reserves steady and the world's watchdogs approve, but your backers' escape route is now monitored, and they are furious.",effects:{FI:5,GL:5,EN:3,FA:-10}},right:{id:"b",label:"Let your friends keep sending their money away.",tooltip:"The men who move that money also fund the party.",reveal:"You leave the over-invoicing pipeline flowing. Your backers keep stashing wealth abroad and stay loyal, and the reserves keep haemorrhaging out through a hole you chose not to plug.",effects:{FA:5,FI:-10,GL:-6}}},{id:"finance-0057",location:"finance",arc:"finance-t0-a52",stage:0,speaker:"Investment Authority Chief",portrait:"ambassador",tags:["sez","fdi","incentives"],prompt:"Foreign companies want free land and no taxes for a long time to build factories here.",left:{id:"a",label:"Give them free things so they build factories.",tooltip:"An empty zone earns nothing; fill it at any price.",reveal:"You hand out the tax holidays and the factories come. Jobs and FDI flow in for the headlines, and the revenue board quietly notes the decade of tax you have signed away.",effects:{FI:3,EN:3,GL:3,RE:-3}},right:{id:"b",label:"Give them fewer free things.",tooltip:"A zone bought with the whole future is a bad bargain.",reveal:"You offer modest, sunset-clause incentives. Some footloose investors look elsewhere and the zones fill slower, but the deals that land actually pay tax within the decade.",effects:{FI:3,GL:-3,EN:2}}},{id:"finance-0058",location:"finance",arc:"finance-t0-a53",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["deficit","printing","inflation"],prompt:"You have no money to pay bills. You can print fake money now, but it will ruin everything later.",left:{id:"a",label:"Print the fake money to pay bills.",tooltip:"A bill paid today is a bill paid.",reveal:"You lean on the printing press and the bills are met. The relief is immediate and the cost deferred, as the new money seeps into prices and the inflation you deferred compounds.",effects:{FI:5,EN:-13,GL:-6}},right:{id:"b",label:"Say no to printing fake money.",tooltip:"A printing press is a slow-motion default.",reveal:"You hold the line against monetisation and cut or borrow instead. The squeeze is painful and immediate, but you spare the country the inflationary spiral that has ruined so many.",effects:{GL:3,FI:-6,EN:-3}}},{id:"finance-0059",location:"finance",arc:"finance-t0-a54",stage:0,speaker:"Agricultural Bank Chairman",portrait:"people",tags:["sme","farmers","credit"],prompt:"Poor farmers can't borrow money because banks only lend to rich people.",left:{id:"a",label:"Force banks to lend money to poor farmers.",tooltip:"A loan to a farmer grows more than a loan to a tycoon.",reveal:"You push cheap credit out to farmers and micro-enterprises. Default risk and cost rise, but the rural economy stirs to life and millions feel the state's hand for the first time.",effects:{EN:8,FI:-10}},right:{id:"b",label:"Let banks keep lending only to the rich.",tooltip:"A bank that lends to the poor is a bank that fails.",reveal:"You keep credit flowing to the safe and the big. The banks' books stay clean, and the small farmer and the micro-trader keep borrowing from the moneylender at ruinous rates.",effects:{FI:3,EN:-10,FA:2}}},{id:"finance-0060",location:"finance",arc:"finance-t0-a55",stage:0,speaker:"Treasury Operations Chief",portrait:"official",tags:["liquidity","festival","wages"],prompt:"A big holiday is coming and factory owners can't pay their workers. The workers will be very mad.",left:{id:"a",label:"Give the owners government money to pay the workers.",tooltip:"A million unpaid workers at Eid is a powder keg.",reveal:"You bail out the payrolls and the workers go home paid for the holiday. The owners are rescued from their own mismanagement again, learning once more that the state will always catch them.",effects:{EN:6,FI:-10,FA:2}},right:{id:"b",label:"Make the owners fix their own problem.",tooltip:"I will not bankroll the bonuses of profitable men.",reveal:"You refuse the bailout and tell the owners to pay their own way. Some factories erupt in unrest over delayed wages, but the owners learn the treasury is not their overdraft.",effects:{FI:3,EN:-10,FA:-3}}},{id:"finance-0061",location:"finance",arc:"finance-t0-a56",stage:0,speaker:"Export Promotion Director",portrait:"official",tags:["exports","diversification","garments"],prompt:"Your country only sells clothes to the world. You can try to sell new things like medicine and computers, but it is slow and hard.",left:{id:"a",label:"Try to sell new things like medicine and computers.",tooltip:"An economy on one leg falls when that leg is kicked.",reveal:"You back the emerging sectors with incentives and infrastructure. The payoff is slow and some bets will fail, but the export base begins, finally, to broaden beyond the loom.",effects:{FI:2,GL:3,EN:3,RE:2}},right:{id:"b",label:"Keep focusing only on selling clothes.",tooltip:"Why bet on maybes when the looms pay now?",reveal:"You concentrate support on the proven garment sector. Exports stay strong and the cash flows, and the economy's single point of failure grows ever more dangerous and ever more entrenched.",effects:{FI:5,EN:-3,GL:-3}}},{id:"finance-0062",location:"finance",arc:"finance-t0-a57",stage:0,speaker:"Digital Economy Adviser",portrait:"people",tags:["it","freelancers","youth"],prompt:"Young people making money online are having a hard time getting paid because of bad rules.",left:{id:"a",label:"Change the rules to help them get paid easily.",tooltip:"A laptop in a village earns dollars from the world.",reveal:"You smooth payments, ease taxes, and back training for the digital workforce. A new stream of foreign currency grows, and a generation of the young find work without leaving home.",effects:{FI:5,EN:5,GL:2}},right:{id:"b",label:"Do not change the rules.",tooltip:"A scattered cottage industry is not a strategy.",reveal:"You keep the clumsy status quo. The freelancers route their earnings through grey channels or move abroad, and a homegrown export pillar withers before it can take root.",effects:{FI:-3,EN:-6,GL:-3}}},{id:"finance-0063",location:"finance",arc:"finance-t0-a58",stage:0,speaker:"Financial Intelligence Chief",portrait:"ambassador",tags:["capital-flight","second-homes","elite"],prompt:"News reporters found out your leaders secretly own big houses in other countries using stolen money.",left:{id:"a",label:"Help catch them and take the money back.",tooltip:"Stolen money parked abroad still belongs to the people.",reveal:"You take up the foreign cooperation and chase the laundered fortunes home. Some assets are frozen and the public is electrified, but the exposed elite — your own ranks — declare quiet war.",effects:{FI:5,GL:5,EN:6,FA:-16}},right:{id:"b",label:"Ignore it and let them keep the houses.",tooltip:"Half my cabinet owns those flats.",reveal:"You decline to pursue the foreign holdings. Your elite's offshore nest eggs stay safe and they stay loyal, and the message that the powerful loot with impunity is stamped a little deeper.",effects:{FA:6,FI:-6,EN:-13,GL:-10}}},{id:"finance-0064",location:"finance",arc:"finance-t0-a59",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["crypto","regulation","capital-controls"],prompt:"Young people are using digital internet money. It might be dangerous, but everyone is doing it.",left:{id:"a",label:"Ban all internet money.",tooltip:"A currency I cannot see is a hole in the dam.",reveal:"You ban crypto and threaten the traders. The official capital controls hold a little better, but the trade simply goes underground, and the tech-savvy young add another grievance to the pile.",effects:{FI:2,MI:2,GL:-3,EN:-6}},right:{id:"b",label:"Make rules for it and tax it.",tooltip:"Better to tax the tide than to forbid it.",reveal:"You bring crypto into a regulated, taxed framework. The capital-flight risk is real and the controls leakier, but you tax the activity, attract some fintech, and keep faith with the young.",effects:{FI:3,GL:2,EN:2}}},{id:"finance-0065",location:"finance",arc:"finance-t0-a60",stage:0,speaker:"PPP Authority Chief",portrait:"fixer",tags:["ppp","infrastructure","contracts"],prompt:"A company wants to build a big road for free, but they will charge everyone to drive on it for a very long time.",left:{id:"a",label:"Let them build it and charge people.",tooltip:"Roads now, paid for by tomorrow's tolls.",reveal:"The expressway gets built without upfront state money. The consortium pockets guaranteed returns for decades, and the 'minimum revenue' clause quietly hands the risk back to the public purse.",effects:{RE:3,FI:2,EN:2,GL:-3}},right:{id:"b",label:"Say no and build a fair road yourself.",tooltip:"A guarantee that the state eats all losses is a gift, not a partnership.",reveal:"You refuse the lopsided guarantee and renegotiate or build it yourself. The road is slower to come and the budget strained, but the public is not signed up to underwrite private profit.",effects:{FI:-6,EN:2,GL:2}}},{id:"finance-0066",location:"finance",arc:"finance-t0-a61",stage:0,speaker:"Planning Commission Member",portrait:"official",tags:["development-budget","spending","quality"],prompt:"Every year, people rush to spend government money on badly made projects just before time runs out.",left:{id:"a",label:"Stop the rush and only build a few good things.",tooltip:"A road built twice is a road paid for thrice.",reveal:"You impose vetting and steady disbursement over the year-end splurge. The 'utilisation' numbers dip and the contractors grumble, but the projects that get built actually last.",effects:{FI:3,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Keep rushing to spend the money fast.",tooltip:"Unspent money is a bureaucrat's failure on paper.",reveal:"You let the final-quarter splurge continue. The disbursement targets are hit and everyone looks busy, and the padded, half-built projects crumble within a season or two.",effects:{FA:2,FI:-3,EN:-10}}},{id:"finance-0067",location:"finance",arc:"finance-t0-a62",stage:0,speaker:"Microfinance Regulator",portrait:"people",tags:["microfinance","debt","poverty"],prompt:"Poor people are borrowing too much money from too many places and are stuck. You can make rules to stop this, but the lenders will be mad.",left:{id:"a",label:"Make rules to protect the poor people.",tooltip:"A loan that traps is no longer a ladder.",reveal:"You cap effective rates and require a shared registry to stop multiple-lending. The big lenders fight the limits, but the rural poor stop drowning under stacked, overlapping loans.",effects:{EN:6,GL:2,FI:-3,FA:-3}},right:{id:"b",label:"Let the lenders do whatever they want.",tooltip:"Do not break the model the world copied.",reveal:"You leave the MFIs to their own devices. The model's reputation is preserved, and in the villages the quiet debt spirals tighten, household by over-borrowed household.",effects:{FI:2,FA:2,EN:-10}}},{id:"finance-0068",location:"finance",arc:"finance-t0-a63",stage:0,speaker:"Defence Finance Secretary",portrait:"general",tags:["defence","budget","spending"],prompt:"The army wants a lot more money for cool new gear. If you give it to them, you can't build schools and hospitals.",left:{id:"a",label:"Give the army the money they want.",tooltip:"A contented barracks is a sleeping coup.",reveal:"You fund the military's wish-list and the brass is reassured of your favour. The barracks stay loyal, and the schools, clinics, and pensions you promised the public quietly shrink to pay for it.",effects:{MI:6,FA:2,FI:-10,EN:-10}},right:{id:"b",label:"Say no and spend money on the people instead.",tooltip:"A nation is defended by its people's wellbeing too.",reveal:"You hold the line on defence and protect social spending. The public services hold, but the generals feel slighted and watched, and a restive barracks is a risk you now carry.",effects:{EN:6,GL:2,MI:-10,FI:-3}}},{id:"finance-0069",location:"finance",arc:"finance-t0-a64",stage:0,speaker:"Auditor General",portrait:"official",tags:["reserves","transparency","audit"],prompt:"You have been counting money you already promised to others, making you look richer than you are.",left:{id:"a",label:"Tell the truth about having less money.",tooltip:"A number built on a lie collapses worse later.",reveal:"You restate the reserves truthfully. The markets and the public are rattled by the lower figure, but the credibility you buy with honesty steadies the longer game and the IMF's trust.",effects:{GL:5,FI:-6,EN:-3}},right:{id:"b",label:"Keep counting the promised money to look rich.",tooltip:"A panic today is worse than a problem deferred.",reveal:"You keep the flattering figure on the books. The markets stay calm on a number that is not real, and the day the truth finally surfaces, the fall will be all the further.",effects:{FI:3,GL:-10,EN:-3}}},{id:"finance-0070",location:"finance",arc:"finance-t0-a65",stage:0,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["fraud","banks","scandal"],prompt:"A group of bad guys stole a giant amount of money from a government bank.",left:{id:"a",label:"Investigate them in front of everyone.",tooltip:"A fraud buried festers into a collapse.",reveal:"You open a transparent probe and the arrests climb toward the boardroom and beyond. Confidence wobbles at the spectacle, but the looters face justice and the system is forced to clean house.",effects:{GL:5,EN:5,FI:-6,FA:-10}},right:{id:"b",label:"Fix it quietly to protect the bank's secret.",tooltip:"A public scandal runs the depositors to the doors.",reveal:"You keep the fraud out of the headlines and settle it in the dark. Confidence holds on the surface, the connected escape, and the hole in the bank is quietly stuffed with public money.",effects:{FI:2,FA:3,EN:-10,GL:-10}}},{id:"finance-0071",location:"finance",arc:"finance-t0-a65",stage:1,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["fraud","banks","scandal"],prompt:"A second bank was robbed the same way. The checker wants to make strong rules that would stop your friends from controlling the banks.",left:{id:"a",label:"Make the strong rules to stop the stealing.",tooltip:"A watchdog on the owner's leash guards nothing.",reveal:"You hand the banking regulator genuine independence and teeth. The politicians who packed the boards lose their grip and rage, but the banking sector gains its first real check in a generation.",effects:{GL:5,EN:5,FI:2,FA:-10}},right:{id:"b",label:"Keep your friends in control of the banks.",tooltip:"An independent watchdog bites the hand that feeds the party.",reveal:"You keep the regulator pliant. The board appointments stay a political spoil, the frauds keep their cover, and the banking system slides deeper toward a reckoning no one is watching for.",effects:{FA:5,FI:-6,EN:-10,GL:-6}}},{id:"finance-0072",location:"finance",arc:"finance-t0-a66",stage:0,speaker:"Remittance Policy Director",portrait:"people",tags:["remittances","incentive","reserves"],prompt:"Workers far away are using secret ways to send money home. You can pay them a bonus to use the safe banks instead.",left:{id:"a",label:"Pay the bonus so they use safe banks.",tooltip:"A bonus on every dollar is a dollar in the vault.",reveal:"You pay the incentive and the official remittances surge as hundi loses its edge. The budget takes a real hit, but the reserves swell with the inflows you lured back into the light.",effects:{FI:5,EN:3,GL:2}},right:{id:"b",label:"Save your money and don't pay the bonus.",tooltip:"I will not pay people to do what they should anyway.",reveal:"You forgo the incentive. The budget is spared the cost, but the remittances keep leaking into hundi, the reserves miss the inflows, and the black-market dollar keeps its premium.",effects:{FI:-6,EN:-3,GL:-3}}},{id:"finance-0073",location:"finance",arc:"finance-t0-a66",stage:1,speaker:"Remittance Policy Director",portrait:"people",tags:["remittances","incentive","reserves"],prompt:"Factory owners are jealous of the bonus you gave the workers. They demand a bonus too, or they will hide their money.",left:{id:"a",label:"Give the factory owners the bonus too.",tooltip:"One dollar should be worth another, whoever earned it.",reveal:"You level the field and incentivise export proceeds as well. The reserves keep filling and the exporters are placated, but the budget's incentive bill balloons toward the unsustainable.",effects:{FI:2,GL:2,EN:-3}},right:{id:"b",label:"Say no, the bonus is only for workers.",tooltip:"I cannot subsidise every dollar in the economy.",reveal:"You refuse to widen the scheme. The budget is protected, but the garment lobby retaliates by parking earnings abroad, and some of the reserve gain leaks back out the other side.",effects:{FI:2,FA:-3,GL:-3}}},{id:"finance-0074",location:"finance",arc:"finance-t0-a67",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["imports","lc","reserves"],prompt:"You can stop people from buying things from other countries to save money. But this will hurt factories that need parts.",left:{id:"a",label:"Stop people from buying things from other countries.",tooltip:"A dollar saved is a dollar that stays in the vault.",reveal:"You ration the LCs and the reserve bleed slows. Factories starved of imported inputs cut shifts, a black market in LC approvals blooms, and the well-connected jump the dollar queue.",effects:{FI:5,EN:-10,FA:2,GL:-3}},right:{id:"b",label:"Let them keep buying things and try to save money elsewhere.",tooltip:"A factory without inputs is a layoff with a delay.",reveal:"You keep the import channel open and seek savings elsewhere. Industry keeps running and no corrupt LC queue forms, but the reserves keep draining toward the danger line.",effects:{EN:3,FI:-10,GL:2}}},{id:"finance-0075",location:"finance",arc:"finance-t0-a67",stage:1,speaker:"Central Bank Governor",portrait:"official",tags:["imports","lc","reserves"],prompt:"Stopping buying things caused a big problem. Now there is not enough medicine or food.",left:{id:"a",label:"Keep the strict rules to save money.",tooltip:"The reserves must come first or nothing else holds.",reveal:"You maintain the clampdown. The reserves are defended, but the shortages deepen into closed factories and empty pharmacy shelves, and the hardship radiates through the economy.",effects:{FI:5,EN:-13,GL:-3}},right:{id:"b",label:"Change the rules to buy the most important things.",tooltip:"I will not ration medicine to save a statistic.",reveal:"You carve out medicines, food, and key inputs from the curbs. The reserve relief is smaller, but the worst shortages ease and the factories keep their workers on the line.",effects:{EN:5,FI:-6,GL:2}}},{id:"finance-0076",location:"finance",arc:"finance-t0-a68",stage:0,speaker:"Statistics Bureau Chief",portrait:"shadow",tags:["gdp","statistics","credibility"],prompt:"You can change the math to make your country look super rich and successful, even if it's a lie.",left:{id:"a",label:"Use the fake math to look great.",tooltip:"A nation grows as fast as its statistics say.",reveal:"You release the burnished numbers and top the league tables. The applause is real and the doubt is louder; when reality diverges from the data, the whole record becomes suspect.",effects:{FI:3,GL:2,EN:-10}},right:{id:"b",label:"Tell the honest truth, even if it looks less great.",tooltip:"A growth rate I have to defend is not growth.",reveal:"You release credible numbers, modest as they are. The headlines are duller and rivals crow, but the data the country plans by — and the lenders trust — stays sound.",effects:{GL:3,EN:2,FI:-6}}},{id:"finance-0077",location:"finance",arc:"finance-t0-a69",stage:0,speaker:"Wage Commission Chair",portrait:"people",tags:["wages","labour","cost"],prompt:"You can pass a rule that all workers must be paid a fair amount. The bosses say this will cost them too much money.",left:{id:"a",label:"Make a rule that pays workers fairly.",tooltip:"A wage too low to live on is a subsidy to the boss.",reveal:"You set a real floor under wages. Millions of the working poor breathe easier, the donors howl about competitiveness, and a few marginal employers do shed jobs.",effects:{EN:8,FI:-6,FA:-6}},right:{id:"b",label:"Let the bosses decide how much to pay.",tooltip:"A floor too high empties the factory.",reveal:"You leave wages to the market and the donors content. Competitiveness is protected and the jobs stay, and the working poor keep grinding at a wage that never quite covers the rent.",effects:{FI:3,FA:3,EN:-13}}},{id:"finance-0078",location:"finance",arc:"finance-t0-a70",stage:0,speaker:"Consumer Protection Director",portrait:"shadow",tags:["e-commerce","ponzi","fraud"],prompt:"A famous online store is stealing everyone's money. You need to stop them quickly before they run away.",left:{id:"a",label:"Stop them and arrest them immediately.",tooltip:"A scam this size will not be allowed to vanish.",reveal:"You freeze the accounts and arrest the founders before they bolt. Some customer money is clawed back, and the swift action signals that the digital wild-west has a sheriff at last.",effects:{EN:6,GL:3,FI:2}},right:{id:"b",label:"Wait and study the problem slowly.",tooltip:"A hasty freeze could spook the whole sector.",reveal:"You proceed cautiously and the founders launder and flee. The customers' money evaporates, the scandal metastasises, and trust in the entire e-commerce sector collapses.",effects:{FI:-6,EN:-13,GL:-6}}},{id:"finance-0079",location:"finance",arc:"finance-t0-a71",stage:0,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["nbfi","embezzlement","regulator"],prompt:"One bad guy stole all the money from a money-lending business and ran away.",left:{id:"a",label:"Chase him down and punish the people who helped him.",tooltip:"A theft this brazen demands a reckoning.",reveal:"You launch an international pursuit and turn the lens on the regulators who slept. The fugitive is hunted and some enablers fall, and the financial watchdogs are forced, painfully, to wake.",effects:{GL:5,EN:5,FA:-10,FI:2}},right:{id:"b",label:"Forget about it and let him get away.",tooltip:"A public hunt only advertises how deep the rot runs.",reveal:"You let the loss be quietly absorbed. The fugitive keeps his fortune abroad, the sleeping regulators keep their jobs, and the next operator notes how softly a billion can be stolen here.",effects:{FA:3,FI:-6,EN:-10,GL:-6}}},{id:"finance-0080",location:"finance",arc:"finance-t0-a72",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["autonomy","monetary","independence"],prompt:"Your helpers want the bank boss to break the rules to make you look good for the election. The bank boss says this is dangerous.",left:{id:"a",label:"Force the bank boss to break the rules.",tooltip:"A bank that defies the government is a rival.",reveal:"You subordinate the central bank to the ministry's will. The election-year sugar flows, and the institution's hard-won credibility — the thing that anchors inflation and the currency — bleeds away.",effects:{FI:3,MI:2,GL:-10,EN:-6}},right:{id:"b",label:"Let the bank boss do his job the right way.",tooltip:"A tame central bank is a slow-motion crisis.",reveal:"You shield the governor's autonomy. The ministry fumes at being denied its election-year levers, but the bank keeps the credibility that holds the currency and the lenders' trust.",effects:{GL:5,FI:-3,EN:2}}},{id:"finance-0081",location:"finance",arc:"finance-t0-a73",stage:0,speaker:"Food Directorate Chief",portrait:"people",tags:["procurement","farmers","rice"],prompt:"The farmers picked their rice. You can pay them a high price to help them, or a low price to save government money.",left:{id:"a",label:"Pay a high price to help the farmers.",tooltip:"A farmer paid fairly plants again.",reveal:"You buy at a generous price and fill the granary. The growers prosper and the food reserve swells, at a real cost to the budget that the millers' cartel would have pocketed anyway.",effects:{EN:6,FI:-10}},right:{id:"b",label:"Pay a low price to save money.",tooltip:"The granary cannot bankrupt the treasury.",reveal:"You buy cheap and save the budget. The granary fills at less cost, but the farmer, undercut, sells to the millers' cartel at a loss and curses the season.",effects:{FI:5,EN:-10}}},{id:"finance-0082",location:"finance",arc:"finance-t0-a74",stage:0,speaker:"Food Directorate Chief",portrait:"relief",tags:["oms","inflation","poor"],prompt:"Food is too expensive and poor people are starving. You can open the emergency food stores now, or save them just in case things get even worse.",left:{id:"a",label:"Open the emergency food stores now.",tooltip:"A hungry city is a city on the edge.",reveal:"You flood the cities with cheap state rice and the queues ease. The reserve drains and skimming creeps in at the trucks, but the poor eat and the streets stay calm.",effects:{EN:6,FI:-6}},right:{id:"b",label:"Save the food for a worse day.",tooltip:"A granary emptied early starves a later crisis.",reveal:"You ration the reserve against future shortage. The budget and the buffer are protected, but the urban poor go hungry now, and the resentment simmers in the bread queues.",effects:{FI:3,EN:-13}}},{id:"finance-0083",location:"finance",arc:"finance-t0-a75",stage:0,speaker:"Social Protection Director",portrait:"people",tags:["cash-transfer","education","poverty"],prompt:"You can pay poor mothers money if they promise to keep their kids in school and take them to the doctor.",left:{id:"a",label:"Pay the mothers to help the kids.",tooltip:"Money to a mother for her child's schooling pays back for decades.",reveal:"You build the scheme and the payments reach poor mothers. The delivery is a logistical mountain and the budget line permanent, but school attendance climbs and a poverty cycle starts to break.",effects:{EN:8,GL:3,FI:-13}},right:{id:"b",label:"Just give them free things instead of money.",tooltip:"A grand transfer scheme is a budget I cannot promise forever.",reveal:"You keep the patchy in-kind handouts instead. The budget is spared the permanent commitment, and the chance to bind relief to schooling and health is left on the table.",effects:{FI:3,EN:-6}}},{id:"finance-0084",location:"finance",arc:"finance-t0-a76",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["property-tax","wealth","elite"],prompt:"Rich people have giant, empty houses that they don't pay taxes on. You can tax their houses to get money for the country.",left:{id:"a",label:"Tax the giant houses.",tooltip:"A palace should pay more than a payslip.",reveal:"You bring in a genuine property tax on the high end. The revenue base broadens onto idle wealth, the affluent grumble and lobby, and for once the rich shoulder a fair share.",effects:{FI:6,EN:5,FA:-10,GL:2}},right:{id:"b",label:"Let the rich people keep their houses untaxed.",tooltip:"The men in those mansions are the men who fund me.",reveal:"You leave the mansions and empty flats lightly taxed. The donors are content and their wealth stays idle and untouched, and the revenue gap is filled, as ever, by those who cannot dodge.",effects:{FA:3,FI:-6,EN:-10}}},{id:"finance-0085",location:"finance",arc:"finance-t0-a77",stage:0,speaker:"Revenue Board Chairman",portrait:"ambassador",tags:["digital-tax","big-tech","revenue"],prompt:"Big internet companies make lots of money in your country but pay no tax. You can make them pay, but they might get angry.",left:{id:"a",label:"Make the big internet companies pay tax.",tooltip:"A giant that earns here pays here.",reveal:"You tax the tech giants' local earnings. The revenue is real and popular, but the platforms threaten to throttle services and Washington adds it to a list of grievances against you.",effects:{FI:5,GL:-6,EN:2}},right:{id:"b",label:"Wait so they don't get angry.",tooltip:"A fight with the platforms and Washington at once is a fight I lose.",reveal:"You shelve the tax to keep the peace. The giants keep earning tax-free, the revenue stays forgone, and your dependence on their services and Washington's goodwill stays unchallenged.",effects:{GL:2,FI:-6}}},{id:"finance-0086",location:"finance",arc:"finance-t0-a78",stage:0,speaker:"Debt Management Director",portrait:"ambassador",tags:["diaspora-bond","infrastructure","funding"],prompt:"You can ask people from your country living far away to lend you money to build things. But if you lose it, they will be very hurt.",left:{id:"a",label:"Ask them to lend you the money.",tooltip:"Let the children abroad help build the home.",reveal:"The diaspora subscribes generously and the projects get cheap funding. You have also taken the savings of trusting expatriates, and any stumble in repayment would be a betrayal felt worldwide.",effects:{FI:5,GL:2,RE:2}},right:{id:"b",label:"Find the money somewhere else.",tooltip:"I will not stake my people's trust on a bond.",reveal:"You decline to tap the diaspora's savings. The funding is costlier and slower, but you do not put the expatriates' faith — and their remittances — on the line.",effects:{GL:2,FI:-6}}},{id:"finance-0087",location:"finance",arc:"finance-t0-a79",stage:0,speaker:"Agriculture Finance Secretary",portrait:"people",tags:["diesel","irrigation","subsidy"],prompt:"The gas farmers need to water their crops is too expensive. You can help pay for the gas, or let the farmers struggle.",left:{id:"a",label:"Help pay for the gas to save the crops.",tooltip:"A dry pump in boro season is a famine in waiting.",reveal:"You subsidise the diesel and the pumps keep running through the dry season. The crop is saved and the farmers grateful, at a heavy cost and with the usual leakage at the depots.",effects:{EN:6,RE:2,FI:-10}},right:{id:"b",label:"Let the farmers pay the high price.",tooltip:"I cannot subsidise the world's oil price for every pump.",reveal:"You let the diesel cost hit the field. The budget is spared, but the irrigation falters, the boro crop wobbles, and the spectre of a thin harvest looms over the year.",effects:{FI:3,EN:-10,RE:-3}}},{id:"finance-0088",location:"finance",arc:"finance-t0-a80",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["sin-tax","health","revenue"],prompt:"You can put a high tax on junk food and cigarettes so people buy less and stay healthy. But the people who make them will be mad.",left:{id:"a",label:"Put a high tax on junk food and cigarettes.",tooltip:"A tax that fills the treasury and empties the wards is a gift.",reveal:"You levy the sin taxes and revenue and health both improve. The lobbies fight and the public grumbles at pricier vices, but consumption of the worst products begins to fall.",effects:{FI:5,EN:5,FA:-6}},right:{id:"b",label:"Do not add the tax.",tooltip:"A new tax on small pleasures is a small revolt.",reveal:"You hold off on the sin taxes. The lobbies and the public are spared, and so is the disease and the revenue forgone, as the wards fill and the treasury stays thin.",effects:{FA:2,FI:-6,EN:-6}}},{id:"finance-0089",location:"finance",arc:"finance-t0-a81",stage:0,speaker:"Budget Secretary",portrait:"official",tags:["fiscal-rule","debt","discipline"],prompt:"You can make a strict law that stops the government from borrowing too much money. This makes you safe but stops you from spending freely.",left:{id:"a",label:"Make the strict law to be safe.",tooltip:"A state that cannot bind itself cannot be trusted.",reveal:"You pass the fiscal-responsibility law. The lenders cheer the credibility and the markets calm, and you have tied your own hands against the easy election-year splurge.",effects:{GL:5,FI:3,EN:-3}},right:{id:"b",label:"Keep the freedom to spend whatever you want.",tooltip:"A rule that forbids me to spend in a crisis is a trap.",reveal:"You decline the statutory cap. You keep the freedom to splurge when politics demands, and the lenders keep their doubt about whether the deficit will ever truly be controlled.",effects:{FI:-3,EN:2,GL:-6}}},{id:"finance-0090",location:"finance",arc:"finance-t0-a82",stage:0,speaker:"Large Taxpayer Unit Chief",portrait:"official",tags:["transfer-pricing","multinationals","evasion"],prompt:"Huge world companies are tricking the math so they don't pay taxes in your country. You can stop them, but they might leave.",left:{id:"a",label:"Stop their tricks and make them pay.",tooltip:"Profits earned here should be taxed here.",reveal:"You enforce transfer-pricing rules and claw back real revenue. The multinationals grumble and a few trim investment, but the era of booking local fortunes as foreign losses ends.",effects:{FI:6,GL:2,EN:2}},right:{id:"b",label:"Be gentle so they don't leave.",tooltip:"A spooked multinational takes its factory elsewhere.",reveal:"You go easy to protect the investment climate. The firms keep shifting their profits offshore tax-free, and the revenue you could have captured stays on a balance sheet in another country.",effects:{GL:2,FI:-10}}},{id:"finance-0091",location:"finance",arc:"finance-t0-a83",stage:0,speaker:"Agriculture Finance Secretary",portrait:"people",tags:["insurance","farmers","climate"],prompt:"Bad weather keeps destroying farmers' crops. You can create an insurance plan to protect them, but it costs a lot to set up.",left:{id:"a",label:"Create the insurance plan to protect them.",tooltip:"A farmer insured plants without fear.",reveal:"You stand up crop insurance for the climate-battered. The system is costly and complex to run, but a ruined harvest no longer means a ruined family, and the farmers plant with confidence.",effects:{EN:6,RE:2,FI:-10}},right:{id:"b",label:"Just give them a little help after the storms.",tooltip:"A whole insurance system is a luxury; relief is enough.",reveal:"You keep the patchy, after-the-fact relief. It is cheaper and simpler, and each disaster still sweeps another cohort of farmers from their land into the moneylender's grip.",effects:{FI:3,EN:-6}}},{id:"finance-0092",location:"finance",arc:"finance-t0-a84",stage:0,speaker:"Provident Fund Trustee",portrait:"official",tags:["pension-fund","investment","risk"],prompt:"Workers' retirement money is safe but growing slowly. You can try to make it grow faster by investing in risky things, but they might lose it all.",left:{id:"a",label:"Try to make it grow faster in risky things.",tooltip:"Idle retirement money should work harder.",reveal:"You free the funds to invest in markets and infrastructure. Returns rise in good years, but the workers' retirements now ride the market's moods, and the temptation to steer them into pet projects is real.",effects:{FI:3,RE:2,EN:-6}},right:{id:"b",label:"Keep their money safe and boring.",tooltip:"A pensioner's savings are not a venture fund.",reveal:"You keep the funds in safe, dull government paper. The returns are modest, but the workers' retirements are not gambled on markets or raided for politically favoured schemes.",effects:{EN:3,FI:-3}}},{id:"finance-0093",location:"finance",arc:"finance-t0-a85",stage:0,speaker:"Stimulus Coordination Chief",portrait:"fixer",tags:["stimulus","sme","leakage"],prompt:"You have emergency money to save businesses. If you give it out fast, rich friends will grab it all. If you are careful, it will reach small shops.",left:{id:"a",label:"Give it out fast through the banks.",tooltip:"Speed saves firms; controls can come later.",reveal:"You disburse fast through the banks, and the big connected firms hoover up the lion's share. Many are saved, but the small firms that needed it most are left out, and the leakage is enormous.",effects:{FI:3,FA:3,EN:-10}},right:{id:"b",label:"Be careful and make sure small shops get it.",tooltip:"A stimulus that feeds the fed is no stimulus.",reveal:"You insist on a slower channel that reaches the genuinely small and informal. The big firms wait and grumble and a few fail in the delay, but the rescue reaches those it was meant for.",effects:{EN:6,FI:-6,FA:-6}}},{id:"finance-0094",location:"finance",arc:"finance-t0-a86",stage:0,speaker:"Securities Regulator",portrait:"shadow",tags:["ipo","market","manipulation"],prompt:"Rich people are playing a game with the stock market to steal from normal people.",left:{id:"a",label:"Make strict rules to keep it fair.",tooltip:"A market rigged at the listing is rotten at the root.",reveal:"You impose disciplined, fundamentals-based pricing. The listings slow and the insiders lose their easy killing, but the retail investor stops being the designated bag-holder.",effects:{GL:3,EN:5,FI:-3,FA:-3}},right:{id:"b",label:"Let the rich people keep playing their game.",tooltip:"A busy market looks like a healthy one.",reveal:"You let the rigged IPOs flow. The market looks vibrant and the insiders prosper, and the small investors who buy the dumped shares learn, again, who the market is really for.",effects:{FI:3,FA:2,EN:-10}}},{id:"finance-0095",location:"finance",arc:"finance-t0-a87",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["banks","exposure","concentration"],prompt:"A few giant businesses have borrowed almost all the money. If they fail, the country fails. You can force them to stop borrowing so much.",left:{id:"a",label:"Force them to stop borrowing so much.",tooltip:"A bank chained to one tycoon falls with him.",reveal:"You force the concentration down. The over-leveraged groups must deleverage and protest bitterly, but the banking system stops being hostage to a handful of empires.",effects:{FI:3,GL:3,EN:3,FA:-10}},right:{id:"b",label:"Let the giant businesses keep borrowing.",tooltip:"The great groups are the engines; do not stall them.",reveal:"You let the concentration ride. The tycoons keep borrowing freely and stay loyal, and the system's fate stays welded to a few balance sheets that are too big to fail and too connected to refuse.",effects:{FI:2,FA:3,EN:-6,GL:-6}}},{id:"finance-0096",location:"finance",arc:"finance-t0-a88",stage:0,speaker:"Banking Division Secretary",portrait:"fixer",tags:["banks","family-control","governance"],prompt:"One family is allowed to control a whole bank forever, which makes it easy for them to steal. You can change the rule, but they are your friends.",left:{id:"a",label:"Change the rule to stop them from controlling it forever.",tooltip:"A bank run as a family fief gets looted as one.",reveal:"You cap family directorships and tenure. The banking dynasties rage and lean on their party ties, but the boards open up and the insider-looting machine loses its grease.",effects:{GL:5,EN:5,FI:2,FA:-13}},right:{id:"b",label:"Let them keep controlling the bank.",tooltip:"The banking families are pillars of the party.",reveal:"You keep the family-control law intact. The dynasties stay grateful and entrenched, and the next hollowed-out bank is already being quietly emptied by the board that owns it.",effects:{FA:5,FI:-3,EN:-10,GL:-6}}},{id:"finance-0097",location:"finance",arc:"finance-t0-a89",stage:0,speaker:"Tariff Commission Chief",portrait:"official",tags:["dumping","tariffs","industry"],prompt:"Super cheap toys and tools from other countries are hurting your own factories. You can tax them to save your jobs, but things will cost more.",left:{id:"a",label:"Tax the cheap foreign things to save your jobs.",tooltip:"A factory drowned in cheap imports is a town unemployed.",reveal:"You shield the domestic industry with duties. The local manufacturers and their workers are saved, the exporting nation protests to the trade body, and consumers pay more for the protected goods.",effects:{FI:2,EN:3,GL:-6}},right:{id:"b",label:"Keep the foreign things cheap for shoppers.",tooltip:"A consumer's cheap goods are a benefit too.",reveal:"You leave the market open. Consumers enjoy the cheap imports, but the domestic factories buckle and shed jobs, hollowing out the very industry you hoped to grow.",effects:{GL:2,FI:-3,EN:-6}}},{id:"finance-0098",location:"finance",arc:"finance-t0-a90",stage:0,speaker:"Budget Secretary",portrait:"official",tags:["soe","losses","transparency"],prompt:"Government factories are losing tons of money secretly. You can tell everyone the truth, which will be shocking, or keep hiding it.",left:{id:"a",label:"Tell the honest truth about the lost money.",tooltip:"A loss hidden is a debt compounding in the dark.",reveal:"You consolidate the hidden losses into the open budget. The true deficit number shocks, but the lenders respect the honesty and the bleeding enterprises can finally be confronted.",effects:{GL:5,EN:2,FI:-6}},right:{id:"b",label:"Keep hiding the lost money.",tooltip:"An ugly number published is a panic invited.",reveal:"You leave the SOE losses in the shadows. The headline deficit stays flattering, and the hidden hole keeps growing, funded by banks that will one day present the bill.",effects:{FI:3,GL:-10,EN:-3}}},{id:"finance-0099",location:"finance",arc:"finance-t0-a91",stage:0,speaker:"Anti-Money-Laundering Director",portrait:"ambassador",tags:["fatf","compliance","reputation"],prompt:"The world says your country lets bad guys hide stolen money. They will punish you unless you stop them, but the bad guys are your friends.",left:{id:"a",label:"Stop the bad guys to protect your country.",tooltip:"A grey-listed nation is a nation cut off.",reveal:"You build genuine anti-laundering enforcement and dodge the listing. Correspondent banking stays open and investors calm, but your backers' laundering channels are now watched, and they are furious.",effects:{GL:6,FI:3,FA:-10}},right:{id:"b",label:"Do nothing and let the world punish you.",tooltip:"I will not strangle my friends' money to please a watchdog.",reveal:"You make cosmetic changes and your backers keep their channels. The watchdog grey-lists you, correspondent banks pull back, and the cost of every cross-border transaction climbs.",effects:{FA:3,GL:-13,FI:-10}}},{id:"finance-0100",location:"finance",arc:"finance-t0-a92",stage:0,speaker:"Land Reform Commissioner",portrait:"official",tags:["benami","property","corruption"],prompt:"Powerful people hide their stolen houses by putting them in other people's names. You can make a law to catch them and take the houses.",left:{id:"a",label:"Make the law and take the stolen houses.",tooltip:"A fortune in a servant's name is a confession.",reveal:"You pass the law and begin piercing the false ownership. Illicit fortunes are exposed and some seized, and the powerful who hid behind nominees are suddenly, dangerously visible.",effects:{GL:5,EN:6,FI:3,FA:-13}},right:{id:"b",label:"Leave the hidden houses alone.",tooltip:"Too many of those names lead back to my own.",reveal:"You let the benami fortunes lie. The powerful keep their disguised wealth, the loophole stays wide open, and the corrupt accumulation of decades goes quietly unchallenged.",effects:{FA:5,FI:-3,EN:-10,GL:-6}}},{id:"finance-0101",location:"finance",arc:"finance-t0-a93",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["gold","smuggling","policy"],prompt:"People are secretly sneaking gold through your airports, and the police are helping them for money.",left:{id:"a",label:"Make it legal to bring gold in and charge a fair tax.",tooltip:"A trade taxed in daylight starves the smuggler.",reveal:"You open a legal, taxed gold-import channel. The smuggling syndicates lose their edge, the jewellers and the treasury gain, and a shadow trade is dragged into the light.",effects:{FI:5,GL:2,EN:2,FA:-3}},right:{id:"b",label:"Keep it illegal and try to catch them.",tooltip:"Legalising smuggling rewards the smuggler.",reveal:"You keep gold imports banned and chase the couriers. The headline seizures look tough, but the protected syndicates keep the bulk of the trade and the airport rackets stay golden.",effects:{MI:2,FI:-3,EN:-6}}},{id:"finance-0102",location:"finance",arc:"finance-t0-a94",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["vat-refund","drawback","fraud"],prompt:"People are tricking the government into giving them extra money for things they never really made or sold.",left:{id:"a",label:"Use computers to check everything and stop the trick.",tooltip:"A refund on a phantom export is theft with a stamp.",reveal:"You digitise and audit the refund system and the phantom claims collapse. Real exporters wait a little longer for genuine refunds, but a vast leak of public money is plugged.",effects:{FI:6,GL:2,FA:-6}},right:{id:"b",label:"Leave the system alone and let them trick it.",tooltip:"A crackdown punishes the honest exporter too.",reveal:"You leave the refund pipeline loose. The genuine exporters get their money fast, and so do the fraudsters claiming on exports that never existed, bleeding the treasury all the while.",effects:{FI:-6,FA:2,EN:-6}}},{id:"finance-0103",location:"finance",arc:"finance-t0-a95",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["bonded-warehouse","duty","diversion"],prompt:"Factory owners get cheap materials to make things to sell far away, but they secretly sell them at home to get richer.",left:{id:"a",label:"Check their factories closely to stop the secret selling.",tooltip:"A duty-free import sold at home is smuggling by license.",reveal:"You audit the bonds and catch the diverters. Honest producers stop being undercut and the duty is recovered, and the connected abusers and their patrons turn on you.",effects:{FI:5,EN:3,FA:-6}},right:{id:"b",label:"Let the factory owners keep doing it.",tooltip:"The men running those bonds run the party's accounts.",reveal:"You leave the bonded scam alone. The diverted goods keep flooding the local market duty-free, honest producers keep losing, and the racket's patrons stay loyal and rich.",effects:{FA:3,FI:-6,EN:-6}}},{id:"finance-0104",location:"finance",arc:"finance-t0-a96",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["inheritance-tax","wealth","dynasty"],prompt:"Very rich families pass down all their money to their kids without paying any taxes. You could tax this money to help the country.",left:{id:"a",label:"Make them pay a tax when they pass down money.",tooltip:"A fortune unearned should not pass wholly untouched.",reveal:"You levy a tax on great inheritances. Revenue rises and dynastic wealth loosens at the edges, and the established families — yours included — recoil at the precedent.",effects:{FI:5,EN:5,FA:-13}},right:{id:"b",label:"Let them pass down the money without any taxes.",tooltip:"I will not be the one to tax my own children's legacy.",reveal:"You spare inheritances the tax. The hereditary elite keeps its fortunes intact across generations, and the chance to broaden revenue and loosen dynastic wealth passes by.",effects:{FA:5,FI:-6,EN:-6}}},{id:"finance-0105",location:"finance",arc:"finance-t0-a97",stage:0,speaker:"Insurance Regulator",portrait:"people",tags:["microinsurance","poverty","resilience"],prompt:"Poor families lose everything if someone gets sick or a storm hits. You could help them buy cheap protection plans to keep them safe.",left:{id:"a",label:"Help them get cheap protection plans for bad days.",tooltip:"A few taka of cover stands between a family and ruin.",reveal:"You build subsidised, well-regulated microinsurance. The cost and oversight are real, but a flood or a funeral stops meaning the loss of everything for millions of poor households.",effects:{EN:6,FI:-6,GL:2}},right:{id:"b",label:"Let them figure it out on their own.",tooltip:"A whole insurance system for tiny premiums earns nothing.",reveal:"You leave the poor to their informal safety nets of debt and charity. The budget is spared, and the next flood or illness keeps sweeping families from the edge into destitution.",effects:{FI:2,EN:-10}}},{id:"finance-0106",location:"finance",arc:"finance-t0-a98",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["islamic-finance","sukuk","savings"],prompt:"Many religious people won't put money in normal banks because of their religious rules. You can make special religious bank rules for them.",left:{id:"a",label:"Make true religious bank rules to help them.",tooltip:"Faith-shy savings can still build roads.",reveal:"You establish credible Islamic-finance rules and issue sukuk. A vast pool of pious savings enters the formal economy and funds development, and the framework's integrity wins trust.",effects:{FI:5,EN:3,GL:2}},right:{id:"b",label:"Just put a fake religious sticker on normal bank rules.",tooltip:"The label is what the market wants; the substance is detail.",reveal:"You relabel conventional products as Islamic without real substance. The savings trickle in, but the scholars cry foul, a mis-selling scandal brews, and trust in the whole sector frays.",effects:{FI:2,EN:-6,GL:-3}}},{id:"finance-0107",location:"finance",arc:"finance-t0-a99",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["deposit-insurance","savers","stability"],prompt:"Normal people lose all their money if a bank breaks. You can make banks pay a fee to keep people's money safe no matter what.",left:{id:"a",label:"Make the banks pay the fee to keep people's money safe.",tooltip:"A saver who fears for his deposit starts a run.",reveal:"You build real deposit insurance funded by a bank levy. The banks grumble at the cost, but small savers gain protection and the system gains a shock absorber against panic.",effects:{FI:3,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Let people risk losing their money.",tooltip:"A levy on the banks is a cost passed to the customer.",reveal:"You decline the scheme to spare the banks the levy. The savers stay exposed, and the next rumour about a weak bank empties its counters before the truth can catch up.",effects:{FI:2,EN:-10}}},{id:"finance-0108",location:"finance",arc:"finance-t0-a100",stage:0,speaker:"Education Finance Secretary",portrait:"people",tags:["stipend","girls","education"],prompt:"The money you give poor kids, especially girls, to help them stay in school is too small. Giving them more would help, but it costs a lot.",left:{id:"a",label:"Give the kids more money to stay in school.",tooltip:"A stipend that keeps a girl in school changes a generation.",reveal:"You widen and raise the stipend. Enrolment climbs, child marriages slip later, and the budget takes a heavy permanent load for a payoff measured in decades.",effects:{EN:8,GL:3,FI:-13}},right:{id:"b",label:"Keep giving them only a tiny bit of money.",tooltip:"A generous stipend is a budget line forever.",reveal:"You keep the stipend lean. The budget is protected, but the poorest children — and the girls most at risk of early marriage — keep dropping out for want of a few taka.",effects:{FI:3,EN:-6}}},{id:"finance-0109",location:"finance",arc:"finance-t0-a101",stage:0,speaker:"Women's Affairs Finance Officer",portrait:"people",tags:["maternity","allowance","poverty"],prompt:"Poor moms have to work very hard right until their babies are born. You can give them money so they can stay home and rest.",left:{id:"a",label:"Give the moms money to rest and care for their babies.",tooltip:"A nation that will not support its mothers stunts its future.",reveal:"You establish the maternity allowance. Mothers rest and nurse, infant health improves, and the budget carries a new permanent burden for a quietly transformative return.",effects:{EN:8,GL:3,FI:-10}},right:{id:"b",label:"Let them keep working and hope someone else helps.",tooltip:"A new allowance is a promise the budget cannot keep.",reveal:"You decline the allowance. The treasury is spared, and poor mothers keep labouring to the last day and back, the cost paid in their health and their children's.",effects:{FI:3,EN:-10}}},{id:"finance-0110",location:"finance",arc:"finance-t0-a102",stage:0,speaker:"Education Finance Secretary",portrait:"fixer",tags:["textbooks","printing","graft"],prompt:"The people printing free school books for kids are stealing money and making bad books. They are friends with your team.",left:{id:"a",label:"Fix the book printing so kids get good books.",tooltip:"A child's book should not be a printer's bribe.",reveal:"You open the tenders and enforce quality. The party-linked printing cartel rages and threatens delays, but the books arrive better and the graft shrinks.",effects:{EN:5,FI:2,GL:2,FA:-6}},right:{id:"b",label:"Let your friends keep stealing and making bad books.",tooltip:"The books arrive on time; do not break the machine.",reveal:"You leave the cosy contracts intact. The books arrive on schedule, flimsy and over-priced, and the printers' cartel stays a reliable, grateful funder of the party.",effects:{FA:3,FI:-3,EN:-6}}},{id:"finance-0111",location:"finance",arc:"finance-t0-a103",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["tax-net","informal","compliance"],prompt:"Very few people pay taxes. You can ask normal workers and small stores to pay, but they will be very mad because they never have before.",left:{id:"a",label:"Make the normal workers and small stores pay taxes.",tooltip:"A nation where few pay is a nation few can fund.",reveal:"You launch the registration and enforcement drive. Revenue broadens onto those long outside the net, the new taxpayers grumble loudly, and the salaried at last get some company in paying.",effects:{FI:6,EN:3,FA:-6}},right:{id:"b",label:"Let them keep skipping their taxes.",tooltip:"A million new tax notices is a million new enemies.",reveal:"You hold off on the expansion. The informal middle keeps its untaxed cash, the revenue base stays narrow, and the few who do pay keep carrying the many who do not.",effects:{FA:2,FI:-6}}},{id:"finance-0112",location:"finance",arc:"finance-t0-a104",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["currency","redenomination","confidence"],prompt:"Your money has too many zeros on it because prices went way up over the years. Someone wants to chop the zeros off just to make it look nicer.",left:{id:"a",label:"Chop the zeros off to make the money look nicer.",tooltip:"A proud currency wears fewer zeros.",reveal:"You lop the zeros off the taka in a grand relaunch. The notes look tidier and the optics flatter, and the costly, disruptive exercise changes nothing about the inflation that bloated them.",effects:{FI:-6,GL:2,EN:-3}},right:{id:"b",label:"Say no because it doesn't actually fix anything.",tooltip:"Zeros are a symptom; cutting them cures nothing.",reveal:"You spike the vanity project. There is no relaunch fanfare, but the money and disruption are saved, and you focus on the inflation that actually matters.",effects:{FI:3,GL:-3}}},{id:"finance-0113",location:"finance",arc:"finance-t0-a105",stage:0,speaker:"Financial Inclusion Director",portrait:"people",tags:["agent-banking","rural","inclusion"],prompt:"You can let tiny village shops act like banks so poor people can easily save money. Big banks are scared they will lose money from fraud.",left:{id:"a",label:"Let the tiny shops act like banks.",tooltip:"A bank counter in every bazaar banks the nation.",reveal:"You drive agent banking deep into the villages. The unbanked gain savings, credit, and payments for the first time, and the banks' fraud fears prove manageable against the reach gained.",effects:{EN:6,FI:3,GL:2}},right:{id:"b",label:"Let the big banks decide what to do.",tooltip:"A reckless rollout invites a fraud scandal.",reveal:"You leave the pace to the cautious banks. The fraud risk stays low, and so does the reach, and the villages keep waiting for a banking system that never quite arrives.",effects:{FI:2,EN:-6}}},{id:"finance-0114",location:"finance",arc:"finance-t0-a106",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["world-bank","conditions","reform"],prompt:"A big world bank offers you cheap money, but only if you promise to follow their strict rules for how you run things.",left:{id:"a",label:"Take the money and follow their strict rules.",tooltip:"Cheap money and good medicine in one dose.",reveal:"You accept the budget support and enact the reforms. The cheap money helps and the governance genuinely improves, and the nationalists grumble about foreign hands on the tiller.",effects:{FI:5,GL:3,EN:2,FA:-3}},right:{id:"b",label:"Say no to the money so you can make your own rules.",tooltip:"I will not let a foreign bank write my budget.",reveal:"You turn down the conditional money on principle. You keep full policy control, but you forgo cheap finance and the reforms that, conditions aside, the country actually needed.",effects:{FA:2,FI:-10,GL:-3}}},{id:"finance-0115",location:"finance",arc:"finance-t0-a107",stage:0,speaker:"Labour Finance Inspector",portrait:"people",tags:["wage-theft","workers","enforcement"],prompt:"Bosses everywhere are tricking workers and not paying them their full money. You can create a strong police team to stop them.",left:{id:"a",label:"Create a strong team to make bosses pay the workers.",tooltip:"A wage withheld is a wage stolen.",reveal:"You stand up a unit that actually recovers stolen wages and fines the thieves. Workers start getting their due, the donor-employers cry harassment, and a quiet everyday injustice meets a check.",effects:{EN:6,GL:2,FI:-3,FA:-6}},right:{id:"b",label:"Let the workers fight the bosses on their own.",tooltip:"An employer hounded for back-pay closes the gate.",reveal:"You decline to build the unit. The employers keep their impunity, and the workers keep chasing wages already earned and rarely paid in full.",effects:{FA:3,FI:2,EN:-10}}},{id:"finance-0116",location:"finance",arc:"finance-t0-a108",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["recapitalisation","banks","bailout"],prompt:"Government banks are empty because bad managers stole the money. You need to give them more money to stay open.",left:{id:"a",label:"Give them the money with no extra rules.",tooltip:"A failed state bank cannot simply be allowed to die.",reveal:"You pour public money into the looted banks again, no questions asked. They limp on, the loopers and defaulters who emptied them face nothing, and the cycle is set to repeat.",effects:{FI:-6,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Give them the money but make them follow strict new rules.",tooltip:"I will not refill a bucket no one will fix.",reveal:"You make the bailout conditional on board purges, recoveries, and reform. The looters and their patrons fight it bitterly, but the public money goes in with at least a chance of staying.",effects:{GL:3,EN:3,FI:-6,FA:-10}}},{id:"finance-0117",location:"finance",arc:"finance-t0-a109",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["small-business","turnover-tax","simplicity"],prompt:"Tiny stores have to do really hard math to pay taxes. You can make it super easy for them, but you might collect less money overall.",left:{id:"a",label:"Make the taxes super easy for tiny stores.",tooltip:"A tax a shopkeeper can compute is a tax a shopkeeper pays.",reveal:"You bring in a flat, simple turnover tax for small firms. Compliance jumps as the paperwork and the bribes fall away, and the system gains millions of small, honest taxpayers.",effects:{FI:3,EN:5,FA:-3}},right:{id:"b",label:"Keep the hard math rules.",tooltip:"A flat tax leaves money on the table from the bigger fish.",reveal:"You keep the complex regime. The treasury squeezes more from the few who comply, and the rest stay outside, paying the assessor a bribe instead of the state a tax.",effects:{FI:2,EN:-6}}},{id:"finance-0118",location:"finance",arc:"finance-t0-a110",stage:0,speaker:"Central Bank Governor",portrait:"fixer",tags:["directed-lending","credit","distortion"],prompt:"Your helpers want banks to give cheap money to businesses owned by your friends. The bank boss says this is a bad idea.",left:{id:"a",label:"Force the banks to give cheap money to your friends.",tooltip:"Credit steered to friends is friendship repaid.",reveal:"You direct the cheap credit to the favoured firms. They prosper on subsidised loans, the market distorts, and a fresh crop of politically-blessed bad loans begins to sprout.",effects:{FI:2,FA:3,EN:-6,GL:-6}},right:{id:"b",label:"Let the bank boss decide who gets the money safely.",tooltip:"Lending by favour is the seed of every banking crisis.",reveal:"You refuse to direct the credit. The favoured firms grumble at being denied their subsidy, but the banks lend on merit and the next wave of bad loans is not sown by decree.",effects:{GL:3,FI:2,EN:2,FA:-6}}},{id:"finance-0119",location:"finance",arc:"finance-t0-a111",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["interest-rate","inflation","growth"],prompt:"Everything in the stores costs too much. You can make it harder for people to borrow money to fix prices, but it slows down businesses.",left:{id:"a",label:"Make it harder to borrow money so prices drop.",tooltip:"Unchecked inflation robs every wage and saving.",reveal:"You tighten hard and inflation begins, slowly, to ease. Borrowing costs jump, growth cools, the business lobby howls, and the painful medicine works as medicine does.",effects:{FI:3,GL:3,EN:-10}},right:{id:"b",label:"Keep it easy to borrow money so businesses stay busy.",tooltip:"A choked economy is a poorer one for everyone.",reveal:"You keep rates low to protect growth and jobs. The business lobby is pleased and the expansion continues, and inflation keeps gnawing at every wage and every saving in the country.",effects:{EN:2,FI:-6,GL:-3}}},{id:"finance-0120",location:"finance",arc:"finance-t0-a112",stage:0,speaker:"Investment Authority Chief",portrait:"ambassador",tags:["fdi","screening","sovereignty"],prompt:"Other countries want to buy your boat docks and phone companies. You can check them first to stay safe, or let anyone buy to get money fast.",left:{id:"a",label:"Check who is buying things to keep the country safe.",tooltip:"Some assets must not be owned from abroad.",reveal:"You set up a screening regime for strategic sectors. Some investment is deterred and the open-economy purists complain, but no single foreign power buys a chokehold on your ports or banks.",effects:{GL:2,MI:3,FI:-6}},right:{id:"b",label:"Let anyone from other countries buy whatever they want.",tooltip:"Capital is capital; the country needs it.",reveal:"You keep the door wide open. The investment flows in handsomely, and with it a foreign power's quiet acquisition of stakes in the infrastructure your security depends on.",effects:{FI:5,GL:2,MI:-6}}},{id:"finance-0121",location:"finance",arc:"finance-t0-a113",stage:0,speaker:"Land Reform Commissioner",portrait:"people",tags:["land-records","digitisation","corruption"],prompt:"The papers that show who owns land are messy and full of lies. You can use computers to fix it, but corrupt helpers will be mad.",left:{id:"a",label:"Use computers to make the land papers honest.",tooltip:"A clear title is the poor man's strongest shield.",reveal:"You drive the digitisation through against fierce resistance. The forgers and touts lose their racket, land litigation eases, and the poor gain titles that can finally be defended.",effects:{EN:6,GL:3,FI:2,FA:-6}},right:{id:"b",label:"Leave the messy papers alone.",tooltip:"Untangling a century of forgery is a war I cannot win.",reveal:"You leave the land-records chaos intact. The clerks and touts keep their lucrative fraud, the courts stay clogged with land disputes, and the powerful keep dispossessing the weak by forged deed.",effects:{FA:3,FI:-3,EN:-10}}},{id:"finance-0122",location:"finance",arc:"finance-t0-a114",stage:0,speaker:"Ports Finance Director",portrait:"official",tags:["port","efficiency","trade"],prompt:"Your big boat dock is too slow and messy. You can fix it with robots, but the bad groups who make money from the mess will fight you.",left:{id:"a",label:"Fix the dock and stop the bad groups.",tooltip:"A clogged port is a tax on every import and export.",reveal:"You automate the port and break the handling syndicates. The demurrage bill plummets and trade speeds up, and the displaced syndicate bosses and their political patrons declare war.",effects:{FI:5,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Leave the messy dock the way it is.",tooltip:"A port shutdown over reform would cripple the economy.",reveal:"You avoid the fight with the port syndicates. The congestion and demurrage grind on as a permanent drag, and the economy quietly pays the syndicates' toll on every container.",effects:{FA:2,FI:-6,GL:-3}}},{id:"finance-0123",location:"finance",arc:"finance-t0-a115",stage:0,speaker:"Digital Finance Adviser",portrait:"people",tags:["digital-payments","cash","transparency"],prompt:"Everyone uses paper money, making it easy to hide stealing. You can force people to pay with phones, but poor people might struggle.",left:{id:"a",label:"Force people to start paying with their phones.",tooltip:"Cash in the dark is where taxes go to die.",reveal:"You push hard for digital payments and the tax net widens as cash retreats. Corruption gets harder to hide, and the cash-poor and elderly struggle, needing support to keep up.",effects:{FI:5,EN:2,GL:2}},right:{id:"b",label:"Let people keep paying with paper money.",tooltip:"A nation forced cashless overnight abandons its poorest.",reveal:"You let the transition come gradually. No one is left stranded by a sudden cashless push, but the untraceable cash economy keeps shielding the evaders and the grafters.",effects:{EN:2,FI:-3}}},{id:"finance-0124",location:"finance",arc:"finance-t0-a116",stage:0,speaker:"Telecom Finance Director",portrait:"ambassador",tags:["spectrum","auction","revenue"],prompt:"You are selling new invisible waves that make cell phones work. You can charge companies a lot, or sell them cheap so internet is cheaper for everyone.",left:{id:"a",label:"Charge a lot of money to make the government rich.",tooltip:"Spectrum is a one-time treasure; sell it dear.",reveal:"You squeeze the operators for a record auction haul. The treasury banks a windfall, and the operators, recouping it, keep data dear and coverage thin for years to come.",effects:{FI:6,EN:-6,RE:-3}},right:{id:"b",label:"Sell them cheap so people get cheaper phone internet.",tooltip:"Cheap data grows more than a one-time cheque.",reveal:"You price the spectrum to spur coverage and affordable data. The one-time haul is smaller, but cheap fast internet spreads, and the digital economy it feeds pays back for years.",effects:{EN:5,GL:2,FI:-6}}},{id:"finance-0125",location:"finance",arc:"finance-t0-a117",stage:0,speaker:"Aviation Finance Secretary",portrait:"fixer",tags:["airline","losses","soe"],prompt:"Your country's airplane company loses money every day because it's run badly. You keep paying to keep it flying to look cool.",left:{id:"a",label:"Fix the airplane company or sell it to someone else.",tooltip:"A flag that flies on subsidy flies on borrowed time.",reveal:"You force the restructuring, cutting the padded leases and the overstaffing. The unions and the brokers who profited rage, but the airline stops being a bottomless drain on the treasury.",effects:{FI:6,GL:2,EN:-10,FA:-6}},right:{id:"b",label:"Keep paying government money so it keeps flying.",tooltip:"A nation's airline is a nation's face.",reveal:"You keep the airline aloft on subsidy. The flag flies and the patronage flows, and the padded deals and graft keep the losses mounting flight after flight.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0126",location:"finance",arc:"finance-t0-a118",stage:0,speaker:"Fiscal Climate Adviser",portrait:"official",tags:["carbon-tax","climate","revenue"],prompt:"You can charge a tax on things that make dirty smoke. It helps the earth, but makes things more expensive for people who already don't have enough money.",left:{id:"a",label:"Start charging the dirty smoke tax.",tooltip:"The polluter should pay, and the treasury should collect.",reveal:"You bring in a carbon levy. Revenue rises, the economy nudges greener, and the climate donors approve, while industry and consumers feel one more cost in an already pinched year.",effects:{FI:3,EN:3,GL:3,RE:2}},right:{id:"b",label:"Don't charge the tax right now.",tooltip:"A new fuel levy amid inflation is a riot ordered in advance.",reveal:"You shelve the carbon tax. Industry and consumers are spared another cost, and the revenue, the green nudge, and the donor goodwill all go uncollected.",effects:{FI:-3,EN:-3,GL:-3}}},{id:"finance-0127",location:"finance",arc:"finance-t0-a119",stage:0,speaker:"Revenue Board Chairman",portrait:"shadow",tags:["capital-gains","stock-market","elite"],prompt:"Rich people who make a lot of money in the stock market don't pay taxes on it. If you tax them, they might crash the market on purpose.",left:{id:"a",label:"Make the rich people pay taxes on that money.",tooltip:"A fortune made on the bourse should pay like any other.",reveal:"You tax the big market gains. Revenue rises and fairness with it, the small investor is spared, and the big players stage a noisy sell-off and lean on every connection they have.",effects:{FI:5,EN:3,FA:-6}},right:{id:"b",label:"Let them keep the money without paying taxes.",tooltip:"A capital-gains tax could spook the whole bourse.",reveal:"You leave the gains untaxed to keep the market calm. The wealthy and the manipulators keep their tax-free windfalls, and the revenue and the fairness go uncollected.",effects:{FA:2,FI:-6,EN:-3}}},{id:"finance-0128",location:"finance",arc:"finance-t0-a120",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["imf","transparency","data"],prompt:"The big world bank wants to tell everyone the honest, ugly truth about your country's money problems. You can try to push them to hide it.",left:{id:"a",label:"Let them tell everyone the honest truth.",tooltip:"A diagnosis softened is a disease untreated.",reveal:"You let the IMF publish the unvarnished assessment. The numbers sting and the opposition feasts, but the lenders and markets reward the transparency, and the problems can finally be named.",effects:{GL:5,FI:-3,EN:-3}},right:{id:"b",label:"Push them to hide the bad parts of the story.",tooltip:"An honest report is a headline against me.",reveal:"You lean on the mission for a gentler write-up. The official narrative survives intact, the markets are soothed by a number that is not quite real, and the IMF's quiet doubts deepen.",effects:{FI:2,GL:-10}}},{id:"finance-0129",location:"finance",arc:"finance-t0-a121",stage:0,speaker:"Industrial Safety Secretary",portrait:"people",tags:["garments","safety","factories"],prompt:"A factory broke and fell down. Now everyone demands factories be made safer. Owners want your help to avoid paying for safety.",left:{id:"a",label:"Force the owners to make their factories super safe.",tooltip:"A factory that buries its workers is no asset.",reveal:"You enforce the retrofits hard, factory by factory. The owners howl at the cost and a few lines close, but the death-trap buildings are fixed and the buyers keep their orders.",effects:{EN:8,GL:5,FI:-6,FA:-6}},right:{id:"b",label:"Help the owners dodge the safety rules.",tooltip:"Protect the owners who keep a million employed.",reveal:"You help the owners paper over the accord. The retrofits go undone, the lines stay cheap, and the next fire or collapse is already being built into a building no one fixed.",effects:{FI:3,FA:3,EN:-16,GL:-10}}},{id:"finance-0130",location:"finance",arc:"finance-t0-a122",stage:0,speaker:"Tariff Commission Chief",portrait:"official",tags:["machinery","duty","industry"],prompt:"Factory bosses want to bring in big machines without paying taxes. But some of them trick you and bring in normal stuff to sell instead.",left:{id:"a",label:"Let them bring in all machines without taxes.",tooltip:"Cheap machines build modern factories.",reveal:"You open the duty-free channel wide. Genuine manufacturers re-tool cheaply, and the disguised-import racket revives alongside, smuggling finished goods in under the machinery label.",effects:{FI:-3,EN:3,RE:2}},right:{id:"b",label:"Check very carefully before letting anything in without taxes.",tooltip:"A loophole for machines becomes a loophole for everything.",reveal:"You permit duty-free machinery only with strict end-use verification. The honest manufacturers grumble at the paperwork, but the disguised-import loophole stays shut and the duty is protected.",effects:{FI:3,EN:2,FA:-3}}},{id:"finance-0131",location:"finance",arc:"finance-t0-a123",stage:0,speaker:"ICT Investment Director",portrait:"official",tags:["it","hi-tech-park","jobs"],prompt:"You can build a giant computer park to create smart jobs. If you don't spend enough money, it will just be empty buildings.",left:{id:"a",label:"Spend a lot to make the computer park amazing.",tooltip:"The future's factories are made of code.",reveal:"You back the park with reliable power, fibre, and incentives, and court real anchor tenants. The cost is high and the bet uncertain, but a genuine tech cluster and its skilled jobs begin to form.",effects:{EN:5,FI:-10,GL:2,RE:2}},right:{id:"b",label:"Build it cheaply and hope it works out.",tooltip:"A grand park half-empty is a grand embarrassment.",reveal:"You build a modest version and hope tenants come. The cost is contained, but without serious infrastructure and incentives the park risks joining the country's collection of hollow monuments.",effects:{FI:-3,EN:2}}},{id:"finance-0132",location:"finance",arc:"finance-t0-a124",stage:0,speaker:"SME Finance Director",portrait:"people",tags:["women","entrepreneurs","credit"],prompt:"Women who want to start small shops can't borrow money from banks. You can create a special fund just to help them.",left:{id:"a",label:"Create the special fund to help women start shops.",tooltip:"Half the talent locked out is half the economy lost.",reveal:"You build the dedicated fund. Default risk runs higher and the bankers grumble, but a wave of women-led businesses opens, and a vast pool of stifled enterprise finally finds capital.",effects:{EN:6,FI:-6,GL:2}},right:{id:"b",label:"Let the banks treat everyone the same.",tooltip:"Special funds breed special defaults.",reveal:"You keep credit 'neutral', which in practice means collateral-bound and male. The default risk stays low and the bankers content, and women entrepreneurs keep borrowing from family or not at all.",effects:{FI:2,EN:-6}}},{id:"finance-0133",location:"finance",arc:"finance-t0-a125",stage:0,speaker:"Planning Commission Member",portrait:"fixer",tags:["mp-fund","patronage","local"],prompt:"Your politicians get a big bag of money every year to fix their towns. Most of them use it to build their own houses or help friends.",left:{id:"a",label:"Keep giving the politicians the bag of money.",tooltip:"An MP without a chequebook is an MP without friends.",reveal:"You keep the funds flowing to the MPs. They build loyalty and the occasional genuine road, and skim and steer the rest to their own contractors and kin, audited by no one.",effects:{FA:5,MI:2,EN:-10,FI:-3}},right:{id:"b",label:"Give the money to honest town leaders instead.",tooltip:"Development should follow a plan, not a member's whim.",reveal:"You move the money to audited local councils. The MPs lose a treasured lever and seethe, but the development spreads by need and plan rather than by the member's favour.",effects:{EN:6,GL:3,FA:-10}}},{id:"finance-0134",location:"finance",arc:"finance-t0-a126",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["rating","markets","reform"],prompt:"The world will say your country is bad with money unless you raise taxes and cut help for the poor. People will hate you for it.",left:{id:"a",label:"Raise taxes to prove you are good with money.",tooltip:"A downgrade taxes every loan for a decade.",reveal:"You enact the painful reforms and stave off the downgrade. The public feels the squeeze and grumbles, but the rating holds and the country's future borrowing stays affordable.",effects:{GL:3,FI:3,EN:-13}},right:{id:"b",label:"Ignore the world and keep people happy for now.",tooltip:"I will not cut subsidies to please a foreign rating.",reveal:"You spare the public the reforms and take the downgrade. The politics stay calm now, and every loan the country raises henceforth carries a higher price for the rating you let slip.",effects:{EN:3,FI:-10,GL:-6}}},{id:"finance-0135",location:"finance",arc:"finance-t0-a127",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["allowance","veterans","spending"],prompt:"The list of old war heroes who get free money is growing because people are lying and faking papers. You can clean the list up.",left:{id:"a",label:"Check the papers and kick the liars off the list.",tooltip:"A forged certificate dishonours the real heroes.",reveal:"You audit the rolls and strip out the forgeries. The genuine veterans are honoured and the fraud purged, and the cleansing of a sacred list draws furious accusations of disrespect.",effects:{FI:3,GL:2,EN:2,FA:-6}},right:{id:"b",label:"Keep paying everyone on the list to avoid anger.",tooltip:"I will not be the one to question a freedom-fighter's claim.",reveal:"You leave the rolls untouched. The genuine and the forged draw the honour allowance alike, the sacred constituency stays placated, and the fraud quietly bloats the budget line.",effects:{FA:5,FI:-6,EN:-3}}},{id:"finance-0136",location:"finance",arc:"finance-t0-a128",stage:0,speaker:"Transport Economy Adviser",portrait:"people",tags:["gig-economy","ride-share","workers"],prompt:"Delivery and driving apps give young people jobs, but the bosses don't protect them or pay them enough.",left:{id:"a",label:"Make strong rules to protect the delivery drivers.",tooltip:"A job with no floor is a trap with an app.",reveal:"You impose minimum earnings, insurance, and dispute rights on the platforms. Fares rise a little and the apps threaten to scale back, but a precarious workforce gains a measure of security.",effects:{EN:6,FI:-3,GL:2}},right:{id:"b",label:"Leave the apps alone so prices stay cheap.",tooltip:"Cheap rides and easy work are their own reward.",reveal:"You leave the platforms free. Fares stay low and the apps expand, and the young riders and drivers keep working without a floor, a benefit, or a safety net beneath them.",effects:{FI:2,EN:-10}}},{id:"finance-0137",location:"finance",arc:"finance-t0-a129",stage:0,speaker:"Commerce Envoy",portrait:"ambassador",tags:["fta","regional","trade"],prompt:"You can make a deal to trade freely with neighbors. It helps sell your things, but cheap neighbor things might close your own shops.",left:{id:"a",label:"Sign the deal to trade freely with neighbors.",tooltip:"A market opened both ways favours the competitive.",reveal:"You sign the FTA and your exporters gain access to vast new markets. Some domestic industries, undercut by cheaper imports, buckle and shed jobs, and the adjustment is wrenching.",effects:{GL:5,FI:2,EN:-6}},right:{id:"b",label:"Say no to protect your own small shops.",tooltip:"Free trade with a giant is a flood with a treaty.",reveal:"You decline the deal to shield domestic industry. The home producers are protected and the jobs held, but your exporters lose the access, and the integration the region is moving toward leaves you behind.",effects:{EN:2,FI:-3,GL:-6}}},{id:"finance-0138",location:"finance",arc:"finance-t0-a130",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["stamp-duty","property","informality"],prompt:"The tax to buy a house is so high that everyone lies about the price. If you lower the tax, more people might be honest.",left:{id:"a",label:"Lower the tax to make people honest.",tooltip:"A rate too high is a rate evaded.",reveal:"You slash the stamp duty. Declarations jump toward honesty, the property market quickens, and after a brief dip the revenue actually rises as the under-declaration racket collapses.",effects:{FI:3,EN:3,GL:2}},right:{id:"b",label:"Keep the high tax just in case.",tooltip:"A rate cut is a revenue cut I cannot risk now.",reveal:"You keep the duty high. The headline rate looks lucrative, and the universal under-declaration keeps fuelling black money while the treasury collects on fictional sale prices.",effects:{FI:-3,EN:-3}}},{id:"finance-0139",location:"finance",arc:"finance-t0-a131",stage:0,speaker:"Industries Secretary",portrait:"people",tags:["sme","manufacturing","cluster"],prompt:"Poor, tiny workshops make important parts for your machines. You can give them training and money to grow big, or ignore them for flashier things.",left:{id:"a",label:"Help the tiny workshops grow and become better.",tooltip:"A nation that makes its own parts depends on no one's.",reveal:"You back the workshops with credit, training, and standards. The transformation is slow and unglamorous, but an import-substituting manufacturing base — and skilled jobs — takes root.",effects:{EN:5,FI:-6,RE:2}},right:{id:"b",label:"Ignore them and focus on big, shiny projects.",tooltip:"Workshops do not make headlines.",reveal:"You steer support to glossier projects instead. The flagship announcements dazzle, and the unsung workshops that actually keep industry running stay starved and stuck.",effects:{GL:2,FI:-3,EN:-3}}},{id:"finance-0140",location:"finance",arc:"finance-t0-a132",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["adb","loan","megaproject"],prompt:"A bank offers cheap money to build a road, but they demand you build it perfectly without any cheating or stealing by your builders.",left:{id:"a",label:"Take the money and build the road perfectly.",tooltip:"Cheap money and clean procurement together.",reveal:"You take the soft loan and accept the rigorous conditions. The build is slower and the contractors are denied their padding, but the corridor is cheaply financed and honestly built.",effects:{FI:3,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Use your own money so your builders can do what they want.",tooltip:"I will not let a bank's auditors run my project.",reveal:"You skip the conditional loan and finance it domestically. The contractors get their padding and the speed they want, and the project costs more, runs dirtier, and strains the budget.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0141",location:"finance",arc:"finance-t0-a133",stage:0,speaker:"Central Bank Governor",portrait:"shadow",tags:["currency","high-note","black-money"],prompt:"You can print a really big piece of money. It makes carrying cash easy, but also makes it super easy for bad guys to hide stolen money.",left:{id:"a",label:"Print the really big piece of money.",tooltip:"A bigger note is a smaller suitcase.",reveal:"You print the big note. Large cash deals get easier for everyone, including the hoarders, bribers, and launderers who can now move fortunes in a slim envelope.",effects:{FI:2,EN:-6,GL:-3}},right:{id:"b",label:"Don't print it.",tooltip:"A big note is a bribe's best friend.",reveal:"You refuse the high-denomination note. Large cash deals stay bulky and a little harder to hide, a small friction against the corruption that thrives on portable wealth.",effects:{GL:2,EN:2}}},{id:"finance-0142",location:"finance",arc:"finance-t0-a134",stage:0,speaker:"Urban Economy Officer",portrait:"people",tags:["vendors","informal","licensing"],prompt:"People selling food on the street have to pay bad police officers every day to not get kicked out. You can give them real licenses.",left:{id:"a",label:"Give the street sellers real licenses so they are safe.",tooltip:"A hawker licensed is a hawker freed from the mastan.",reveal:"You license the vendors and assign them zones. The police and mastans lose their daily extortion and resent it, but the vendors gain legal standing and the footpaths get some order.",effects:{EN:6,FI:2,MI:-3,FA:-3}},right:{id:"b",label:"Keep kicking them out of the streets.",tooltip:"The footpaths belong to the pedestrian.",reveal:"You keep mounting eviction drives that scatter the vendors for a day before they return. The bribes keep flowing to police and mastans, and nothing actually changes but the optics.",effects:{MI:2,FI:-3,EN:-10}}},{id:"finance-0143",location:"finance",arc:"finance-t0-a135",stage:0,speaker:"Railway Finance Secretary",portrait:"people",tags:["railway","losses","subsidy"],prompt:"Government trains lose money on every ride because tickets are so cheap. But poor people need those cheap trains.",left:{id:"a",label:"Make the tickets cost more and fire extra workers.",tooltip:"A railway that bankrupts itself serves no one long.",reveal:"You raise fares, curb the ticketless, and trim the bloat. The losses narrow and the service steadies, but the poor who depend on cheap travel feel the pinch and the unions strike.",effects:{FI:5,EN:-10,FA:-3}},right:{id:"b",label:"Keep the tickets super cheap and lose money.",tooltip:"The train is the poor man's only affordable distance.",reveal:"You keep fares low and the trains rolling at a loss. The poor keep their cheap lifeline, and the railway keeps draining the budget, its graft and overstaffing untouched.",effects:{EN:5,FI:-10}}},{id:"finance-0144",location:"finance",arc:"finance-t0-a136",stage:0,speaker:"Industries Secretary",portrait:"doctor",tags:["pharma","api","self-reliance"],prompt:"Your medicine makers buy all their magic ingredients from other countries. You can build a special park to make the ingredients at home.",left:{id:"a",label:"Build the special park to make the magic ingredients.",tooltip:"An industry that imports its core imports its fate.",reveal:"You commit to the API park. The investment is heavy and the payoff years away, but the pharma industry begins to make its own ingredients and an export edge sharpens.",effects:{FI:-6,EN:3,GL:2,RE:2}},right:{id:"b",label:"Keep buying them from other countries.",tooltip:"Why build what I can buy?",reveal:"You keep relying on imported ingredients. The capital is saved, and the industry stays one foreign supply-shock away from a shortage of the medicines the country and its exports depend on.",effects:{FI:2,EN:-3,GL:-3}}},{id:"finance-0145",location:"finance",arc:"finance-t0-a137",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["sim-tax","internet","access"],prompt:"Phones and internet are taxed heavily to get the government money. But this makes it too expensive for poor people to use the internet.",left:{id:"a",label:"Keep the high taxes to make the government rich.",tooltip:"A connected nation can spare a few taka per gigabyte.",reveal:"You raise the connectivity taxes and the revenue flows easily. Data and phones get dearer, the rural poor and the digital economy both feel it, and a regressive levy deepens.",effects:{FI:5,EN:-10}},right:{id:"b",label:"Lower the taxes so poor people can use the internet.",tooltip:"A tax on data is a tax on the future.",reveal:"You cut the SIM and data taxes. The easy revenue is forgone, but cheaper connectivity spreads to the rural poor and feeds the digital economy that pays back many times over.",effects:{EN:5,GL:2,FI:-6}}},{id:"finance-0146",location:"finance",arc:"finance-t0-a138",stage:0,speaker:"Cottage Industry Director",portrait:"people",tags:["handloom","heritage","artisans"],prompt:"People who make beautiful clothes by hand are going out of business because machines are faster. You can step in to save their art.",left:{id:"a",label:"Give them money and help so they can keep making clothes by hand.",tooltip:"A craft lost is a heritage no money rebuilds.",reveal:"You back the weavers with credit, design, and a protected heritage label. The cost is modest and the market still hard, but a dying craft and the communities who keep it get a fighting chance.",effects:{EN:5,GL:2,FI:-6}},right:{id:"b",label:"Do nothing and let the machines win.",tooltip:"Nostalgia cannot outcompete a power loom.",reveal:"You let the handloom communities fend for themselves. The cheaper power-loom goods win, the looms fall silent one village at a time, and a centuries-old craft fades toward memory.",effects:{FI:2,EN:-6}}},{id:"finance-0147",location:"finance",arc:"finance-t0-a139",stage:0,speaker:"Export Zone Authority Chief",portrait:"people",tags:["epz","wages","investment"],prompt:"Special factory zones ban workers from grouping up to ask for better pay. If you let them group up, the foreign owners might get scared and leave.",left:{id:"a",label:"Let the workers group up and ask for better pay.",tooltip:"A showcase built on suppressed wages shames the show.",reveal:"You lift the EPZ wage and permit unions. Some investors grumble and threaten to look elsewhere, but the zone workers gain dignity and pay, and the showcase stops being a sweatshop with landscaping.",effects:{EN:6,GL:3,FI:-6,FA:-3}},right:{id:"b",label:"Keep the ban so the foreign owners stay happy.",tooltip:"The investors came for the cheap, calm labour.",reveal:"You keep the zones cheap and union-free. The investors stay content and the FDI flows, and the zone workers keep earning below the national floor with no voice to change it.",effects:{FI:5,FA:2,EN:-13,GL:-3}}},{id:"finance-0148",location:"finance",arc:"finance-t0-a140",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["advance-tax","compliance","burden"],prompt:"The government secretly takes a little tax money from almost everything people do. It's easy money, but it is very unfair to poor people.",left:{id:"a",label:"Fix the taxes so they are fair to everyone.",tooltip:"A tax collected before profit is a tax on existence.",reveal:"You prune the tangle of advance taxes. Collection gets a little harder and revenue dips short-term, but the hidden burden on the small and the consumer eases and the system grows fairer.",effects:{EN:5,GL:2,FI:-6}},right:{id:"b",label:"Keep taking the easy, secret tax money.",tooltip:"A tax collected at source is a tax that does not escape.",reveal:"You keep the advance-tax web intact. Collection stays easy and leak-proof, and the hidden, regressive burden goes on falling hardest on those least able to reclaim it.",effects:{FI:3,EN:-6}}},{id:"finance-0149",location:"finance",arc:"finance-t0-a141",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["budget","deficit","populism"],prompt:"Your friends want to promise to give away tons of free stuff right before an election to win votes, even though you don't have the money.",left:{id:"a",label:"Promise to give away tons of free stuff to win.",tooltip:"A budget is a promise, and promises win votes.",reveal:"You unveil the record-shattering budget to fanfare. The schemes dazzle and the votes warm, and the fantastical revenue forecasts collapse within months, forcing painful cuts you will own.",effects:{EN:5,FI:-13,GL:-6}},right:{id:"b",label:"Be honest and only promise what you can afford.",tooltip:"A budget built on fantasy is a crisis with a launch date.",reveal:"You table a realistic budget the numbers actually support. The cabinet grumbles that it lacks fireworks for the campaign, but the lenders trust it and no mid-year reckoning lies in wait.",effects:{GL:5,FI:3,EN:-3}}},{id:"finance-0150",location:"finance",arc:"finance-t0-a141",stage:1,speaker:"Budget Secretary",portrait:"fixer",tags:["budget","deficit","populism"],prompt:"You promised to build lots of things, but the money is gone. You can just announce more fake projects to look good, or quietly finish the old ones.",left:{id:"a",label:"Announce more fake projects to look good.",tooltip:"A ribbon cut is worth more than a road finished.",reveal:"You keep launching glittering new schemes over the unfinished ones. The headlines flow, the backlog of half-built promises grows, and the public learns that an announcement here rarely becomes a thing.",effects:{FA:2,EN:-10,FI:-3}},right:{id:"b",label:"Finish what you started and don't make new promises.",tooltip:"A promise kept quietly beats ten announced loudly.",reveal:"You stop the announcement treadmill and fund the existing commitments to completion. There are fewer ribbons to cut, but the schools, roads, and clinics already promised actually get built.",effects:{EN:6,GL:2,FI:-6}}},{id:"finance-0151",location:"finance",arc:"finance-t1-a0",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:"A term later, the same fault line tears open again. The bank boss says the country is running out of money fast, but you have been pretending you have more. He says people will find out the truth soon.",left:{id:"a",label:"Keep pretending you have lots of money.",tooltip:"Confidence is a currency too.",reveal:"The headline reserves look calm; importers and rating agencies quietly stop believing you, and the black-market dollar climbs.",effects:{FI:3,GL:-13,EN:-6}},right:{id:"b",label:"Tell the truth about having less money.",tooltip:"A lie in the books is a run waiting to happen.",reveal:"The honesty stings the markets for a week, then steadies them. The IMF, reassured by candour, eases the next tranche.",effects:{FI:-10,GL:8,MI:-6}}},{id:"finance-0152",location:"finance",arc:"finance-t1-a0",stage:1,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. You are spending all the country's savings to make your money look strong. The bank boss says you must stop, even if it makes things very expensive.",left:{id:"a",label:"Stop spending savings and let prices go up.",tooltip:"Better a fair price than an empty vault.",reveal:"The taka drops; exporters and remitters cheer while every imported good — fuel, food, medicine — jumps overnight. The streets feel it instantly.",effects:{FI:6,GL:5,EN:-18}},right:{id:"b",label:"Keep spending savings to look strong.",tooltip:"A cliff-edge devaluation would break the poor.",reveal:"You hold the line a while longer at the cost of the vault. The reserves thin toward the danger mark and the market sniffs the weakness.",effects:{FI:-16,EN:5,GL:-6}}},{id:"finance-0153",location:"finance",arc:"finance-t1-a0",stage:2,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:"A new season of power, an old problem with sharper teeth. You are out of money. A big global bank will give you emergency money, but only if you make gas prices very high right now. Your helpers say angry people will fill the streets.",left:{id:"a",label:"Take the money and raise gas prices.",tooltip:"Solvency now, anger managed later.",reveal:"Dollars refill the vault as fuel and power prices spike. The crisis on the balance sheet becomes a crisis in the bazaars.",effects:{FI:10,GL:6,EN:-18,MI:-6}},right:{id:"b",label:"Say no and look for money somewhere else.",tooltip:"I will not detonate prices on a foreign schedule.",reveal:"You borrow from friendly capitals instead — costlier, with strings of their own. The subsidy holds; the debt stack grows more dangerous.",effects:{FI:3,GL:-6,EN:5,RE:-6}}},{id:"finance-0154",location:"finance",arc:"finance-t1-a1",stage:0,speaker:"Bank Reform Commissioner",portrait:"official",tags:["banks","default-loans","cronies"],prompt:"The crisis returns, and this time the cabinet is watching. Rich families who give you money are secretly stealing from the banks. If you tell the truth, the banks will look broken. If you hide it, the banks will rot from the inside.",left:{id:"a",label:"Keep hiding it so the banks look fine.",tooltip:"These men keep the party funded.",reveal:"The books stay pretty and the donors stay loyal. The hole grows in the dark, and one bank's collapse could pull down the rest.",effects:{FI:5,FA:3,GL:-13,EN:-6}},right:{id:"b",label:"Tell the truth and make them pay it back.",tooltip:"A looted bank is a tax on every saver.",reveal:"You name the defaulters and freeze their rolling. The donors revolt and the books look grim — but depositors, and the IMF, exhale.",effects:{FI:-13,GL:8,MI:-6,FA:-10}}},{id:"finance-0155",location:"finance",arc:"finance-t1-a1",stage:1,speaker:"Bank Reform Commissioner",portrait:"official",tags:["banks","default-loans","cronies"],prompt:"Once more the issue lands on your desk, the stakes higher than before. You caught the biggest bank thief, but he owns TV stations and helps your team. He offers to pay back a little bit and say nice things about you on TV if you let him go.",left:{id:"a",label:"Take the deal and the nice TV news.",tooltip:"Half a recovery and a friendly press is no small thing.",reveal:"He repays a fraction and his channels glow for you. Every other defaulter learns the price of getting caught is merely negotiable.",effects:{FI:3,FA:5,GL:-10,MI:3}},right:{id:"b",label:"Make him pay back every penny, no matter what.",tooltip:"The law cannot have a discount for the loud.",reveal:"You break him publicly. His networks turn on you nightly — but the message lands that the era of free money is over.",effects:{FI:6,GL:5,FA:-13,MI:-10}}},{id:"finance-0156",location:"finance",arc:"finance-t1-a2",stage:0,speaker:"Expatriate Welfare Secretary",portrait:"official",tags:["remittances","hundi","diaspora"],prompt:"Another year survived, and the reckoning circles back. Workers in other countries are sending money home secretly because it's cheaper. This means your government doesn't get to count it. You can offer them a bonus to send it legally.",left:{id:"a",label:"Pay them a bonus to send money legally.",tooltip:"Buy the dollars back into the system.",reveal:"Formal inflows jump and the reserves breathe — at a real fiscal cost, and with smugglers adapting their margins fast.",effects:{FI:6,EN:3,GL:3}},right:{id:"b",label:"Send police to stop the secret money networks.",tooltip:"Punish the channel, not subsidise the rival.",reveal:"Raids disrupt the networks briefly. The operators reroute through crypto and gold; workers, harassed, trust the banks even less.",effects:{FI:-6,MI:5,GL:-6}}},{id:"finance-0157",location:"finance",arc:"finance-t1-a3",stage:0,speaker:"Garment Buyers' Consortium",portrait:"official",tags:["rmg","exports","wages"],prompt:"The ground has shifted; the same demand arrives with new menace. People who buy your country's clothes say you must pay workers more and make factories safer, or they will stop buying. Factory owners say paying more will ruin them.",left:{id:"a",label:"Force the owners to pay workers more.",tooltip:"Cheap labour is a race we lose anyway.",reveal:"Wages rise; the buyers stay and the workers quiet. Marginal factories shutter, and the owners — your donors — are furious.",effects:{GL:6,EN:6,FI:-13,FA:-6}},right:{id:"b",label:"Protect the owners and keep wages low.",tooltip:"Mills closed help no worker at all.",reveal:"The owners are grateful and the lines keep running. Some buyers quietly diversify away, and the wage protests build.",effects:{FI:6,FA:5,EN:-16,GL:-10}}},{id:"finance-0158",location:"finance",arc:"finance-t1-a4",stage:0,speaker:"Megaproject Coordinator",portrait:"official",tags:["debt","infrastructure","china"],prompt:"History rhymes: the conflict reopens deeper than last time. You built giant bridges and trains using borrowed money. Now you must pay it back, but you don't have enough. One lender wants to own your boat docks if you can't pay.",left:{id:"a",label:"Let them own the boat docks so you get more time.",tooltip:"Keep the cranes turning at any cost.",reveal:"The repayment is rescheduled and construction continues. A strategic port is now partly mortgaged to a foreign creditor.",effects:{FI:5,RE:-10,GL:-13,MI:-6}},right:{id:"b",label:"Stop building new things and pay the money back now.",tooltip:"No more monuments we cannot afford.",reveal:"You freeze the ribbon-cuttings to service the debt. The optics dull and contractors grumble, but the balance sheet stops bleeding.",effects:{FI:6,GL:3,EN:-6,FA:-6}}},{id:"finance-0159",location:"finance",arc:"finance-t1-a5",stage:0,speaker:"Financial Intelligence Chief",portrait:"official",tags:["laundering","capital-flight","elite"],prompt:"Mid-reign, the old wound is torn afresh. Rich people who complain about the country are secretly hiding their money in other countries. Many of them are your friends.",left:{id:"a",label:"Hide the secret so your friends don't get in trouble.",tooltip:"These are the people who hold the regime up.",reveal:"The list disappears and the friends stay close. The reserves keep leaking out the back door you chose not to lock.",effects:{FI:-10,FA:5,GL:-10}},right:{id:"b",label:"Tell everyone and freeze your friends' money.",tooltip:"Patriotism that flees with the money is none.",reveal:"You name and freeze. The elite is enraged and the courts will be slow — but capital flight stutters and the public roars approval.",effects:{FI:6,EN:5,GL:5,FA:-13}}},{id:"finance-0160",location:"finance",arc:"finance-t1-a6",stage:0,speaker:"Trade & Prices Adviser",portrait:"people",tags:["inflation","subsidies","food"],prompt:"The pressure you deferred has come due, larger now. Food is too expensive and people are hungry and angry. You can buy cheap food from other countries to help, but it will cost the government a lot of money.",left:{id:"a",label:"Buy the cheap food from outside to help people.",tooltip:"An empty plate topples governments faster than deficits.",reveal:"Prices ease at the bazaar and tempers cool. The deficit widens and local farmers, undercut, send their own anger upward.",effects:{EN:8,FI:-13,RE:-6}},right:{id:"b",label:"Do not buy it, and tell people to eat less.",tooltip:"Cheap imports today, dead farms tomorrow.",reveal:"The farmers keep their margins and the budget holds. Urban households seethe as the kitchen stays expensive.",effects:{FI:5,RE:3,EN:-16,FA:-6}}},{id:"finance-0161",location:"finance",arc:"finance-t1-a7",stage:0,speaker:"Sovereign Ratings Analyst",portrait:"ambassador",tags:["rating","markets","confidence"],prompt:"A later term, and the quarrel has hardened into a test. A judge who grades your country's money is going to give you a bad grade. He hints he will give you a good grade if you secretly give him gifts.",left:{id:"a",label:"Secretly give him gifts to get a good grade.",tooltip:"A friendly rating is cheaper than a downgrade.",reveal:"The downgrade is shelved this cycle. The fix is fragile and faintly corrupt; the next analyst may not be so amenable.",effects:{FI:5,GL:-10,EN:-6}},right:{id:"b",label:"Show him the honest truth and accept a bad grade.",tooltip:"I will not bribe my way out of arithmetic.",reveal:"You bare the fiscal accounts honestly. The downgrade may come, but investors who reward candour begin, cautiously, to return.",effects:{FI:-10,GL:6,MI:-3}}},{id:"finance-0162",location:"finance",arc:"finance-t1-a8",stage:0,speaker:"NBR Chairman",portrait:"official",tags:["tax","nbr","informal"],prompt:"The country has changed, but this fault line has not — only worsened. Almost nobody pays taxes. Your helper wants to force shopkeepers to pay, but those shopkeepers give you money for your campaigns.",left:{id:"a",label:"Force the shopkeepers to pay taxes.",tooltip:"A state cannot run on 2% of its people.",reveal:"Revenue creeps up and the IMF nods — while market associations declare a shutter-down strike against you.",effects:{FI:10,GL:5,EN:-13,FA:-6}},right:{id:"b",label:"Be nice to them and don't force them.",tooltip:"Do not squeeze the people who keep me standing.",reveal:"The committees stay loyal and the books stay thin. The tax-to-GDP ratio remains among the lowest on earth.",effects:{FA:6,FI:-13,GL:-10}}},{id:"finance-0163",location:"finance",arc:"finance-t1-a9",stage:0,speaker:"Budget Adviser",portrait:"official",tags:["black-money","whitening","budget"],prompt:"It returns, as these things do, with the patience gone. People are hiding stolen money. You can let them keep it if they pay a tiny tax, and you won't ask any questions. This rewards bad guys but gives you some money.",left:{id:"a",label:"Let them keep the stolen money and pay a tiny tax.",tooltip:"Better the money home than abroad.",reveal:"Hidden fortunes surface and the deficit eases. Honest taxpayers fume that crime pays a lower rate than they do.",effects:{FI:10,EN:-13,GL:-10}},right:{id:"b",label:"Say no to this bad rule.",tooltip:"I will not legislate a discount for thieves.",reveal:"You close the loophole on principle. The flagged billions stay offshore, and the budget must find them elsewhere.",effects:{GL:5,EN:5,FI:-16}}},{id:"finance-0164",location:"finance",arc:"finance-t1-a10",stage:0,speaker:"Stock Exchange Chair",portrait:"official",tags:["dse","market","retail"],prompt:"Years on, the matter is no longer private; the press is already circling. The stock market is crashing and normal people are losing their money. They are very angry. Your helper wants to create a fake rule to stop prices from dropping.",left:{id:"a",label:"Make the fake rule to stop prices from dropping.",tooltip:"Stop the bleeding on the screens.",reveal:"The index steadies on paper; trading dries up as no one will buy a price that cannot fall. Foreign funds flee the frozen market.",effects:{EN:5,FI:-10,GL:-13}},right:{id:"b",label:"Let the prices fall naturally and teach people how it works.",tooltip:"A propped market is a trap with a delay.",reveal:"The index overshoots down, then finds a real bottom. The pain is sharp and the recovery, when it comes, is trusted.",effects:{GL:5,FI:3,EN:-13}}},{id:"finance-0165",location:"finance",arc:"finance-t1-a10",stage:1,speaker:"Stock Exchange Chair",portrait:"official",tags:["dse","market","retail"],prompt:"The same knot, retied tighter, lands before you once more. The stock market is broken. A very rich man says he will fix it, but only if you give him a free bank and a phone company in return.",left:{id:"a",label:"Give him the bank and phone company so he fixes it.",tooltip:"A white knight asks his price.",reveal:"Shares rally on his buying spree. You have sold public assets to paper over a market panic, and he now owns a piece of the state.",effects:{FI:6,EN:3,GL:-13,FA:3}},right:{id:"b",label:"Say no and let the market fix itself slowly.",tooltip:"I will not ransom the bourse to one man.",reveal:"The market mends slowly without a saviour. The tycoon turns his media against you for the snub.",effects:{GL:5,FI:-10,MI:-6}}},{id:"finance-0166",location:"finance",arc:"finance-t1-a11",stage:0,speaker:"Debt Management Chief",portrait:"official",tags:["eurobond","debt","markets"],prompt:"Another monsoon, another return of an argument you cannot end. You need money fast. You can borrow a lot of money from the world, but you will have to pay back way too much extra money for ten years.",left:{id:"a",label:"Borrow the money right now.",tooltip:"Cash today is worth the coupon.",reveal:"Dollars arrive and the reserves breathe. The expensive interest bill compounds quietly for ten years.",effects:{FI:8,GL:3,EN:-6}},right:{id:"b",label:"Wait for a better time and stop buying things.",tooltip:"I will not borrow dear out of panic.",reveal:"You squeeze import demand to hold the line. It bites at home now, but spares the country a decade of costly debt.",effects:{FI:-6,EN:-10,GL:3}}},{id:"finance-0167",location:"finance",arc:"finance-t1-a12",stage:0,speaker:"Agriculture Secretary",portrait:"official",tags:["subsidy","fertiliser","farmers"],prompt:"Deep into the reign, the issue demands a final-sounding answer. Plant food for farmers is very expensive now. If you don't help pay for it, the crops will die. But helping will cost almost all your money.",left:{id:"a",label:"Pay for the plant food so crops can grow.",tooltip:"A failed harvest is a famine and a fall.",reveal:"The fields stay green and the farmers bless you. The deficit balloons and the IMF frowns at the next review.",effects:{EN:8,RE:3,FI:-16}},right:{id:"b",label:"Pay for just a little bit to save your money.",tooltip:"The books must balance somewhere.",reveal:"You please the creditors and thin the subsidy. Input costs hit the villages, and rural anger ferments.",effects:{FI:6,GL:3,EN:-16,FA:-6}}},{id:"finance-0168",location:"finance",arc:"finance-t1-a13",stage:0,speaker:"Pension Authority Head",portrait:"official",tags:["pension","welfare","funding"],prompt:"The reckoning you postponed has matured into a crisis. You promised to give old people money when they retire, and everyone loves it. But secretly, you don't have enough money to pay them later.",left:{id:"a",label:"Keep making the promise and worry about the money later.",tooltip:"The promise wins this decade's votes.",reveal:"Millions sign up to applause. You have built a magnificent liability your successors will curse.",effects:{EN:8,FA:3,FI:-13}},right:{id:"b",label:"Stop making promises until you actually have the money.",tooltip:"A pension that bounces is a betrayal.",reveal:"You cap the scheme to make it real. The rollout looks timid, but the cheque will clear when it comes due.",effects:{FI:5,GL:3,EN:-13}}},{id:"finance-0169",location:"finance",arc:"finance-t1-a14",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["banks","merger","weak-banks"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. Five banks are completely broken but pretending to be okay. You can force them to join good banks, but your rich friends will lose their jobs there.",left:{id:"a",label:"Force them to join the good banks.",tooltip:"Let the dead banks be buried.",reveal:"The rot is consolidated and capped. The ousted directors — several are donors — swear vengeance.",effects:{FI:8,GL:5,FA:-13}},right:{id:"b",label:"Let them pretend to be okay a little longer.",tooltip:"Not before the election, not these names.",reveal:"The zombies shuffle on, draining liquidity. The reckoning is postponed and made larger.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0170",location:"finance",arc:"finance-t1-a15",stage:0,speaker:"Mobile Finance Regulator",portrait:"official",tags:["mfs","bkash","fintech"],prompt:"The old fault line widens; this time there is no quiet option. Poor people use their phones to get their paychecks. The big phone company wants to charge them more money to get their cash.",left:{id:"a",label:"Stop the company from charging more money.",tooltip:"The garment girl should keep her wage.",reveal:"The fee cap eases millions of small lives. The operator threatens to cut rural agents in protest.",effects:{EN:8,FA:3,FI:-10}},right:{id:"b",label:"Let the company charge whatever they want.",tooltip:"A profitable rail keeps expanding.",reveal:"The network grows and invests; the daily skim off the poor grows with it.",effects:{FI:5,GL:3,EN:-13}}},{id:"finance-0171",location:"finance",arc:"finance-t1-a16",stage:0,speaker:"Customs Intelligence Chief",portrait:"shadow",tags:["misinvoicing","laundering","trade"],prompt:"Time has not healed it — the conflict comes back armed. People are sneaking billions of dollars out of the country using fake shopping bills. The worst bad guys are friends with your leaders.",left:{id:"a",label:"Stop the fake bills and catch everyone.",tooltip:"Plug the hole in the hull.",reveal:"Customs tightens and capital flight slows. Powerful importers, exposed, fund your rivals overnight.",effects:{FI:8,GL:5,FA:-13}},right:{id:"b",label:"Let them keep doing it quietly.",tooltip:"Some hulls are best left unexamined.",reveal:"The trade continues and the friends stay close. The reserves keep leaking out the side the cameras never see.",effects:{FA:5,FI:-10,GL:-10}}},{id:"finance-0172",location:"finance",arc:"finance-t1-a17",stage:0,speaker:"Fuel Pricing Board",portrait:"official",tags:["fuel","bpc","subsidy"],prompt:"Once again, and with the whole house holding its breath. The government sells gas for cars super cheap and loses money every day. You can make a rule so the price changes automatically, so you don't have to be the bad guy.",left:{id:"a",label:"Make the automatic price rule.",tooltip:"Take the politics out of the pump.",reveal:"The oil company stops bleeding; fuel jumps with every global tick, and transport strikes follow each rise.",effects:{FI:8,GL:5,EN:-16}},right:{id:"b",label:"Keep the price cheap and lose money.",tooltip:"Cheap diesel keeps the country moving.",reveal:"Buses and irrigation pumps run cheap. The subsidy drains the budget and distorts every market it touches.",effects:{EN:6,FI:-16,RE:-6}}},{id:"finance-0173",location:"finance",arc:"finance-t1-a18",stage:0,speaker:"Treasury Economist",portrait:"official",tags:["currency","dual-rate","taka"],prompt:"The matter resurfaces in a harder year, patience exhausted. The official price of your country's money is fake, so people use a secret black market. You can fix the official price, but it will make everything cost more for everyone at once.",left:{id:"a",label:"Fix the price and make things cost more.",tooltip:"One honest price beats two dishonest ones.",reveal:"The black market shrinks and exporters cheer; every imported good leaps in price the same morning.",effects:{FI:6,GL:5,EN:-16}},right:{id:"b",label:"Keep the fake price and try to control things.",tooltip:"A sudden devaluation would break the poor.",reveal:"You keep the headline rate and dole out scarce dollars by favour — a system that breeds its own corruption.",effects:{FI:-10,EN:3,GL:-10}}},{id:"finance-0174",location:"finance",arc:"finance-t1-a19",stage:0,speaker:"Foreign Loans Director",portrait:"official",tags:["china","debt","geopolitics"],prompt:"A later season of rule, the stakes now openly existential. China wants to give you cheap money to build a cool new road. Your enemies say it is a trap to make you owe China forever.",left:{id:"a",label:"Take China's money to build the road.",tooltip:"Cheap concrete is cheap concrete.",reveal:"The ring road rises on easy terms. The 'debt-trap' headlines and Western coolness are the price of the bargain.",effects:{FI:8,RE:5,GL:-13}},right:{id:"b",label:"Say no and ask other places for money instead.",tooltip:"I will not mortgage the capital to one capital.",reveal:"You pay more for diversified financing and Western goodwill. The project crawls; the books strain.",effects:{GL:5,FI:-13,RE:-6}}},{id:"finance-0175",location:"finance",arc:"finance-t1-a20",stage:0,speaker:"Pay Commission Head",portrait:"official",tags:["wages","civil-service","budget"],prompt:"It comes around again, and the margin for error is gone. Millions of government workers want a big pay raise. If you pay them, they will love you, but it will use up all the money meant for building schools and hospitals.",left:{id:"a",label:"Give them a giant pay raise.",tooltip:"A happy bureaucracy is a working one.",reveal:"The files move and the clerks smile. The recurring wage bill devours the money meant for bridges and clinics.",effects:{MI:5,FA:3,FI:-16,EN:-6}},right:{id:"b",label:"Give them a small raise you can actually afford.",tooltip:"The state cannot be a charity for itself.",reveal:"You protect the development budget. A sullen civil service slow-walks everything for a season.",effects:{FI:6,EN:3,MI:-10}}},{id:"finance-0176",location:"finance",arc:"finance-t1-a21",stage:0,speaker:"Export Promotion Chief",portrait:"official",tags:["rmg","incentive","exports"],prompt:"The same demand, but the reign is older and the knives sharper. You give extra money to people who sell clothes to other countries. The world bank says this is unfair and you must stop. The clothes makers will be very angry.",left:{id:"a",label:"Keep giving them the extra money.",tooltip:"Do not gift our orders to Hanoi.",reveal:"The looms keep their edge and the dollars keep coming. The IMF marks another unmet condition against you.",effects:{FI:5,GL:-10,EN:3,FA:3}},right:{id:"b",label:"Stop giving them the extra money like you promised.",tooltip:"A crutch carried too long becomes a cast.",reveal:"You please the lenders and prod exporters to compete on merit. Margins thin; some marginal factories fold.",effects:{GL:6,FI:-10,EN:-10}}},{id:"finance-0177",location:"finance",arc:"finance-t1-a22",stage:0,speaker:"Deficit Financing Officer",portrait:"official",tags:["printing","inflation","central-bank"],prompt:"Years deep, the unresolved returns to be resolved for good. You don't have enough money to pay your bills. A helper says you can just print fake money to pay them. It feels easy now, but will make everything super expensive later.",left:{id:"a",label:"Print fake money to pay the bills.",tooltip:"No one feels it this quarter.",reveal:"The gap is filled with fresh notes. Inflation stirs in the months ahead, a tax no one voted for.",effects:{FI:6,EN:-16,GL:-6}},right:{id:"b",label:"Say no and borrow real money honestly.",tooltip:"I will not pay tomorrow's prices for today's gap.",reveal:"You raise the money through bonds, dearer but cleaner. The deficit is honest and the taka steadier.",effects:{GL:5,FI:-6,EN:3}}},{id:"finance-0178",location:"finance",arc:"finance-t1-a23",stage:0,speaker:"e-Commerce Victims' Delegation",portrait:"people",tags:["scam","ecommerce","refunds"],prompt:"The conflict reignites, and the world is watching this time. A fake online store stole money from thousands of families. They are crying outside your office and want their money back.",left:{id:"a",label:"Use government money to pay them back.",tooltip:"The state failed to police it; the state pays.",reveal:"Families recover a fraction of their savings. The treasury absorbs a scam it did not commit, and others ask why they were not bailed out too.",effects:{EN:8,FA:3,FI:-16}},right:{id:"b",label:"Try to catch the bad guys, but don't give the families money.",tooltip:"I will jail the thieves, not reward the gamble.",reveal:"You freeze assets and prosecute. The recovered crumbs disappoint the crowd, but the precedent of no-bailout holds.",effects:{GL:3,FI:3,EN:-13}}},{id:"finance-0179",location:"finance",arc:"finance-t1-a24",stage:0,speaker:"Revenue Reform Adviser",portrait:"official",tags:["wealth-tax","surcharge","elite"],prompt:"A familiar crisis, escalated by everything you let slide. A helper says you should charge very rich people a big new tax. Normal people will cheer, but your rich friends will be furious.",left:{id:"a",label:"Charge the rich people the big new tax.",tooltip:"Those with the most can give the most.",reveal:"Public revenue and approval both rise. The moneyed class opens its war chest against you and its front pages turn cold.",effects:{FI:8,EN:6,FA:-13}},right:{id:"b",label:"Do not charge them, to keep your rich friends happy.",tooltip:"I cannot fight the people who fund me.",reveal:"The fortunes stay untaxed and the donors stay sweet. The street notes whose interests the budget serves.",effects:{FA:5,FI:-10,EN:-10}}},{id:"finance-0180",location:"finance",arc:"finance-t1-a25",stage:0,speaker:"Import Policy Officer",portrait:"official",tags:["lc","luxury","reserves"],prompt:"The fault line cracks wider; the decision can no longer wait. To save money, you can stop stores from buying fancy things like cars and makeup from other countries. Rich people will be mad when the shelves are empty.",left:{id:"a",label:"Stop the fancy things from coming in.",tooltip:"Dollars are for medicine, not Mercedes.",reveal:"Reserves stop bleeding on baubles. The affluent grumble about scarcity, and some smuggling reroutes the trade.",effects:{FI:6,GL:3,EN:-6,FA:-6}},right:{id:"b",label:"Keep the fancy things coming so people don't get mad.",tooltip:"Empty shelves photograph badly.",reveal:"The shops stay stocked and the rich content. The reserves keep draining on things the country need not buy.",effects:{FA:3,FI:-13,GL:-6}}},{id:"finance-0181",location:"finance",arc:"finance-t1-a26",stage:0,speaker:"Loan Classification Board",portrait:"official",tags:["rescheduling","defaulters","banks"],prompt:"Late in the reign, the old question demands a heavier answer. People who borrow money and never pay it back want you to change the rules so they look like good guys again. This makes the banks look good but rewards bad behavior.",left:{id:"a",label:"Change the rules to make them look like good guys.",tooltip:"A pretty balance sheet calms the market.",reveal:"Default ratios drop on paper overnight. The rot deepens in the dark, and the honest borrower wonders why he bothers.",effects:{FI:5,GL:-10,FA:3}},right:{id:"b",label:"Keep strict rules and show who the bad guys are.",tooltip:"Call a bad loan a bad loan.",reveal:"The true scale of default is finally visible. It looks ugly and frightens markets briefly — but the cleanup can begin.",effects:{GL:5,FI:-10,EN:3,FA:-6}}},{id:"finance-0182",location:"finance",arc:"finance-t1-a27",stage:0,speaker:"Privatisation Commissioner",portrait:"official",tags:["privatisation","jute","state-firms"],prompt:"It returns once more — and this round may be the one remembered. Old government factories lose money every single year, but they give jobs to many people. Your helper wants to close them.",left:{id:"a",label:"Close the old factories.",tooltip:"Nostalgia is not a business plan.",reveal:"The hemorrhage stops and buyers move in. Thousands of mill workers and their unions march on your gate.",effects:{FI:8,GL:3,EN:-16,MI:-6}},right:{id:"b",label:"Keep the factories open using government money.",tooltip:"These looms built the nation.",reveal:"The jobs and the heritage survive on subsidy. The losses recur, year after year, a line item that never dies.",effects:{EN:5,FA:3,FI:-16}}},{id:"finance-0183",location:"finance",arc:"finance-t1-a28",stage:0,speaker:"National Savings Director",portrait:"official",tags:["sanchayapatra","savings","rates"],prompt:"The reckoning circles back, grown teeth in the waiting. You give old people a really good deal when they save money with the government. But it costs the government too much.",left:{id:"a",label:"Stop giving them the really good deal.",tooltip:"The treasury cannot subsidise every saver.",reveal:"The interest bill eases. Pensioners and widows who counted on that return feel the floor drop, and say so loudly.",effects:{FI:8,GL:3,EN:-13}},right:{id:"b",label:"Keep giving them the really good deal.",tooltip:"The widow's certificate is sacred.",reveal:"You shield the small savers and eat the cost. The high-rollers exploit the same window, and the bill grows.",effects:{EN:6,FA:3,FI:-16}}},{id:"finance-0184",location:"finance",arc:"finance-t1-a29",stage:0,speaker:"Special Economic Zone Director",portrait:"official",tags:["sez","tax-holiday","investment"],prompt:"Another term, the same antagonist, the stakes raised again. A foreign company wants to build a big factory and create jobs. But they want you to promise they don't have to pay taxes for a very long time.",left:{id:"a",label:"Promise they don't have to pay taxes for a long time.",tooltip:"Jobs now, taxes eventually.",reveal:"The cranes arrive and employment rises. The treasury forgoes a fortune for fifteen years to win the ribbon-cutting.",effects:{EN:6,FI:-10,GL:5,RE:3}},right:{id:"b",label:"Tell them they only get a short time without paying taxes.",tooltip:"I will host investment, not subsidise it forever.",reveal:"You drive a harder bargain. The consortium hesitates and shrinks the project — but the state keeps a slice of the upside.",effects:{FI:5,GL:-6,EN:-6}}},{id:"finance-0185",location:"finance",arc:"finance-t1-a30",stage:0,speaker:"Anti-Tobacco Coalition",portrait:"people",tags:["tobacco","tax","health"],prompt:"The matter, long deferred, lands with the force of a verdict. Doctors want you to put a huge tax on cigarettes to stop people from getting sick. But cigarette makers pay you a lot of money and many farmers grow the plants.",left:{id:"a",label:"Put a huge tax on cigarettes.",tooltip:"A cigarette tax is a life saved and a taka earned.",reveal:"Revenue and public health both rise. The tobacco lobby and its farming districts turn sharply against you.",effects:{FI:6,EN:6,FA:-10}},right:{id:"b",label:"Keep the tax on cigarettes very low.",tooltip:"Do not gut a top taxpayer and a voting belt.",reveal:"The companies stay sweet and the leaf districts loyal. The wards fill with the slow harvest of that bargain.",effects:{FI:3,FA:3,EN:-16}}},{id:"finance-0186",location:"finance",arc:"finance-t1-a31",stage:0,speaker:"Land Registration Reformer",portrait:"official",tags:["real-estate","black-money","registration"],prompt:"Years on and unhealed, the conflict returns to claim its answer. People lie about how much their houses cost on paper so they don't have to pay taxes. If you use computers to fix this, powerful people will be caught.",left:{id:"a",label:"Use computers to fix it and catch them.",tooltip:"Drag the land market into the light.",reveal:"Registration revenue surges and a laundering channel narrows. Builders and land barons — and their political patrons — howl.",effects:{FI:8,EN:3,GL:3,FA:-13}},right:{id:"b",label:"Let them keep lying on paper.",tooltip:"Some ledgers are best left yellowed.",reveal:"The cosy undervaluation continues. Black money keeps flowing into bricks while the treasury watches it pass.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0187",location:"finance",arc:"finance-t1-a32",stage:0,speaker:"Hajj Management Director",portrait:"cleric",tags:["hajj","pilgrims","cost"],prompt:"The same fault line, the harder hour, the narrower path. Airplanes cost too much for poor families to take their big religious trip. You can use government money to pay for part of their tickets.",left:{id:"a",label:"Pay for part of their tickets.",tooltip:"Let the faithful afford the journey.",reveal:"Grateful pilgrims bless your name from Mecca. The treasury and the secular press both wince at the bill.",effects:{FA:5,EN:5,FI:-13,GL:-6}},right:{id:"b",label:"Don't pay, but make the travel agents charge less.",tooltip:"Faith should not be a fiscal line.",reveal:"You squeeze the middlemen instead of the budget. The devout are mildly disappointed; the books stay clean.",effects:{FI:5,GL:3,EN:-6,FA:-6}}},{id:"finance-0188",location:"finance",arc:"finance-t1-a33",stage:0,speaker:"Climate Fund Auditor",portrait:"official",tags:["climate","fund","graft"],prompt:"It comes back sharpened by every season you survived. The money meant to help save the earth from storms was stolen by your own team members. You can investigate and take it back, but it will embarrass your team.",left:{id:"a",label:"Investigate and take the stolen money back.",tooltip:"Stolen flood money is blood money.",reveal:"Recovered crores return to the embankments. The implicated party officials become loud, wounded enemies.",effects:{EN:6,GL:6,FI:3,FA:-13}},right:{id:"b",label:"Hide the secret to protect your team.",tooltip:"Do not hand the donors a scandal.",reveal:"The leak stays hidden and the party intact. The embankments stay thin, and the next flood collects the difference.",effects:{FA:5,EN:-16,GL:-10}}},{id:"finance-0189",location:"finance",arc:"finance-t1-a34",stage:0,speaker:"Sovereign Fund Proponent",portrait:"official",tags:["reserves","sovereign-fund","investment"],prompt:"A later year of power, the old crisis now a true test of it. A helper wants to take your emergency money from the bank and spend it to build big things at home. It is brave, but if an emergency happens, you will have no money.",left:{id:"a",label:"Take the emergency money and build big things.",tooltip:"Idle reserves should build the country.",reveal:"Grand projects get cheap money and momentum. The reserve buffer thins, and a future shock will find less cushion.",effects:{RE:5,EN:5,FI:-10,GL:-6}},right:{id:"b",label:"Keep the emergency money safe in the bank.",tooltip:"Reserves are the wall against the storm.",reveal:"You guard the buffer and pass on the projects. Critics call it timid; the next currency scare proves it wise.",effects:{FI:6,GL:3,EN:-6}}},{id:"finance-0190",location:"finance",arc:"finance-t1-a35",stage:0,speaker:"VAT Online Director",portrait:"official",tags:["vat","digitisation","compliance"],prompt:"The unresolved returns, and this time it will not be deferred. Shopkeepers are putting tax money in their own pockets. You can force them to use smart computers to stop this, but millions of them will be angry and vote against you.",left:{id:"a",label:"Force them to use the smart computers.",tooltip:"An honest till funds an honest state.",reveal:"Consumption-tax revenue climbs steadily. A million shopkeepers grumble about the machine watching every sale.",effects:{FI:8,GL:3,EN:-6,FA:-6}},right:{id:"b",label:"Let them keep collecting taxes the old way.",tooltip:"Do not put a meter on every shop counter.",reveal:"The shopkeepers stay content and the leakage continues. The treasury collects a fraction of what it is owed.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0191",location:"finance",arc:"finance-t1-a36",stage:0,speaker:"Garment Buyers' Auditor",portrait:"ambassador",tags:["rmg","compliance","wages"],prompt:"A term later, the same fault line tears open again. Buyers from other countries want proof that your factories pay workers fairly. Being fair costs owners money. Faking the proof risks losing the buyers forever.",left:{id:"a",label:"Force the owners to be completely fair.",tooltip:"The market is worth more than the margin.",reveal:"Buyers are reassured and orders hold; the workers are paid in full. Factory owners — your donors — bristle at the cost.",effects:{GL:6,EN:6,FI:-10,FA:-6}},right:{id:"b",label:"Help the owners fake the proof.",tooltip:"Protect the owners who keep the lines running.",reveal:"The audit is smoothed over and margins protected. One leaked payslip could bring the whole edifice down.",effects:{FI:5,FA:3,GL:-13,EN:-10}}},{id:"finance-0192",location:"finance",arc:"finance-t1-a37",stage:0,speaker:"Revenue Board Chairman",portrait:"fixer",tags:["black-money","tax","whitening"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. Bad guys have hidden, stolen money. You can pass a rule that lets them keep it safely if they pay a tiny tax. Honest people think this is very unfair.",left:{id:"a",label:"Let them keep it safely for a tiny tax.",tooltip:"Better the black money working here than hiding abroad.",reveal:"The clause passes and laundered crores flood into property and banks. The reserves and the books improve, and every honest taxpayer learns that cheating, in the end, is rewarded.",effects:{FI:8,FA:2,EN:-13,GL:-10}},right:{id:"b",label:"Say no to this unfair rule.",tooltip:"A state that pardons theft for a fee invites more theft.",reveal:"You kill the whitening clause. The hidden money stays hidden or flees abroad, and the budget is thinner for it, but the tax system keeps a shred of fairness and credibility.",effects:{GL:5,EN:5,FI:-13}}},{id:"finance-0193",location:"finance",arc:"finance-t1-a38",stage:0,speaker:"Securities Regulator",portrait:"official",tags:["stock-market","crash","retail"],prompt:"A new season of power, an old problem with sharper teeth. Bad guys tricked normal people into losing all their money in the stock market. You can spend government money to pay the normal people back and punish the bad guys.",left:{id:"a",label:"Pay the normal people back and punish the bad guys.",tooltip:"A market that eats its small fish breeds no trust.",reveal:"You cushion the retail losses and go after the big manipulators. The bailout is costly and the syndicates fight back, but the small investor sees the state will not abandon them to the wolves.",effects:{EN:6,GL:3,FI:-13,FA:-6}},right:{id:"b",label:"Let the normal people lose their money.",tooltip:"A gambler who loses cannot bill the state.",reveal:"You let the crash run its course. The treasury is spared, the manipulators keep their gains, and a generation of small savers swears off the market that fleeced them.",effects:{FI:3,EN:-13,GL:-3}}},{id:"finance-0194",location:"finance",arc:"finance-t1-a39",stage:0,speaker:"Privatisation Commission Chief",portrait:"official",tags:["soe","privatisation","jobs"],prompt:"The crisis returns, and this time the cabinet is watching. The government owns old factories and airplanes that lose money every day. You can shut them down, or keep them running just so workers keep their jobs.",left:{id:"a",label:"Shut them down and stop losing money.",tooltip:"A factory that only makes losses makes nothing.",reveal:"You sell or close the bleeding enterprises and stem the subsidy. The freed budget is real, but tens of thousands of workers lose their jobs and turn their fury on you.",effects:{FI:6,GL:3,EN:-13}},right:{id:"b",label:"Keep them running to save the jobs.",tooltip:"A wage lost is a household sunk.",reveal:"You keep the loss-makers running for the workers and the patronage. The jobs and the votes are safe, and the subsidy keeps draining money that schools and clinics will never see.",effects:{EN:5,FA:3,FI:-13}}},{id:"finance-0195",location:"finance",arc:"finance-t1-a40",stage:0,speaker:"Pension Authority Director",portrait:"people",tags:["pension","welfare","future"],prompt:"Once more the issue lands on your desk, the stakes higher than before. You want to help poor workers save money for when they get old. You can use government money to help them, or force them to use only their own money.",left:{id:"a",label:"Use government money to help them save.",tooltip:"An old age without dignity is a society's shame.",reveal:"You build a pension reaching even the poorest with heavy state top-ups. The fiscal burden is enormous and permanent, but a generation of the elderly is lifted out of destitution.",effects:{EN:10,GL:3,FI:-16}},right:{id:"b",label:"Make them use only their own money.",tooltip:"A promise I cannot fund is a betrayal deferred.",reveal:"You launch a modest, mainly contribution-based scheme. It is fiscally sound but reaches the poorest thinly, and the informal workers who most need it can least afford to join.",effects:{FI:3,EN:3,GL:2}}},{id:"finance-0196",location:"finance",arc:"finance-t1-a41",stage:0,speaker:"IMF Programme Negotiator",portrait:"ambassador",tags:["imf","subsidy","austerity"],prompt:"Another year survived, and the reckoning circles back. A big bank will give you important money, but only if you stop helping people pay for gas and electricity. The people will be very angry if prices go up.",left:{id:"a",label:"Stop helping people pay so you can get the bank's money.",tooltip:"The fund's money keeps the lights on at all.",reveal:"You slash the subsidies and unlock the tranche. The reserves and the lenders are reassured, and the price of transport, food, and power detonates in every household.",effects:{FI:6,GL:5,EN:-18}},right:{id:"b",label:"Keep helping people pay and lose the bank's money.",tooltip:"I will not buy a loan with my people's hunger.",reveal:"You shield the subsidies and the IMF talks stall. The street is spared the shock, but the reserves keep bleeding and the lifeline you turned down may not be offered twice.",effects:{EN:6,FI:-13,GL:-6}}},{id:"finance-0197",location:"finance",arc:"finance-t1-a42",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["currency","float","devaluation"],prompt:"The ground has shifted; the same demand arrives with new menace. You are burning up all your savings to pretend your country's money is worth a lot. The bank boss says to stop and tell the truth, even if things get expensive.",left:{id:"a",label:"Tell the truth and let things get expensive.",tooltip:"A currency defended past its worth bankrupts the defender.",reveal:"You float the taka and the black-market premium vanishes. Import prices and inflation jump painfully, but the ruinous reserve drain stops and the market finds honest footing.",effects:{FI:5,GL:3,EN:-13}},right:{id:"b",label:"Burn up more savings to keep pretending.",tooltip:"A falling taka is a falling government.",reveal:"You keep defending the rate. The official price holds and the public is spared the shock for now, but the reserves drain toward empty and the black market thrives in the gap.",effects:{EN:3,FI:-13,GL:-3}}},{id:"finance-0198",location:"finance",arc:"finance-t1-a43",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["banks","merger","npl"],prompt:"History rhymes: the conflict reopens deeper than last time. Some banks are broken because bad bosses stole from them. You can force good banks to mix with the bad ones to save people's money, but it rewards the bad bosses.",left:{id:"a",label:"Mix the banks to save the people's money.",tooltip:"A bank run is a fire that spreads.",reveal:"You merge the zombie banks into stronger ones and depositors are saved. The looters who gutted them walk away clean, and the healthy banks inherit a mountain of toxic debt.",effects:{FI:3,EN:2,GL:-3,FA:-3}},right:{id:"b",label:"Let the bad banks fail so they learn a lesson.",tooltip:"A bank that is never allowed to die never learns to live.",reveal:"You let one rotten bank collapse. Depositors panic and the system shudders, but for once the looters lose their bank, and every other board suddenly takes risk seriously.",effects:{GL:3,FI:-10,EN:-6}}},{id:"finance-0199",location:"finance",arc:"finance-t1-a44",stage:0,speaker:"Banking Division Secretary",portrait:"fixer",tags:["loans","defaulters","favours"],prompt:"Mid-reign, the old wound is torn afresh. Rich people who never pay back their bank loans want you to give them a super easy deal again. It makes the banks look okay on paper, but lets the bad guys win.",left:{id:"a",label:"Give them the super easy deal.",tooltip:"A defaulter's empire employs thousands; do not topple it.",reveal:"You let the big defaulters reschedule on featherbed terms. The banks' books look healthier on paper, the connected tycoons stay afloat, and the rot in the banking system deepens out of sight.",effects:{FI:3,FA:3,EN:-10,GL:-10}},right:{id:"b",label:"Force them to pay back what they owe.",tooltip:"A willful defaulter is a thief with a balance sheet.",reveal:"You refuse the rescheduling and move to recover or seize. The tycoons rage and call in their political chips, but billions in dead loans start, painfully, to come back.",effects:{GL:5,FI:3,EN:3,FA:-10}}},{id:"finance-0200",location:"finance",arc:"finance-t1-a45",stage:0,speaker:"Debt Management Director",portrait:"ambassador",tags:["eurobond","debt","markets"],prompt:"The pressure you deferred has come due, larger now. You can borrow a huge amount of money from the world right now. But you will owe them so much extra money that it will hurt your country for a long time.",left:{id:"a",label:"Borrow the huge amount of money.",tooltip:"Market money comes with no master attached.",reveal:"The bond raises the cash quickly and string-free. The high coupon settles onto future budgets, and your fortunes are now hostage to the moods of distant bond markets.",effects:{FI:5,GL:2,RE:2}},right:{id:"b",label:"Say no to borrowing the money.",tooltip:"A bond at usurer's rates is a trap with a ribbon.",reveal:"You skip the expensive bond and live within tighter means. The development plans shrink and the cash crunch bites, but you do not mortgage the next decade to the markets.",effects:{GL:2,FI:-6,EN:-3}}},{id:"finance-0201",location:"finance",arc:"finance-t1-a46",stage:0,speaker:"Trading Corporation Chief",portrait:"shadow",tags:["inflation","syndicate","food"],prompt:"A later term, and the quarrel has hardened into a test. Bad sellers are hiding food to make it cost more. Some of them give you money.",left:{id:"a",label:"Stop the bad sellers and bring in cheap food.",tooltip:"A cartel that taxes every plate must be smashed.",reveal:"You raid the hoarders and flood the market with state imports. Prices ease and the public exhales, but the cartel bosses — your financiers — turn on you with their wallets shut.",effects:{EN:8,FI:-6,FA:-10}},right:{id:"b",label:"Protect the bad sellers and let food stay expensive.",tooltip:"The men who fund the party are not lightly raided.",reveal:"You spare the syndicate and the hoarding continues. The financiers stay loyal and generous, and the cost of a meal climbs out of reach for the families who can least bear it.",effects:{FI:3,FA:5,EN:-16}}},{id:"finance-0202",location:"finance",arc:"finance-t1-a47",stage:0,speaker:"Customs Commissioner",portrait:"fixer",tags:["customs","ports","corruption"],prompt:"The country has changed, but this fault line has not — only worsened. Guards at the boat docks are taking secret money instead of charging the right taxes.",left:{id:"a",label:"Use computers to stop them from stealing.",tooltip:"A bribed customs house robs the whole nation.",reveal:"You digitise clearance and audit the postings hard. Duty revenue jumps and the rackets wither, and the officers who paid fortunes for the lucrative postings turn bitterly against you.",effects:{FI:6,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Let the guards keep taking secret money.",tooltip:"The men in the customs houses have powerful patrons.",reveal:"You leave the ports' shadow economy intact. The patronage flows smoothly and the postings stay golden, and the treasury keeps collecting a fraction of the duty it is owed.",effects:{FI:-6,FA:3,EN:-6,GL:-3}}},{id:"finance-0203",location:"finance",arc:"finance-t1-a48",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["tax","elite","evasion"],prompt:"It returns, as these things do, with the patience gone. Rich people are not paying their taxes, so normal workers have to pay more.",left:{id:"a",label:"Force the rich people to pay their taxes.",tooltip:"A state funded by clerks while tycoons skate is doomed.",reveal:"You target the rich evaders, audits reaching into donor and dynastic ledgers. The revenue base broadens and the public cheers, but the powerful you have dunned plot their revenge.",effects:{FI:6,EN:6,GL:3,FA:-13}},right:{id:"b",label:"Keep making the normal workers pay.",tooltip:"The easy taxpayer is the one who cannot run.",reveal:"You leave the rich alone and lean harder on the salaried. The revenue is reliable and the donors content, and the shrinking middle class learns exactly whose shoulders the state rests on.",effects:{FI:3,FA:3,EN:-13}}},{id:"finance-0204",location:"finance",arc:"finance-t1-a49",stage:0,speaker:"Digital Finance Adviser",portrait:"official",tags:["mobile-money","remittances","inclusion"],prompt:"Years on, the matter is no longer private; the press is already circling. Paying with phones can help people send money safely, but regular banks don't like it.",left:{id:"a",label:"Help people use their phones to send money safely.",tooltip:"A phone in every hand is a bank in every village.",reveal:"You push incentives for mobile remittances and the formal channels swell. The banks and the hundi networks both lose ground and grumble, but billions enter the legal economy and the unbanked gain access.",effects:{FI:6,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Help the regular banks instead.",tooltip:"The banks are the system; do not undercut them.",reveal:"You shield the banks and leave the mobile push half-hearted. The hundi networks keep their grip on remittances, the reserves miss the inflows, and the village stays unbanked.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0205",location:"finance",arc:"finance-t1-a50",stage:0,speaker:"Pay Commission Chair",portrait:"official",tags:["salaries","bureaucracy","budget"],prompt:"The same knot, retied tighter, lands before you once more. Government workers want a giant raise. If you pay them, they will be happy, but you won't have money for other things.",left:{id:"a",label:"Give them the giant raise.",tooltip:"A well-paid official is a loyal, honest one.",reveal:"You award the generous hike and the bureaucracy is delighted and bound to you. Petty bribery eases, but the wage bill swells permanently, crowding out the development budget for years.",effects:{MI:2,FA:3,FI:-13,EN:-3}},right:{id:"b",label:"Give them a small raise you can afford.",tooltip:"A salary I cannot sustain is a strike deferred.",reveal:"You give a restrained increase the budget can bear. The civil servants grumble at the modesty and some petty corruption persists, but the fiscal hole stays survivable.",effects:{FI:3,EN:2,FA:-3}}},{id:"finance-0206",location:"finance",arc:"finance-t1-a51",stage:0,speaker:"Financial Intelligence Chief",portrait:"shadow",tags:["laundering","over-invoicing","capital-flight"],prompt:"Another monsoon, another return of an argument you cannot end. Your rich friends are secretly sending their money to other countries.",left:{id:"a",label:"Build a strong team to stop them.",tooltip:"A river of stolen money flowing abroad bleeds us white.",reveal:"You stand up real trade-laundering enforcement and the outflows slow. The reserves steady and the world's watchdogs approve, but your backers' escape route is now monitored, and they are furious.",effects:{FI:5,GL:5,EN:3,FA:-10}},right:{id:"b",label:"Let your friends keep sending their money away.",tooltip:"The men who move that money also fund the party.",reveal:"You leave the over-invoicing pipeline flowing. Your backers keep stashing wealth abroad and stay loyal, and the reserves keep haemorrhaging out through a hole you chose not to plug.",effects:{FA:5,FI:-10,GL:-6}}},{id:"finance-0207",location:"finance",arc:"finance-t1-a52",stage:0,speaker:"Investment Authority Chief",portrait:"ambassador",tags:["sez","fdi","incentives"],prompt:"Deep into the reign, the issue demands a final-sounding answer. Foreign companies want free land and no taxes for a long time to build factories here.",left:{id:"a",label:"Give them free things so they build factories.",tooltip:"An empty zone earns nothing; fill it at any price.",reveal:"You hand out the tax holidays and the factories come. Jobs and FDI flow in for the headlines, and the revenue board quietly notes the decade of tax you have signed away.",effects:{FI:3,EN:3,GL:3,RE:-3}},right:{id:"b",label:"Give them fewer free things.",tooltip:"A zone bought with the whole future is a bad bargain.",reveal:"You offer modest, sunset-clause incentives. Some footloose investors look elsewhere and the zones fill slower, but the deals that land actually pay tax within the decade.",effects:{FI:3,GL:-3,EN:2}}},{id:"finance-0208",location:"finance",arc:"finance-t1-a53",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["deficit","printing","inflation"],prompt:"The reckoning you postponed has matured into a crisis. You have no money to pay bills. You can print fake money now, but it will ruin everything later.",left:{id:"a",label:"Print the fake money to pay bills.",tooltip:"A bill paid today is a bill paid.",reveal:"You lean on the printing press and the bills are met. The relief is immediate and the cost deferred, as the new money seeps into prices and the inflation you deferred compounds.",effects:{FI:5,EN:-13,GL:-6}},right:{id:"b",label:"Say no to printing fake money.",tooltip:"A printing press is a slow-motion default.",reveal:"You hold the line against monetisation and cut or borrow instead. The squeeze is painful and immediate, but you spare the country the inflationary spiral that has ruined so many.",effects:{GL:3,FI:-6,EN:-3}}},{id:"finance-0209",location:"finance",arc:"finance-t1-a54",stage:0,speaker:"Agricultural Bank Chairman",portrait:"people",tags:["sme","farmers","credit"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. Poor farmers can't borrow money because banks only lend to rich people.",left:{id:"a",label:"Force banks to lend money to poor farmers.",tooltip:"A loan to a farmer grows more than a loan to a tycoon.",reveal:"You push cheap credit out to farmers and micro-enterprises. Default risk and cost rise, but the rural economy stirs to life and millions feel the state's hand for the first time.",effects:{EN:8,FI:-10}},right:{id:"b",label:"Let banks keep lending only to the rich.",tooltip:"A bank that lends to the poor is a bank that fails.",reveal:"You keep credit flowing to the safe and the big. The banks' books stay clean, and the small farmer and the micro-trader keep borrowing from the moneylender at ruinous rates.",effects:{FI:3,EN:-10,FA:2}}},{id:"finance-0210",location:"finance",arc:"finance-t1-a55",stage:0,speaker:"Treasury Operations Chief",portrait:"official",tags:["liquidity","festival","wages"],prompt:"The old fault line widens; this time there is no quiet option. A big holiday is coming and factory owners can't pay their workers. The workers will be very mad.",left:{id:"a",label:"Give the owners government money to pay the workers.",tooltip:"A million unpaid workers at Eid is a powder keg.",reveal:"You bail out the payrolls and the workers go home paid for the holiday. The owners are rescued from their own mismanagement again, learning once more that the state will always catch them.",effects:{EN:6,FI:-10,FA:2}},right:{id:"b",label:"Make the owners fix their own problem.",tooltip:"I will not bankroll the bonuses of profitable men.",reveal:"You refuse the bailout and tell the owners to pay their own way. Some factories erupt in unrest over delayed wages, but the owners learn the treasury is not their overdraft.",effects:{FI:3,EN:-10,FA:-3}}},{id:"finance-0211",location:"finance",arc:"finance-t1-a56",stage:0,speaker:"Export Promotion Director",portrait:"official",tags:["exports","diversification","garments"],prompt:"Time has not healed it — the conflict comes back armed. Your country only sells clothes to the world. You can try to sell new things like medicine and computers, but it is slow and hard.",left:{id:"a",label:"Try to sell new things like medicine and computers.",tooltip:"An economy on one leg falls when that leg is kicked.",reveal:"You back the emerging sectors with incentives and infrastructure. The payoff is slow and some bets will fail, but the export base begins, finally, to broaden beyond the loom.",effects:{FI:2,GL:3,EN:3,RE:2}},right:{id:"b",label:"Keep focusing only on selling clothes.",tooltip:"Why bet on maybes when the looms pay now?",reveal:"You concentrate support on the proven garment sector. Exports stay strong and the cash flows, and the economy's single point of failure grows ever more dangerous and ever more entrenched.",effects:{FI:5,EN:-3,GL:-3}}},{id:"finance-0212",location:"finance",arc:"finance-t1-a57",stage:0,speaker:"Digital Economy Adviser",portrait:"people",tags:["it","freelancers","youth"],prompt:"Once again, and with the whole house holding its breath. Young people making money online are having a hard time getting paid because of bad rules.",left:{id:"a",label:"Change the rules to help them get paid easily.",tooltip:"A laptop in a village earns dollars from the world.",reveal:"You smooth payments, ease taxes, and back training for the digital workforce. A new stream of foreign currency grows, and a generation of the young find work without leaving home.",effects:{FI:5,EN:5,GL:2}},right:{id:"b",label:"Do not change the rules.",tooltip:"A scattered cottage industry is not a strategy.",reveal:"You keep the clumsy status quo. The freelancers route their earnings through grey channels or move abroad, and a homegrown export pillar withers before it can take root.",effects:{FI:-3,EN:-6,GL:-3}}},{id:"finance-0213",location:"finance",arc:"finance-t1-a58",stage:0,speaker:"Financial Intelligence Chief",portrait:"ambassador",tags:["capital-flight","second-homes","elite"],prompt:"The matter resurfaces in a harder year, patience exhausted. News reporters found out your leaders secretly own big houses in other countries using stolen money.",left:{id:"a",label:"Help catch them and take the money back.",tooltip:"Stolen money parked abroad still belongs to the people.",reveal:"You take up the foreign cooperation and chase the laundered fortunes home. Some assets are frozen and the public is electrified, but the exposed elite — your own ranks — declare quiet war.",effects:{FI:5,GL:5,EN:6,FA:-16}},right:{id:"b",label:"Ignore it and let them keep the houses.",tooltip:"Half my cabinet owns those flats.",reveal:"You decline to pursue the foreign holdings. Your elite's offshore nest eggs stay safe and they stay loyal, and the message that the powerful loot with impunity is stamped a little deeper.",effects:{FA:6,FI:-6,EN:-13,GL:-10}}},{id:"finance-0214",location:"finance",arc:"finance-t1-a59",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["crypto","regulation","capital-controls"],prompt:"A later season of rule, the stakes now openly existential. Young people are using digital internet money. It might be dangerous, but everyone is doing it.",left:{id:"a",label:"Ban all internet money.",tooltip:"A currency I cannot see is a hole in the dam.",reveal:"You ban crypto and threaten the traders. The official capital controls hold a little better, but the trade simply goes underground, and the tech-savvy young add another grievance to the pile.",effects:{FI:2,MI:2,GL:-3,EN:-6}},right:{id:"b",label:"Make rules for it and tax it.",tooltip:"Better to tax the tide than to forbid it.",reveal:"You bring crypto into a regulated, taxed framework. The capital-flight risk is real and the controls leakier, but you tax the activity, attract some fintech, and keep faith with the young.",effects:{FI:3,GL:2,EN:2}}},{id:"finance-0215",location:"finance",arc:"finance-t1-a60",stage:0,speaker:"PPP Authority Chief",portrait:"fixer",tags:["ppp","infrastructure","contracts"],prompt:"It comes around again, and the margin for error is gone. A company wants to build a big road for free, but they will charge everyone to drive on it for a very long time.",left:{id:"a",label:"Let them build it and charge people.",tooltip:"Roads now, paid for by tomorrow's tolls.",reveal:"The expressway gets built without upfront state money. The consortium pockets guaranteed returns for decades, and the 'minimum revenue' clause quietly hands the risk back to the public purse.",effects:{RE:3,FI:2,EN:2,GL:-3}},right:{id:"b",label:"Say no and build a fair road yourself.",tooltip:"A guarantee that the state eats all losses is a gift, not a partnership.",reveal:"You refuse the lopsided guarantee and renegotiate or build it yourself. The road is slower to come and the budget strained, but the public is not signed up to underwrite private profit.",effects:{FI:-6,EN:2,GL:2}}},{id:"finance-0216",location:"finance",arc:"finance-t1-a61",stage:0,speaker:"Planning Commission Member",portrait:"official",tags:["development-budget","spending","quality"],prompt:"The same demand, but the reign is older and the knives sharper. Every year, people rush to spend government money on badly made projects just before time runs out.",left:{id:"a",label:"Stop the rush and only build a few good things.",tooltip:"A road built twice is a road paid for thrice.",reveal:"You impose vetting and steady disbursement over the year-end splurge. The 'utilisation' numbers dip and the contractors grumble, but the projects that get built actually last.",effects:{FI:3,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Keep rushing to spend the money fast.",tooltip:"Unspent money is a bureaucrat's failure on paper.",reveal:"You let the final-quarter splurge continue. The disbursement targets are hit and everyone looks busy, and the padded, half-built projects crumble within a season or two.",effects:{FA:2,FI:-3,EN:-10}}},{id:"finance-0217",location:"finance",arc:"finance-t1-a62",stage:0,speaker:"Microfinance Regulator",portrait:"people",tags:["microfinance","debt","poverty"],prompt:"Years deep, the unresolved returns to be resolved for good. Poor people are borrowing too much money from too many places and are stuck. You can make rules to stop this, but the lenders will be mad.",left:{id:"a",label:"Make rules to protect the poor people.",tooltip:"A loan that traps is no longer a ladder.",reveal:"You cap effective rates and require a shared registry to stop multiple-lending. The big lenders fight the limits, but the rural poor stop drowning under stacked, overlapping loans.",effects:{EN:6,GL:2,FI:-3,FA:-3}},right:{id:"b",label:"Let the lenders do whatever they want.",tooltip:"Do not break the model the world copied.",reveal:"You leave the MFIs to their own devices. The model's reputation is preserved, and in the villages the quiet debt spirals tighten, household by over-borrowed household.",effects:{FI:2,FA:2,EN:-10}}},{id:"finance-0218",location:"finance",arc:"finance-t1-a63",stage:0,speaker:"Defence Finance Secretary",portrait:"general",tags:["defence","budget","spending"],prompt:"The conflict reignites, and the world is watching this time. The army wants a lot more money for cool new gear. If you give it to them, you can't build schools and hospitals.",left:{id:"a",label:"Give the army the money they want.",tooltip:"A contented barracks is a sleeping coup.",reveal:"You fund the military's wish-list and the brass is reassured of your favour. The barracks stay loyal, and the schools, clinics, and pensions you promised the public quietly shrink to pay for it.",effects:{MI:6,FA:2,FI:-10,EN:-10}},right:{id:"b",label:"Say no and spend money on the people instead.",tooltip:"A nation is defended by its people's wellbeing too.",reveal:"You hold the line on defence and protect social spending. The public services hold, but the generals feel slighted and watched, and a restive barracks is a risk you now carry.",effects:{EN:6,GL:2,MI:-10,FI:-3}}},{id:"finance-0219",location:"finance",arc:"finance-t1-a64",stage:0,speaker:"Auditor General",portrait:"official",tags:["reserves","transparency","audit"],prompt:"A familiar crisis, escalated by everything you let slide. You have been counting money you already promised to others, making you look richer than you are.",left:{id:"a",label:"Tell the truth about having less money.",tooltip:"A number built on a lie collapses worse later.",reveal:"You restate the reserves truthfully. The markets and the public are rattled by the lower figure, but the credibility you buy with honesty steadies the longer game and the IMF's trust.",effects:{GL:5,FI:-6,EN:-3}},right:{id:"b",label:"Keep counting the promised money to look rich.",tooltip:"A panic today is worse than a problem deferred.",reveal:"You keep the flattering figure on the books. The markets stay calm on a number that is not real, and the day the truth finally surfaces, the fall will be all the further.",effects:{FI:3,GL:-10,EN:-3}}},{id:"finance-0220",location:"finance",arc:"finance-t1-a65",stage:0,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["fraud","banks","scandal"],prompt:"The fault line cracks wider; the decision can no longer wait. A group of bad guys stole a giant amount of money from a government bank.",left:{id:"a",label:"Investigate them in front of everyone.",tooltip:"A fraud buried festers into a collapse.",reveal:"You open a transparent probe and the arrests climb toward the boardroom and beyond. Confidence wobbles at the spectacle, but the looters face justice and the system is forced to clean house.",effects:{GL:5,EN:5,FI:-6,FA:-10}},right:{id:"b",label:"Fix it quietly to protect the bank's secret.",tooltip:"A public scandal runs the depositors to the doors.",reveal:"You keep the fraud out of the headlines and settle it in the dark. Confidence holds on the surface, the connected escape, and the hole in the bank is quietly stuffed with public money.",effects:{FI:2,FA:3,EN:-10,GL:-10}}},{id:"finance-0221",location:"finance",arc:"finance-t1-a65",stage:1,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["fraud","banks","scandal"],prompt:"Late in the reign, the old question demands a heavier answer. A second bank was robbed the same way. The checker wants to make strong rules that would stop your friends from controlling the banks.",left:{id:"a",label:"Make the strong rules to stop the stealing.",tooltip:"A watchdog on the owner's leash guards nothing.",reveal:"You hand the banking regulator genuine independence and teeth. The politicians who packed the boards lose their grip and rage, but the banking sector gains its first real check in a generation.",effects:{GL:5,EN:5,FI:2,FA:-10}},right:{id:"b",label:"Keep your friends in control of the banks.",tooltip:"An independent watchdog bites the hand that feeds the party.",reveal:"You keep the regulator pliant. The board appointments stay a political spoil, the frauds keep their cover, and the banking system slides deeper toward a reckoning no one is watching for.",effects:{FA:5,FI:-6,EN:-10,GL:-6}}},{id:"finance-0222",location:"finance",arc:"finance-t1-a66",stage:0,speaker:"Remittance Policy Director",portrait:"people",tags:["remittances","incentive","reserves"],prompt:"It returns once more — and this round may be the one remembered. Workers far away are using secret ways to send money home. You can pay them a bonus to use the safe banks instead.",left:{id:"a",label:"Pay the bonus so they use safe banks.",tooltip:"A bonus on every dollar is a dollar in the vault.",reveal:"You pay the incentive and the official remittances surge as hundi loses its edge. The budget takes a real hit, but the reserves swell with the inflows you lured back into the light.",effects:{FI:5,EN:3,GL:2}},right:{id:"b",label:"Save your money and don't pay the bonus.",tooltip:"I will not pay people to do what they should anyway.",reveal:"You forgo the incentive. The budget is spared the cost, but the remittances keep leaking into hundi, the reserves miss the inflows, and the black-market dollar keeps its premium.",effects:{FI:-6,EN:-3,GL:-3}}},{id:"finance-0223",location:"finance",arc:"finance-t1-a66",stage:1,speaker:"Remittance Policy Director",portrait:"people",tags:["remittances","incentive","reserves"],prompt:"The reckoning circles back, grown teeth in the waiting. Factory owners are jealous of the bonus you gave the workers. They demand a bonus too, or they will hide their money.",left:{id:"a",label:"Give the factory owners the bonus too.",tooltip:"One dollar should be worth another, whoever earned it.",reveal:"You level the field and incentivise export proceeds as well. The reserves keep filling and the exporters are placated, but the budget's incentive bill balloons toward the unsustainable.",effects:{FI:2,GL:2,EN:-3}},right:{id:"b",label:"Say no, the bonus is only for workers.",tooltip:"I cannot subsidise every dollar in the economy.",reveal:"You refuse to widen the scheme. The budget is protected, but the garment lobby retaliates by parking earnings abroad, and some of the reserve gain leaks back out the other side.",effects:{FI:2,FA:-3,GL:-3}}},{id:"finance-0224",location:"finance",arc:"finance-t1-a67",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["imports","lc","reserves"],prompt:"Another term, the same antagonist, the stakes raised again. You can stop people from buying things from other countries to save money. But this will hurt factories that need parts.",left:{id:"a",label:"Stop people from buying things from other countries.",tooltip:"A dollar saved is a dollar that stays in the vault.",reveal:"You ration the LCs and the reserve bleed slows. Factories starved of imported inputs cut shifts, a black market in LC approvals blooms, and the well-connected jump the dollar queue.",effects:{FI:5,EN:-10,FA:2,GL:-3}},right:{id:"b",label:"Let them keep buying things and try to save money elsewhere.",tooltip:"A factory without inputs is a layoff with a delay.",reveal:"You keep the import channel open and seek savings elsewhere. Industry keeps running and no corrupt LC queue forms, but the reserves keep draining toward the danger line.",effects:{EN:3,FI:-10,GL:2}}},{id:"finance-0225",location:"finance",arc:"finance-t1-a67",stage:1,speaker:"Central Bank Governor",portrait:"official",tags:["imports","lc","reserves"],prompt:"The matter, long deferred, lands with the force of a verdict. Stopping buying things caused a big problem. Now there is not enough medicine or food.",left:{id:"a",label:"Keep the strict rules to save money.",tooltip:"The reserves must come first or nothing else holds.",reveal:"You maintain the clampdown. The reserves are defended, but the shortages deepen into closed factories and empty pharmacy shelves, and the hardship radiates through the economy.",effects:{FI:5,EN:-13,GL:-3}},right:{id:"b",label:"Change the rules to buy the most important things.",tooltip:"I will not ration medicine to save a statistic.",reveal:"You carve out medicines, food, and key inputs from the curbs. The reserve relief is smaller, but the worst shortages ease and the factories keep their workers on the line.",effects:{EN:5,FI:-6,GL:2}}},{id:"finance-0226",location:"finance",arc:"finance-t1-a68",stage:0,speaker:"Statistics Bureau Chief",portrait:"shadow",tags:["gdp","statistics","credibility"],prompt:"Years on and unhealed, the conflict returns to claim its answer. You can change the math to make your country look super rich and successful, even if it's a lie.",left:{id:"a",label:"Use the fake math to look great.",tooltip:"A nation grows as fast as its statistics say.",reveal:"You release the burnished numbers and top the league tables. The applause is real and the doubt is louder; when reality diverges from the data, the whole record becomes suspect.",effects:{FI:3,GL:2,EN:-10}},right:{id:"b",label:"Tell the honest truth, even if it looks less great.",tooltip:"A growth rate I have to defend is not growth.",reveal:"You release credible numbers, modest as they are. The headlines are duller and rivals crow, but the data the country plans by — and the lenders trust — stays sound.",effects:{GL:3,EN:2,FI:-6}}},{id:"finance-0227",location:"finance",arc:"finance-t1-a69",stage:0,speaker:"Wage Commission Chair",portrait:"people",tags:["wages","labour","cost"],prompt:"The same fault line, the harder hour, the narrower path. You can pass a rule that all workers must be paid a fair amount. The bosses say this will cost them too much money.",left:{id:"a",label:"Make a rule that pays workers fairly.",tooltip:"A wage too low to live on is a subsidy to the boss.",reveal:"You set a real floor under wages. Millions of the working poor breathe easier, the donors howl about competitiveness, and a few marginal employers do shed jobs.",effects:{EN:8,FI:-6,FA:-6}},right:{id:"b",label:"Let the bosses decide how much to pay.",tooltip:"A floor too high empties the factory.",reveal:"You leave wages to the market and the donors content. Competitiveness is protected and the jobs stay, and the working poor keep grinding at a wage that never quite covers the rent.",effects:{FI:3,FA:3,EN:-13}}},{id:"finance-0228",location:"finance",arc:"finance-t1-a70",stage:0,speaker:"Consumer Protection Director",portrait:"shadow",tags:["e-commerce","ponzi","fraud"],prompt:"It comes back sharpened by every season you survived. A famous online store is stealing everyone's money. You need to stop them quickly before they run away.",left:{id:"a",label:"Stop them and arrest them immediately.",tooltip:"A scam this size will not be allowed to vanish.",reveal:"You freeze the accounts and arrest the founders before they bolt. Some customer money is clawed back, and the swift action signals that the digital wild-west has a sheriff at last.",effects:{EN:6,GL:3,FI:2}},right:{id:"b",label:"Wait and study the problem slowly.",tooltip:"A hasty freeze could spook the whole sector.",reveal:"You proceed cautiously and the founders launder and flee. The customers' money evaporates, the scandal metastasises, and trust in the entire e-commerce sector collapses.",effects:{FI:-6,EN:-13,GL:-6}}},{id:"finance-0229",location:"finance",arc:"finance-t1-a71",stage:0,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["nbfi","embezzlement","regulator"],prompt:"A later year of power, the old crisis now a true test of it. One bad guy stole all the money from a money-lending business and ran away.",left:{id:"a",label:"Chase him down and punish the people who helped him.",tooltip:"A theft this brazen demands a reckoning.",reveal:"You launch an international pursuit and turn the lens on the regulators who slept. The fugitive is hunted and some enablers fall, and the financial watchdogs are forced, painfully, to wake.",effects:{GL:5,EN:5,FA:-10,FI:2}},right:{id:"b",label:"Forget about it and let him get away.",tooltip:"A public hunt only advertises how deep the rot runs.",reveal:"You let the loss be quietly absorbed. The fugitive keeps his fortune abroad, the sleeping regulators keep their jobs, and the next operator notes how softly a billion can be stolen here.",effects:{FA:3,FI:-6,EN:-10,GL:-6}}},{id:"finance-0230",location:"finance",arc:"finance-t1-a72",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["autonomy","monetary","independence"],prompt:"The unresolved returns, and this time it will not be deferred. Your helpers want the bank boss to break the rules to make you look good for the election. The bank boss says this is dangerous.",left:{id:"a",label:"Force the bank boss to break the rules.",tooltip:"A bank that defies the government is a rival.",reveal:"You subordinate the central bank to the ministry's will. The election-year sugar flows, and the institution's hard-won credibility — the thing that anchors inflation and the currency — bleeds away.",effects:{FI:3,MI:2,GL:-10,EN:-6}},right:{id:"b",label:"Let the bank boss do his job the right way.",tooltip:"A tame central bank is a slow-motion crisis.",reveal:"You shield the governor's autonomy. The ministry fumes at being denied its election-year levers, but the bank keeps the credibility that holds the currency and the lenders' trust.",effects:{GL:5,FI:-3,EN:2}}},{id:"finance-0231",location:"finance",arc:"finance-t1-a73",stage:0,speaker:"Food Directorate Chief",portrait:"people",tags:["procurement","farmers","rice"],prompt:"A term later, the same fault line tears open again. The farmers picked their rice. You can pay them a high price to help them, or a low price to save government money.",left:{id:"a",label:"Pay a high price to help the farmers.",tooltip:"A farmer paid fairly plants again.",reveal:"You buy at a generous price and fill the granary. The growers prosper and the food reserve swells, at a real cost to the budget that the millers' cartel would have pocketed anyway.",effects:{EN:6,FI:-10}},right:{id:"b",label:"Pay a low price to save money.",tooltip:"The granary cannot bankrupt the treasury.",reveal:"You buy cheap and save the budget. The granary fills at less cost, but the farmer, undercut, sells to the millers' cartel at a loss and curses the season.",effects:{FI:5,EN:-10}}},{id:"finance-0232",location:"finance",arc:"finance-t1-a74",stage:0,speaker:"Food Directorate Chief",portrait:"relief",tags:["oms","inflation","poor"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. Food is too expensive and poor people are starving. You can open the emergency food stores now, or save them just in case things get even worse.",left:{id:"a",label:"Open the emergency food stores now.",tooltip:"A hungry city is a city on the edge.",reveal:"You flood the cities with cheap state rice and the queues ease. The reserve drains and skimming creeps in at the trucks, but the poor eat and the streets stay calm.",effects:{EN:6,FI:-6}},right:{id:"b",label:"Save the food for a worse day.",tooltip:"A granary emptied early starves a later crisis.",reveal:"You ration the reserve against future shortage. The budget and the buffer are protected, but the urban poor go hungry now, and the resentment simmers in the bread queues.",effects:{FI:3,EN:-13}}},{id:"finance-0233",location:"finance",arc:"finance-t1-a75",stage:0,speaker:"Social Protection Director",portrait:"people",tags:["cash-transfer","education","poverty"],prompt:"A new season of power, an old problem with sharper teeth. You can pay poor mothers money if they promise to keep their kids in school and take them to the doctor.",left:{id:"a",label:"Pay the mothers to help the kids.",tooltip:"Money to a mother for her child's schooling pays back for decades.",reveal:"You build the scheme and the payments reach poor mothers. The delivery is a logistical mountain and the budget line permanent, but school attendance climbs and a poverty cycle starts to break.",effects:{EN:8,GL:3,FI:-13}},right:{id:"b",label:"Just give them free things instead of money.",tooltip:"A grand transfer scheme is a budget I cannot promise forever.",reveal:"You keep the patchy in-kind handouts instead. The budget is spared the permanent commitment, and the chance to bind relief to schooling and health is left on the table.",effects:{FI:3,EN:-6}}},{id:"finance-0234",location:"finance",arc:"finance-t1-a76",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["property-tax","wealth","elite"],prompt:"The crisis returns, and this time the cabinet is watching. Rich people have giant, empty houses that they don't pay taxes on. You can tax their houses to get money for the country.",left:{id:"a",label:"Tax the giant houses.",tooltip:"A palace should pay more than a payslip.",reveal:"You bring in a genuine property tax on the high end. The revenue base broadens onto idle wealth, the affluent grumble and lobby, and for once the rich shoulder a fair share.",effects:{FI:6,EN:5,FA:-10,GL:2}},right:{id:"b",label:"Let the rich people keep their houses untaxed.",tooltip:"The men in those mansions are the men who fund me.",reveal:"You leave the mansions and empty flats lightly taxed. The donors are content and their wealth stays idle and untouched, and the revenue gap is filled, as ever, by those who cannot dodge.",effects:{FA:3,FI:-6,EN:-10}}},{id:"finance-0235",location:"finance",arc:"finance-t1-a77",stage:0,speaker:"Revenue Board Chairman",portrait:"ambassador",tags:["digital-tax","big-tech","revenue"],prompt:"Once more the issue lands on your desk, the stakes higher than before. Big internet companies make lots of money in your country but pay no tax. You can make them pay, but they might get angry.",left:{id:"a",label:"Make the big internet companies pay tax.",tooltip:"A giant that earns here pays here.",reveal:"You tax the tech giants' local earnings. The revenue is real and popular, but the platforms threaten to throttle services and Washington adds it to a list of grievances against you.",effects:{FI:5,GL:-6,EN:2}},right:{id:"b",label:"Wait so they don't get angry.",tooltip:"A fight with the platforms and Washington at once is a fight I lose.",reveal:"You shelve the tax to keep the peace. The giants keep earning tax-free, the revenue stays forgone, and your dependence on their services and Washington's goodwill stays unchallenged.",effects:{GL:2,FI:-6}}},{id:"finance-0236",location:"finance",arc:"finance-t1-a78",stage:0,speaker:"Debt Management Director",portrait:"ambassador",tags:["diaspora-bond","infrastructure","funding"],prompt:"Another year survived, and the reckoning circles back. You can ask people from your country living far away to lend you money to build things. But if you lose it, they will be very hurt.",left:{id:"a",label:"Ask them to lend you the money.",tooltip:"Let the children abroad help build the home.",reveal:"The diaspora subscribes generously and the projects get cheap funding. You have also taken the savings of trusting expatriates, and any stumble in repayment would be a betrayal felt worldwide.",effects:{FI:5,GL:2,RE:2}},right:{id:"b",label:"Find the money somewhere else.",tooltip:"I will not stake my people's trust on a bond.",reveal:"You decline to tap the diaspora's savings. The funding is costlier and slower, but you do not put the expatriates' faith — and their remittances — on the line.",effects:{GL:2,FI:-6}}},{id:"finance-0237",location:"finance",arc:"finance-t1-a79",stage:0,speaker:"Agriculture Finance Secretary",portrait:"people",tags:["diesel","irrigation","subsidy"],prompt:"The ground has shifted; the same demand arrives with new menace. The gas farmers need to water their crops is too expensive. You can help pay for the gas, or let the farmers struggle.",left:{id:"a",label:"Help pay for the gas to save the crops.",tooltip:"A dry pump in boro season is a famine in waiting.",reveal:"You subsidise the diesel and the pumps keep running through the dry season. The crop is saved and the farmers grateful, at a heavy cost and with the usual leakage at the depots.",effects:{EN:6,RE:2,FI:-10}},right:{id:"b",label:"Let the farmers pay the high price.",tooltip:"I cannot subsidise the world's oil price for every pump.",reveal:"You let the diesel cost hit the field. The budget is spared, but the irrigation falters, the boro crop wobbles, and the spectre of a thin harvest looms over the year.",effects:{FI:3,EN:-10,RE:-3}}},{id:"finance-0238",location:"finance",arc:"finance-t1-a80",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["sin-tax","health","revenue"],prompt:"History rhymes: the conflict reopens deeper than last time. You can put a high tax on junk food and cigarettes so people buy less and stay healthy. But the people who make them will be mad.",left:{id:"a",label:"Put a high tax on junk food and cigarettes.",tooltip:"A tax that fills the treasury and empties the wards is a gift.",reveal:"You levy the sin taxes and revenue and health both improve. The lobbies fight and the public grumbles at pricier vices, but consumption of the worst products begins to fall.",effects:{FI:5,EN:5,FA:-6}},right:{id:"b",label:"Do not add the tax.",tooltip:"A new tax on small pleasures is a small revolt.",reveal:"You hold off on the sin taxes. The lobbies and the public are spared, and so is the disease and the revenue forgone, as the wards fill and the treasury stays thin.",effects:{FA:2,FI:-6,EN:-6}}},{id:"finance-0239",location:"finance",arc:"finance-t1-a81",stage:0,speaker:"Budget Secretary",portrait:"official",tags:["fiscal-rule","debt","discipline"],prompt:"Mid-reign, the old wound is torn afresh. You can make a strict law that stops the government from borrowing too much money. This makes you safe but stops you from spending freely.",left:{id:"a",label:"Make the strict law to be safe.",tooltip:"A state that cannot bind itself cannot be trusted.",reveal:"You pass the fiscal-responsibility law. The lenders cheer the credibility and the markets calm, and you have tied your own hands against the easy election-year splurge.",effects:{GL:5,FI:3,EN:-3}},right:{id:"b",label:"Keep the freedom to spend whatever you want.",tooltip:"A rule that forbids me to spend in a crisis is a trap.",reveal:"You decline the statutory cap. You keep the freedom to splurge when politics demands, and the lenders keep their doubt about whether the deficit will ever truly be controlled.",effects:{FI:-3,EN:2,GL:-6}}},{id:"finance-0240",location:"finance",arc:"finance-t1-a82",stage:0,speaker:"Large Taxpayer Unit Chief",portrait:"official",tags:["transfer-pricing","multinationals","evasion"],prompt:"The pressure you deferred has come due, larger now. Huge world companies are tricking the math so they don't pay taxes in your country. You can stop them, but they might leave.",left:{id:"a",label:"Stop their tricks and make them pay.",tooltip:"Profits earned here should be taxed here.",reveal:"You enforce transfer-pricing rules and claw back real revenue. The multinationals grumble and a few trim investment, but the era of booking local fortunes as foreign losses ends.",effects:{FI:6,GL:2,EN:2}},right:{id:"b",label:"Be gentle so they don't leave.",tooltip:"A spooked multinational takes its factory elsewhere.",reveal:"You go easy to protect the investment climate. The firms keep shifting their profits offshore tax-free, and the revenue you could have captured stays on a balance sheet in another country.",effects:{GL:2,FI:-10}}},{id:"finance-0241",location:"finance",arc:"finance-t1-a83",stage:0,speaker:"Agriculture Finance Secretary",portrait:"people",tags:["insurance","farmers","climate"],prompt:"A later term, and the quarrel has hardened into a test. Bad weather keeps destroying farmers' crops. You can create an insurance plan to protect them, but it costs a lot to set up.",left:{id:"a",label:"Create the insurance plan to protect them.",tooltip:"A farmer insured plants without fear.",reveal:"You stand up crop insurance for the climate-battered. The system is costly and complex to run, but a ruined harvest no longer means a ruined family, and the farmers plant with confidence.",effects:{EN:6,RE:2,FI:-10}},right:{id:"b",label:"Just give them a little help after the storms.",tooltip:"A whole insurance system is a luxury; relief is enough.",reveal:"You keep the patchy, after-the-fact relief. It is cheaper and simpler, and each disaster still sweeps another cohort of farmers from their land into the moneylender's grip.",effects:{FI:3,EN:-6}}},{id:"finance-0242",location:"finance",arc:"finance-t1-a84",stage:0,speaker:"Provident Fund Trustee",portrait:"official",tags:["pension-fund","investment","risk"],prompt:"The country has changed, but this fault line has not — only worsened. Workers' retirement money is safe but growing slowly. You can try to make it grow faster by investing in risky things, but they might lose it all.",left:{id:"a",label:"Try to make it grow faster in risky things.",tooltip:"Idle retirement money should work harder.",reveal:"You free the funds to invest in markets and infrastructure. Returns rise in good years, but the workers' retirements now ride the market's moods, and the temptation to steer them into pet projects is real.",effects:{FI:3,RE:2,EN:-6}},right:{id:"b",label:"Keep their money safe and boring.",tooltip:"A pensioner's savings are not a venture fund.",reveal:"You keep the funds in safe, dull government paper. The returns are modest, but the workers' retirements are not gambled on markets or raided for politically favoured schemes.",effects:{EN:3,FI:-3}}},{id:"finance-0243",location:"finance",arc:"finance-t1-a85",stage:0,speaker:"Stimulus Coordination Chief",portrait:"fixer",tags:["stimulus","sme","leakage"],prompt:"It returns, as these things do, with the patience gone. You have emergency money to save businesses. If you give it out fast, rich friends will grab it all. If you are careful, it will reach small shops.",left:{id:"a",label:"Give it out fast through the banks.",tooltip:"Speed saves firms; controls can come later.",reveal:"You disburse fast through the banks, and the big connected firms hoover up the lion's share. Many are saved, but the small firms that needed it most are left out, and the leakage is enormous.",effects:{FI:3,FA:3,EN:-10}},right:{id:"b",label:"Be careful and make sure small shops get it.",tooltip:"A stimulus that feeds the fed is no stimulus.",reveal:"You insist on a slower channel that reaches the genuinely small and informal. The big firms wait and grumble and a few fail in the delay, but the rescue reaches those it was meant for.",effects:{EN:6,FI:-6,FA:-6}}},{id:"finance-0244",location:"finance",arc:"finance-t1-a86",stage:0,speaker:"Securities Regulator",portrait:"shadow",tags:["ipo","market","manipulation"],prompt:"Years on, the matter is no longer private; the press is already circling. Rich people are playing a game with the stock market to steal from normal people.",left:{id:"a",label:"Make strict rules to keep it fair.",tooltip:"A market rigged at the listing is rotten at the root.",reveal:"You impose disciplined, fundamentals-based pricing. The listings slow and the insiders lose their easy killing, but the retail investor stops being the designated bag-holder.",effects:{GL:3,EN:5,FI:-3,FA:-3}},right:{id:"b",label:"Let the rich people keep playing their game.",tooltip:"A busy market looks like a healthy one.",reveal:"You let the rigged IPOs flow. The market looks vibrant and the insiders prosper, and the small investors who buy the dumped shares learn, again, who the market is really for.",effects:{FI:3,FA:2,EN:-10}}},{id:"finance-0245",location:"finance",arc:"finance-t1-a87",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["banks","exposure","concentration"],prompt:"The same knot, retied tighter, lands before you once more. A few giant businesses have borrowed almost all the money. If they fail, the country fails. You can force them to stop borrowing so much.",left:{id:"a",label:"Force them to stop borrowing so much.",tooltip:"A bank chained to one tycoon falls with him.",reveal:"You force the concentration down. The over-leveraged groups must deleverage and protest bitterly, but the banking system stops being hostage to a handful of empires.",effects:{FI:3,GL:3,EN:3,FA:-10}},right:{id:"b",label:"Let the giant businesses keep borrowing.",tooltip:"The great groups are the engines; do not stall them.",reveal:"You let the concentration ride. The tycoons keep borrowing freely and stay loyal, and the system's fate stays welded to a few balance sheets that are too big to fail and too connected to refuse.",effects:{FI:2,FA:3,EN:-6,GL:-6}}},{id:"finance-0246",location:"finance",arc:"finance-t1-a88",stage:0,speaker:"Banking Division Secretary",portrait:"fixer",tags:["banks","family-control","governance"],prompt:"Another monsoon, another return of an argument you cannot end. One family is allowed to control a whole bank forever, which makes it easy for them to steal. You can change the rule, but they are your friends.",left:{id:"a",label:"Change the rule to stop them from controlling it forever.",tooltip:"A bank run as a family fief gets looted as one.",reveal:"You cap family directorships and tenure. The banking dynasties rage and lean on their party ties, but the boards open up and the insider-looting machine loses its grease.",effects:{GL:5,EN:5,FI:2,FA:-13}},right:{id:"b",label:"Let them keep controlling the bank.",tooltip:"The banking families are pillars of the party.",reveal:"You keep the family-control law intact. The dynasties stay grateful and entrenched, and the next hollowed-out bank is already being quietly emptied by the board that owns it.",effects:{FA:5,FI:-3,EN:-10,GL:-6}}},{id:"finance-0247",location:"finance",arc:"finance-t1-a89",stage:0,speaker:"Tariff Commission Chief",portrait:"official",tags:["dumping","tariffs","industry"],prompt:"Deep into the reign, the issue demands a final-sounding answer. Super cheap toys and tools from other countries are hurting your own factories. You can tax them to save your jobs, but things will cost more.",left:{id:"a",label:"Tax the cheap foreign things to save your jobs.",tooltip:"A factory drowned in cheap imports is a town unemployed.",reveal:"You shield the domestic industry with duties. The local manufacturers and their workers are saved, the exporting nation protests to the trade body, and consumers pay more for the protected goods.",effects:{FI:2,EN:3,GL:-6}},right:{id:"b",label:"Keep the foreign things cheap for shoppers.",tooltip:"A consumer's cheap goods are a benefit too.",reveal:"You leave the market open. Consumers enjoy the cheap imports, but the domestic factories buckle and shed jobs, hollowing out the very industry you hoped to grow.",effects:{GL:2,FI:-3,EN:-6}}},{id:"finance-0248",location:"finance",arc:"finance-t1-a90",stage:0,speaker:"Budget Secretary",portrait:"official",tags:["soe","losses","transparency"],prompt:"The reckoning you postponed has matured into a crisis. Government factories are losing tons of money secretly. You can tell everyone the truth, which will be shocking, or keep hiding it.",left:{id:"a",label:"Tell the honest truth about the lost money.",tooltip:"A loss hidden is a debt compounding in the dark.",reveal:"You consolidate the hidden losses into the open budget. The true deficit number shocks, but the lenders respect the honesty and the bleeding enterprises can finally be confronted.",effects:{GL:5,EN:2,FI:-6}},right:{id:"b",label:"Keep hiding the lost money.",tooltip:"An ugly number published is a panic invited.",reveal:"You leave the SOE losses in the shadows. The headline deficit stays flattering, and the hidden hole keeps growing, funded by banks that will one day present the bill.",effects:{FI:3,GL:-10,EN:-3}}},{id:"finance-0249",location:"finance",arc:"finance-t1-a91",stage:0,speaker:"Anti-Money-Laundering Director",portrait:"ambassador",tags:["fatf","compliance","reputation"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. The world says your country lets bad guys hide stolen money. They will punish you unless you stop them, but the bad guys are your friends.",left:{id:"a",label:"Stop the bad guys to protect your country.",tooltip:"A grey-listed nation is a nation cut off.",reveal:"You build genuine anti-laundering enforcement and dodge the listing. Correspondent banking stays open and investors calm, but your backers' laundering channels are now watched, and they are furious.",effects:{GL:6,FI:3,FA:-10}},right:{id:"b",label:"Do nothing and let the world punish you.",tooltip:"I will not strangle my friends' money to please a watchdog.",reveal:"You make cosmetic changes and your backers keep their channels. The watchdog grey-lists you, correspondent banks pull back, and the cost of every cross-border transaction climbs.",effects:{FA:3,GL:-13,FI:-10}}},{id:"finance-0250",location:"finance",arc:"finance-t1-a92",stage:0,speaker:"Land Reform Commissioner",portrait:"official",tags:["benami","property","corruption"],prompt:"The old fault line widens; this time there is no quiet option. Powerful people hide their stolen houses by putting them in other people's names. You can make a law to catch them and take the houses.",left:{id:"a",label:"Make the law and take the stolen houses.",tooltip:"A fortune in a servant's name is a confession.",reveal:"You pass the law and begin piercing the false ownership. Illicit fortunes are exposed and some seized, and the powerful who hid behind nominees are suddenly, dangerously visible.",effects:{GL:5,EN:6,FI:3,FA:-13}},right:{id:"b",label:"Leave the hidden houses alone.",tooltip:"Too many of those names lead back to my own.",reveal:"You let the benami fortunes lie. The powerful keep their disguised wealth, the loophole stays wide open, and the corrupt accumulation of decades goes quietly unchallenged.",effects:{FA:5,FI:-3,EN:-10,GL:-6}}},{id:"finance-0251",location:"finance",arc:"finance-t1-a93",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["gold","smuggling","policy"],prompt:"Time has not healed it — the conflict comes back armed. People are secretly sneaking gold through your airports, and the police are helping them for money.",left:{id:"a",label:"Make it legal to bring gold in and charge a fair tax.",tooltip:"A trade taxed in daylight starves the smuggler.",reveal:"You open a legal, taxed gold-import channel. The smuggling syndicates lose their edge, the jewellers and the treasury gain, and a shadow trade is dragged into the light.",effects:{FI:5,GL:2,EN:2,FA:-3}},right:{id:"b",label:"Keep it illegal and try to catch them.",tooltip:"Legalising smuggling rewards the smuggler.",reveal:"You keep gold imports banned and chase the couriers. The headline seizures look tough, but the protected syndicates keep the bulk of the trade and the airport rackets stay golden.",effects:{MI:2,FI:-3,EN:-6}}},{id:"finance-0252",location:"finance",arc:"finance-t1-a94",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["vat-refund","drawback","fraud"],prompt:"Once again, and with the whole house holding its breath. People are tricking the government into giving them extra money for things they never really made or sold.",left:{id:"a",label:"Use computers to check everything and stop the trick.",tooltip:"A refund on a phantom export is theft with a stamp.",reveal:"You digitise and audit the refund system and the phantom claims collapse. Real exporters wait a little longer for genuine refunds, but a vast leak of public money is plugged.",effects:{FI:6,GL:2,FA:-6}},right:{id:"b",label:"Leave the system alone and let them trick it.",tooltip:"A crackdown punishes the honest exporter too.",reveal:"You leave the refund pipeline loose. The genuine exporters get their money fast, and so do the fraudsters claiming on exports that never existed, bleeding the treasury all the while.",effects:{FI:-6,FA:2,EN:-6}}},{id:"finance-0253",location:"finance",arc:"finance-t1-a95",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["bonded-warehouse","duty","diversion"],prompt:"The matter resurfaces in a harder year, patience exhausted. Factory owners get cheap materials to make things to sell far away, but they secretly sell them at home to get richer.",left:{id:"a",label:"Check their factories closely to stop the secret selling.",tooltip:"A duty-free import sold at home is smuggling by license.",reveal:"You audit the bonds and catch the diverters. Honest producers stop being undercut and the duty is recovered, and the connected abusers and their patrons turn on you.",effects:{FI:5,EN:3,FA:-6}},right:{id:"b",label:"Let the factory owners keep doing it.",tooltip:"The men running those bonds run the party's accounts.",reveal:"You leave the bonded scam alone. The diverted goods keep flooding the local market duty-free, honest producers keep losing, and the racket's patrons stay loyal and rich.",effects:{FA:3,FI:-6,EN:-6}}},{id:"finance-0254",location:"finance",arc:"finance-t1-a96",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["inheritance-tax","wealth","dynasty"],prompt:"A later season of rule, the stakes now openly existential. Very rich families pass down all their money to their kids without paying any taxes. You could tax this money to help the country.",left:{id:"a",label:"Make them pay a tax when they pass down money.",tooltip:"A fortune unearned should not pass wholly untouched.",reveal:"You levy a tax on great inheritances. Revenue rises and dynastic wealth loosens at the edges, and the established families — yours included — recoil at the precedent.",effects:{FI:5,EN:5,FA:-13}},right:{id:"b",label:"Let them pass down the money without any taxes.",tooltip:"I will not be the one to tax my own children's legacy.",reveal:"You spare inheritances the tax. The hereditary elite keeps its fortunes intact across generations, and the chance to broaden revenue and loosen dynastic wealth passes by.",effects:{FA:5,FI:-6,EN:-6}}},{id:"finance-0255",location:"finance",arc:"finance-t1-a97",stage:0,speaker:"Insurance Regulator",portrait:"people",tags:["microinsurance","poverty","resilience"],prompt:"It comes around again, and the margin for error is gone. Poor families lose everything if someone gets sick or a storm hits. You could help them buy cheap protection plans to keep them safe.",left:{id:"a",label:"Help them get cheap protection plans for bad days.",tooltip:"A few taka of cover stands between a family and ruin.",reveal:"You build subsidised, well-regulated microinsurance. The cost and oversight are real, but a flood or a funeral stops meaning the loss of everything for millions of poor households.",effects:{EN:6,FI:-6,GL:2}},right:{id:"b",label:"Let them figure it out on their own.",tooltip:"A whole insurance system for tiny premiums earns nothing.",reveal:"You leave the poor to their informal safety nets of debt and charity. The budget is spared, and the next flood or illness keeps sweeping families from the edge into destitution.",effects:{FI:2,EN:-10}}},{id:"finance-0256",location:"finance",arc:"finance-t1-a98",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["islamic-finance","sukuk","savings"],prompt:"The same demand, but the reign is older and the knives sharper. Many religious people won't put money in normal banks because of their religious rules. You can make special religious bank rules for them.",left:{id:"a",label:"Make true religious bank rules to help them.",tooltip:"Faith-shy savings can still build roads.",reveal:"You establish credible Islamic-finance rules and issue sukuk. A vast pool of pious savings enters the formal economy and funds development, and the framework's integrity wins trust.",effects:{FI:5,EN:3,GL:2}},right:{id:"b",label:"Just put a fake religious sticker on normal bank rules.",tooltip:"The label is what the market wants; the substance is detail.",reveal:"You relabel conventional products as Islamic without real substance. The savings trickle in, but the scholars cry foul, a mis-selling scandal brews, and trust in the whole sector frays.",effects:{FI:2,EN:-6,GL:-3}}},{id:"finance-0257",location:"finance",arc:"finance-t1-a99",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["deposit-insurance","savers","stability"],prompt:"Years deep, the unresolved returns to be resolved for good. Normal people lose all their money if a bank breaks. You can make banks pay a fee to keep people's money safe no matter what.",left:{id:"a",label:"Make the banks pay the fee to keep people's money safe.",tooltip:"A saver who fears for his deposit starts a run.",reveal:"You build real deposit insurance funded by a bank levy. The banks grumble at the cost, but small savers gain protection and the system gains a shock absorber against panic.",effects:{FI:3,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Let people risk losing their money.",tooltip:"A levy on the banks is a cost passed to the customer.",reveal:"You decline the scheme to spare the banks the levy. The savers stay exposed, and the next rumour about a weak bank empties its counters before the truth can catch up.",effects:{FI:2,EN:-10}}},{id:"finance-0258",location:"finance",arc:"finance-t1-a100",stage:0,speaker:"Education Finance Secretary",portrait:"people",tags:["stipend","girls","education"],prompt:"The conflict reignites, and the world is watching this time. The money you give poor kids, especially girls, to help them stay in school is too small. Giving them more would help, but it costs a lot.",left:{id:"a",label:"Give the kids more money to stay in school.",tooltip:"A stipend that keeps a girl in school changes a generation.",reveal:"You widen and raise the stipend. Enrolment climbs, child marriages slip later, and the budget takes a heavy permanent load for a payoff measured in decades.",effects:{EN:8,GL:3,FI:-13}},right:{id:"b",label:"Keep giving them only a tiny bit of money.",tooltip:"A generous stipend is a budget line forever.",reveal:"You keep the stipend lean. The budget is protected, but the poorest children — and the girls most at risk of early marriage — keep dropping out for want of a few taka.",effects:{FI:3,EN:-6}}},{id:"finance-0259",location:"finance",arc:"finance-t1-a101",stage:0,speaker:"Women's Affairs Finance Officer",portrait:"people",tags:["maternity","allowance","poverty"],prompt:"A familiar crisis, escalated by everything you let slide. Poor moms have to work very hard right until their babies are born. You can give them money so they can stay home and rest.",left:{id:"a",label:"Give the moms money to rest and care for their babies.",tooltip:"A nation that will not support its mothers stunts its future.",reveal:"You establish the maternity allowance. Mothers rest and nurse, infant health improves, and the budget carries a new permanent burden for a quietly transformative return.",effects:{EN:8,GL:3,FI:-10}},right:{id:"b",label:"Let them keep working and hope someone else helps.",tooltip:"A new allowance is a promise the budget cannot keep.",reveal:"You decline the allowance. The treasury is spared, and poor mothers keep labouring to the last day and back, the cost paid in their health and their children's.",effects:{FI:3,EN:-10}}},{id:"finance-0260",location:"finance",arc:"finance-t1-a102",stage:0,speaker:"Education Finance Secretary",portrait:"fixer",tags:["textbooks","printing","graft"],prompt:"The fault line cracks wider; the decision can no longer wait. The people printing free school books for kids are stealing money and making bad books. They are friends with your team.",left:{id:"a",label:"Fix the book printing so kids get good books.",tooltip:"A child's book should not be a printer's bribe.",reveal:"You open the tenders and enforce quality. The party-linked printing cartel rages and threatens delays, but the books arrive better and the graft shrinks.",effects:{EN:5,FI:2,GL:2,FA:-6}},right:{id:"b",label:"Let your friends keep stealing and making bad books.",tooltip:"The books arrive on time; do not break the machine.",reveal:"You leave the cosy contracts intact. The books arrive on schedule, flimsy and over-priced, and the printers' cartel stays a reliable, grateful funder of the party.",effects:{FA:3,FI:-3,EN:-6}}},{id:"finance-0261",location:"finance",arc:"finance-t1-a103",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["tax-net","informal","compliance"],prompt:"Late in the reign, the old question demands a heavier answer. Very few people pay taxes. You can ask normal workers and small stores to pay, but they will be very mad because they never have before.",left:{id:"a",label:"Make the normal workers and small stores pay taxes.",tooltip:"A nation where few pay is a nation few can fund.",reveal:"You launch the registration and enforcement drive. Revenue broadens onto those long outside the net, the new taxpayers grumble loudly, and the salaried at last get some company in paying.",effects:{FI:6,EN:3,FA:-6}},right:{id:"b",label:"Let them keep skipping their taxes.",tooltip:"A million new tax notices is a million new enemies.",reveal:"You hold off on the expansion. The informal middle keeps its untaxed cash, the revenue base stays narrow, and the few who do pay keep carrying the many who do not.",effects:{FA:2,FI:-6}}},{id:"finance-0262",location:"finance",arc:"finance-t1-a104",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["currency","redenomination","confidence"],prompt:"It returns once more — and this round may be the one remembered. Your money has too many zeros on it because prices went way up over the years. Someone wants to chop the zeros off just to make it look nicer.",left:{id:"a",label:"Chop the zeros off to make the money look nicer.",tooltip:"A proud currency wears fewer zeros.",reveal:"You lop the zeros off the taka in a grand relaunch. The notes look tidier and the optics flatter, and the costly, disruptive exercise changes nothing about the inflation that bloated them.",effects:{FI:-6,GL:2,EN:-3}},right:{id:"b",label:"Say no because it doesn't actually fix anything.",tooltip:"Zeros are a symptom; cutting them cures nothing.",reveal:"You spike the vanity project. There is no relaunch fanfare, but the money and disruption are saved, and you focus on the inflation that actually matters.",effects:{FI:3,GL:-3}}},{id:"finance-0263",location:"finance",arc:"finance-t1-a105",stage:0,speaker:"Financial Inclusion Director",portrait:"people",tags:["agent-banking","rural","inclusion"],prompt:"The reckoning circles back, grown teeth in the waiting. You can let tiny village shops act like banks so poor people can easily save money. Big banks are scared they will lose money from fraud.",left:{id:"a",label:"Let the tiny shops act like banks.",tooltip:"A bank counter in every bazaar banks the nation.",reveal:"You drive agent banking deep into the villages. The unbanked gain savings, credit, and payments for the first time, and the banks' fraud fears prove manageable against the reach gained.",effects:{EN:6,FI:3,GL:2}},right:{id:"b",label:"Let the big banks decide what to do.",tooltip:"A reckless rollout invites a fraud scandal.",reveal:"You leave the pace to the cautious banks. The fraud risk stays low, and so does the reach, and the villages keep waiting for a banking system that never quite arrives.",effects:{FI:2,EN:-6}}},{id:"finance-0264",location:"finance",arc:"finance-t1-a106",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["world-bank","conditions","reform"],prompt:"Another term, the same antagonist, the stakes raised again. A big world bank offers you cheap money, but only if you promise to follow their strict rules for how you run things.",left:{id:"a",label:"Take the money and follow their strict rules.",tooltip:"Cheap money and good medicine in one dose.",reveal:"You accept the budget support and enact the reforms. The cheap money helps and the governance genuinely improves, and the nationalists grumble about foreign hands on the tiller.",effects:{FI:5,GL:3,EN:2,FA:-3}},right:{id:"b",label:"Say no to the money so you can make your own rules.",tooltip:"I will not let a foreign bank write my budget.",reveal:"You turn down the conditional money on principle. You keep full policy control, but you forgo cheap finance and the reforms that, conditions aside, the country actually needed.",effects:{FA:2,FI:-10,GL:-3}}},{id:"finance-0265",location:"finance",arc:"finance-t1-a107",stage:0,speaker:"Labour Finance Inspector",portrait:"people",tags:["wage-theft","workers","enforcement"],prompt:"The matter, long deferred, lands with the force of a verdict. Bosses everywhere are tricking workers and not paying them their full money. You can create a strong police team to stop them.",left:{id:"a",label:"Create a strong team to make bosses pay the workers.",tooltip:"A wage withheld is a wage stolen.",reveal:"You stand up a unit that actually recovers stolen wages and fines the thieves. Workers start getting their due, the donor-employers cry harassment, and a quiet everyday injustice meets a check.",effects:{EN:6,GL:2,FI:-3,FA:-6}},right:{id:"b",label:"Let the workers fight the bosses on their own.",tooltip:"An employer hounded for back-pay closes the gate.",reveal:"You decline to build the unit. The employers keep their impunity, and the workers keep chasing wages already earned and rarely paid in full.",effects:{FA:3,FI:2,EN:-10}}},{id:"finance-0266",location:"finance",arc:"finance-t1-a108",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["recapitalisation","banks","bailout"],prompt:"Years on and unhealed, the conflict returns to claim its answer. Government banks are empty because bad managers stole the money. You need to give them more money to stay open.",left:{id:"a",label:"Give them the money with no extra rules.",tooltip:"A failed state bank cannot simply be allowed to die.",reveal:"You pour public money into the looted banks again, no questions asked. They limp on, the loopers and defaulters who emptied them face nothing, and the cycle is set to repeat.",effects:{FI:-6,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Give them the money but make them follow strict new rules.",tooltip:"I will not refill a bucket no one will fix.",reveal:"You make the bailout conditional on board purges, recoveries, and reform. The looters and their patrons fight it bitterly, but the public money goes in with at least a chance of staying.",effects:{GL:3,EN:3,FI:-6,FA:-10}}},{id:"finance-0267",location:"finance",arc:"finance-t1-a109",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["small-business","turnover-tax","simplicity"],prompt:"The same fault line, the harder hour, the narrower path. Tiny stores have to do really hard math to pay taxes. You can make it super easy for them, but you might collect less money overall.",left:{id:"a",label:"Make the taxes super easy for tiny stores.",tooltip:"A tax a shopkeeper can compute is a tax a shopkeeper pays.",reveal:"You bring in a flat, simple turnover tax for small firms. Compliance jumps as the paperwork and the bribes fall away, and the system gains millions of small, honest taxpayers.",effects:{FI:3,EN:5,FA:-3}},right:{id:"b",label:"Keep the hard math rules.",tooltip:"A flat tax leaves money on the table from the bigger fish.",reveal:"You keep the complex regime. The treasury squeezes more from the few who comply, and the rest stay outside, paying the assessor a bribe instead of the state a tax.",effects:{FI:2,EN:-6}}},{id:"finance-0268",location:"finance",arc:"finance-t1-a110",stage:0,speaker:"Central Bank Governor",portrait:"fixer",tags:["directed-lending","credit","distortion"],prompt:"It comes back sharpened by every season you survived. Your helpers want banks to give cheap money to businesses owned by your friends. The bank boss says this is a bad idea.",left:{id:"a",label:"Force the banks to give cheap money to your friends.",tooltip:"Credit steered to friends is friendship repaid.",reveal:"You direct the cheap credit to the favoured firms. They prosper on subsidised loans, the market distorts, and a fresh crop of politically-blessed bad loans begins to sprout.",effects:{FI:2,FA:3,EN:-6,GL:-6}},right:{id:"b",label:"Let the bank boss decide who gets the money safely.",tooltip:"Lending by favour is the seed of every banking crisis.",reveal:"You refuse to direct the credit. The favoured firms grumble at being denied their subsidy, but the banks lend on merit and the next wave of bad loans is not sown by decree.",effects:{GL:3,FI:2,EN:2,FA:-6}}},{id:"finance-0269",location:"finance",arc:"finance-t1-a111",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["interest-rate","inflation","growth"],prompt:"A later year of power, the old crisis now a true test of it. Everything in the stores costs too much. You can make it harder for people to borrow money to fix prices, but it slows down businesses.",left:{id:"a",label:"Make it harder to borrow money so prices drop.",tooltip:"Unchecked inflation robs every wage and saving.",reveal:"You tighten hard and inflation begins, slowly, to ease. Borrowing costs jump, growth cools, the business lobby howls, and the painful medicine works as medicine does.",effects:{FI:3,GL:3,EN:-10}},right:{id:"b",label:"Keep it easy to borrow money so businesses stay busy.",tooltip:"A choked economy is a poorer one for everyone.",reveal:"You keep rates low to protect growth and jobs. The business lobby is pleased and the expansion continues, and inflation keeps gnawing at every wage and every saving in the country.",effects:{EN:2,FI:-6,GL:-3}}},{id:"finance-0270",location:"finance",arc:"finance-t1-a112",stage:0,speaker:"Investment Authority Chief",portrait:"ambassador",tags:["fdi","screening","sovereignty"],prompt:"The unresolved returns, and this time it will not be deferred. Other countries want to buy your boat docks and phone companies. You can check them first to stay safe, or let anyone buy to get money fast.",left:{id:"a",label:"Check who is buying things to keep the country safe.",tooltip:"Some assets must not be owned from abroad.",reveal:"You set up a screening regime for strategic sectors. Some investment is deterred and the open-economy purists complain, but no single foreign power buys a chokehold on your ports or banks.",effects:{GL:2,MI:3,FI:-6}},right:{id:"b",label:"Let anyone from other countries buy whatever they want.",tooltip:"Capital is capital; the country needs it.",reveal:"You keep the door wide open. The investment flows in handsomely, and with it a foreign power's quiet acquisition of stakes in the infrastructure your security depends on.",effects:{FI:5,GL:2,MI:-6}}},{id:"finance-0271",location:"finance",arc:"finance-t1-a113",stage:0,speaker:"Land Reform Commissioner",portrait:"people",tags:["land-records","digitisation","corruption"],prompt:"A term later, the same fault line tears open again. The papers that show who owns land are messy and full of lies. You can use computers to fix it, but corrupt helpers will be mad.",left:{id:"a",label:"Use computers to make the land papers honest.",tooltip:"A clear title is the poor man's strongest shield.",reveal:"You drive the digitisation through against fierce resistance. The forgers and touts lose their racket, land litigation eases, and the poor gain titles that can finally be defended.",effects:{EN:6,GL:3,FI:2,FA:-6}},right:{id:"b",label:"Leave the messy papers alone.",tooltip:"Untangling a century of forgery is a war I cannot win.",reveal:"You leave the land-records chaos intact. The clerks and touts keep their lucrative fraud, the courts stay clogged with land disputes, and the powerful keep dispossessing the weak by forged deed.",effects:{FA:3,FI:-3,EN:-10}}},{id:"finance-0272",location:"finance",arc:"finance-t1-a114",stage:0,speaker:"Ports Finance Director",portrait:"official",tags:["port","efficiency","trade"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. Your big boat dock is too slow and messy. You can fix it with robots, but the bad groups who make money from the mess will fight you.",left:{id:"a",label:"Fix the dock and stop the bad groups.",tooltip:"A clogged port is a tax on every import and export.",reveal:"You automate the port and break the handling syndicates. The demurrage bill plummets and trade speeds up, and the displaced syndicate bosses and their political patrons declare war.",effects:{FI:5,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Leave the messy dock the way it is.",tooltip:"A port shutdown over reform would cripple the economy.",reveal:"You avoid the fight with the port syndicates. The congestion and demurrage grind on as a permanent drag, and the economy quietly pays the syndicates' toll on every container.",effects:{FA:2,FI:-6,GL:-3}}},{id:"finance-0273",location:"finance",arc:"finance-t1-a115",stage:0,speaker:"Digital Finance Adviser",portrait:"people",tags:["digital-payments","cash","transparency"],prompt:"A new season of power, an old problem with sharper teeth. Everyone uses paper money, making it easy to hide stealing. You can force people to pay with phones, but poor people might struggle.",left:{id:"a",label:"Force people to start paying with their phones.",tooltip:"Cash in the dark is where taxes go to die.",reveal:"You push hard for digital payments and the tax net widens as cash retreats. Corruption gets harder to hide, and the cash-poor and elderly struggle, needing support to keep up.",effects:{FI:5,EN:2,GL:2}},right:{id:"b",label:"Let people keep paying with paper money.",tooltip:"A nation forced cashless overnight abandons its poorest.",reveal:"You let the transition come gradually. No one is left stranded by a sudden cashless push, but the untraceable cash economy keeps shielding the evaders and the grafters.",effects:{EN:2,FI:-3}}},{id:"finance-0274",location:"finance",arc:"finance-t1-a116",stage:0,speaker:"Telecom Finance Director",portrait:"ambassador",tags:["spectrum","auction","revenue"],prompt:"The crisis returns, and this time the cabinet is watching. You are selling new invisible waves that make cell phones work. You can charge companies a lot, or sell them cheap so internet is cheaper for everyone.",left:{id:"a",label:"Charge a lot of money to make the government rich.",tooltip:"Spectrum is a one-time treasure; sell it dear.",reveal:"You squeeze the operators for a record auction haul. The treasury banks a windfall, and the operators, recouping it, keep data dear and coverage thin for years to come.",effects:{FI:6,EN:-6,RE:-3}},right:{id:"b",label:"Sell them cheap so people get cheaper phone internet.",tooltip:"Cheap data grows more than a one-time cheque.",reveal:"You price the spectrum to spur coverage and affordable data. The one-time haul is smaller, but cheap fast internet spreads, and the digital economy it feeds pays back for years.",effects:{EN:5,GL:2,FI:-6}}},{id:"finance-0275",location:"finance",arc:"finance-t1-a117",stage:0,speaker:"Aviation Finance Secretary",portrait:"fixer",tags:["airline","losses","soe"],prompt:"Once more the issue lands on your desk, the stakes higher than before. Your country's airplane company loses money every day because it's run badly. You keep paying to keep it flying to look cool.",left:{id:"a",label:"Fix the airplane company or sell it to someone else.",tooltip:"A flag that flies on subsidy flies on borrowed time.",reveal:"You force the restructuring, cutting the padded leases and the overstaffing. The unions and the brokers who profited rage, but the airline stops being a bottomless drain on the treasury.",effects:{FI:6,GL:2,EN:-10,FA:-6}},right:{id:"b",label:"Keep paying government money so it keeps flying.",tooltip:"A nation's airline is a nation's face.",reveal:"You keep the airline aloft on subsidy. The flag flies and the patronage flows, and the padded deals and graft keep the losses mounting flight after flight.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0276",location:"finance",arc:"finance-t1-a118",stage:0,speaker:"Fiscal Climate Adviser",portrait:"official",tags:["carbon-tax","climate","revenue"],prompt:"Another year survived, and the reckoning circles back. You can charge a tax on things that make dirty smoke. It helps the earth, but makes things more expensive for people who already don't have enough money.",left:{id:"a",label:"Start charging the dirty smoke tax.",tooltip:"The polluter should pay, and the treasury should collect.",reveal:"You bring in a carbon levy. Revenue rises, the economy nudges greener, and the climate donors approve, while industry and consumers feel one more cost in an already pinched year.",effects:{FI:3,EN:3,GL:3,RE:2}},right:{id:"b",label:"Don't charge the tax right now.",tooltip:"A new fuel levy amid inflation is a riot ordered in advance.",reveal:"You shelve the carbon tax. Industry and consumers are spared another cost, and the revenue, the green nudge, and the donor goodwill all go uncollected.",effects:{FI:-3,EN:-3,GL:-3}}},{id:"finance-0277",location:"finance",arc:"finance-t1-a119",stage:0,speaker:"Revenue Board Chairman",portrait:"shadow",tags:["capital-gains","stock-market","elite"],prompt:"The ground has shifted; the same demand arrives with new menace. Rich people who make a lot of money in the stock market don't pay taxes on it. If you tax them, they might crash the market on purpose.",left:{id:"a",label:"Make the rich people pay taxes on that money.",tooltip:"A fortune made on the bourse should pay like any other.",reveal:"You tax the big market gains. Revenue rises and fairness with it, the small investor is spared, and the big players stage a noisy sell-off and lean on every connection they have.",effects:{FI:5,EN:3,FA:-6}},right:{id:"b",label:"Let them keep the money without paying taxes.",tooltip:"A capital-gains tax could spook the whole bourse.",reveal:"You leave the gains untaxed to keep the market calm. The wealthy and the manipulators keep their tax-free windfalls, and the revenue and the fairness go uncollected.",effects:{FA:2,FI:-6,EN:-3}}},{id:"finance-0278",location:"finance",arc:"finance-t1-a120",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["imf","transparency","data"],prompt:"History rhymes: the conflict reopens deeper than last time. The big world bank wants to tell everyone the honest, ugly truth about your country's money problems. You can try to push them to hide it.",left:{id:"a",label:"Let them tell everyone the honest truth.",tooltip:"A diagnosis softened is a disease untreated.",reveal:"You let the IMF publish the unvarnished assessment. The numbers sting and the opposition feasts, but the lenders and markets reward the transparency, and the problems can finally be named.",effects:{GL:5,FI:-3,EN:-3}},right:{id:"b",label:"Push them to hide the bad parts of the story.",tooltip:"An honest report is a headline against me.",reveal:"You lean on the mission for a gentler write-up. The official narrative survives intact, the markets are soothed by a number that is not quite real, and the IMF's quiet doubts deepen.",effects:{FI:2,GL:-10}}},{id:"finance-0279",location:"finance",arc:"finance-t1-a121",stage:0,speaker:"Industrial Safety Secretary",portrait:"people",tags:["garments","safety","factories"],prompt:"Mid-reign, the old wound is torn afresh. A factory broke and fell down. Now everyone demands factories be made safer. Owners want your help to avoid paying for safety.",left:{id:"a",label:"Force the owners to make their factories super safe.",tooltip:"A factory that buries its workers is no asset.",reveal:"You enforce the retrofits hard, factory by factory. The owners howl at the cost and a few lines close, but the death-trap buildings are fixed and the buyers keep their orders.",effects:{EN:8,GL:5,FI:-6,FA:-6}},right:{id:"b",label:"Help the owners dodge the safety rules.",tooltip:"Protect the owners who keep a million employed.",reveal:"You help the owners paper over the accord. The retrofits go undone, the lines stay cheap, and the next fire or collapse is already being built into a building no one fixed.",effects:{FI:3,FA:3,EN:-16,GL:-10}}},{id:"finance-0280",location:"finance",arc:"finance-t1-a122",stage:0,speaker:"Tariff Commission Chief",portrait:"official",tags:["machinery","duty","industry"],prompt:"The pressure you deferred has come due, larger now. Factory bosses want to bring in big machines without paying taxes. But some of them trick you and bring in normal stuff to sell instead.",left:{id:"a",label:"Let them bring in all machines without taxes.",tooltip:"Cheap machines build modern factories.",reveal:"You open the duty-free channel wide. Genuine manufacturers re-tool cheaply, and the disguised-import racket revives alongside, smuggling finished goods in under the machinery label.",effects:{FI:-3,EN:3,RE:2}},right:{id:"b",label:"Check very carefully before letting anything in without taxes.",tooltip:"A loophole for machines becomes a loophole for everything.",reveal:"You permit duty-free machinery only with strict end-use verification. The honest manufacturers grumble at the paperwork, but the disguised-import loophole stays shut and the duty is protected.",effects:{FI:3,EN:2,FA:-3}}},{id:"finance-0281",location:"finance",arc:"finance-t1-a123",stage:0,speaker:"ICT Investment Director",portrait:"official",tags:["it","hi-tech-park","jobs"],prompt:"A later term, and the quarrel has hardened into a test. You can build a giant computer park to create smart jobs. If you don't spend enough money, it will just be empty buildings.",left:{id:"a",label:"Spend a lot to make the computer park amazing.",tooltip:"The future's factories are made of code.",reveal:"You back the park with reliable power, fibre, and incentives, and court real anchor tenants. The cost is high and the bet uncertain, but a genuine tech cluster and its skilled jobs begin to form.",effects:{EN:5,FI:-10,GL:2,RE:2}},right:{id:"b",label:"Build it cheaply and hope it works out.",tooltip:"A grand park half-empty is a grand embarrassment.",reveal:"You build a modest version and hope tenants come. The cost is contained, but without serious infrastructure and incentives the park risks joining the country's collection of hollow monuments.",effects:{FI:-3,EN:2}}},{id:"finance-0282",location:"finance",arc:"finance-t1-a124",stage:0,speaker:"SME Finance Director",portrait:"people",tags:["women","entrepreneurs","credit"],prompt:"The country has changed, but this fault line has not — only worsened. Women who want to start small shops can't borrow money from banks. You can create a special fund just to help them.",left:{id:"a",label:"Create the special fund to help women start shops.",tooltip:"Half the talent locked out is half the economy lost.",reveal:"You build the dedicated fund. Default risk runs higher and the bankers grumble, but a wave of women-led businesses opens, and a vast pool of stifled enterprise finally finds capital.",effects:{EN:6,FI:-6,GL:2}},right:{id:"b",label:"Let the banks treat everyone the same.",tooltip:"Special funds breed special defaults.",reveal:"You keep credit 'neutral', which in practice means collateral-bound and male. The default risk stays low and the bankers content, and women entrepreneurs keep borrowing from family or not at all.",effects:{FI:2,EN:-6}}},{id:"finance-0283",location:"finance",arc:"finance-t1-a125",stage:0,speaker:"Planning Commission Member",portrait:"fixer",tags:["mp-fund","patronage","local"],prompt:"It returns, as these things do, with the patience gone. Your politicians get a big bag of money every year to fix their towns. Most of them use it to build their own houses or help friends.",left:{id:"a",label:"Keep giving the politicians the bag of money.",tooltip:"An MP without a chequebook is an MP without friends.",reveal:"You keep the funds flowing to the MPs. They build loyalty and the occasional genuine road, and skim and steer the rest to their own contractors and kin, audited by no one.",effects:{FA:5,MI:2,EN:-10,FI:-3}},right:{id:"b",label:"Give the money to honest town leaders instead.",tooltip:"Development should follow a plan, not a member's whim.",reveal:"You move the money to audited local councils. The MPs lose a treasured lever and seethe, but the development spreads by need and plan rather than by the member's favour.",effects:{EN:6,GL:3,FA:-10}}},{id:"finance-0284",location:"finance",arc:"finance-t1-a126",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["rating","markets","reform"],prompt:"Years on, the matter is no longer private; the press is already circling. The world will say your country is bad with money unless you raise taxes and cut help for the poor. People will hate you for it.",left:{id:"a",label:"Raise taxes to prove you are good with money.",tooltip:"A downgrade taxes every loan for a decade.",reveal:"You enact the painful reforms and stave off the downgrade. The public feels the squeeze and grumbles, but the rating holds and the country's future borrowing stays affordable.",effects:{GL:3,FI:3,EN:-13}},right:{id:"b",label:"Ignore the world and keep people happy for now.",tooltip:"I will not cut subsidies to please a foreign rating.",reveal:"You spare the public the reforms and take the downgrade. The politics stay calm now, and every loan the country raises henceforth carries a higher price for the rating you let slip.",effects:{EN:3,FI:-10,GL:-6}}},{id:"finance-0285",location:"finance",arc:"finance-t1-a127",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["allowance","veterans","spending"],prompt:"The same knot, retied tighter, lands before you once more. The list of old war heroes who get free money is growing because people are lying and faking papers. You can clean the list up.",left:{id:"a",label:"Check the papers and kick the liars off the list.",tooltip:"A forged certificate dishonours the real heroes.",reveal:"You audit the rolls and strip out the forgeries. The genuine veterans are honoured and the fraud purged, and the cleansing of a sacred list draws furious accusations of disrespect.",effects:{FI:3,GL:2,EN:2,FA:-6}},right:{id:"b",label:"Keep paying everyone on the list to avoid anger.",tooltip:"I will not be the one to question a freedom-fighter's claim.",reveal:"You leave the rolls untouched. The genuine and the forged draw the honour allowance alike, the sacred constituency stays placated, and the fraud quietly bloats the budget line.",effects:{FA:5,FI:-6,EN:-3}}},{id:"finance-0286",location:"finance",arc:"finance-t1-a128",stage:0,speaker:"Transport Economy Adviser",portrait:"people",tags:["gig-economy","ride-share","workers"],prompt:"Another monsoon, another return of an argument you cannot end. Delivery and driving apps give young people jobs, but the bosses don't protect them or pay them enough.",left:{id:"a",label:"Make strong rules to protect the delivery drivers.",tooltip:"A job with no floor is a trap with an app.",reveal:"You impose minimum earnings, insurance, and dispute rights on the platforms. Fares rise a little and the apps threaten to scale back, but a precarious workforce gains a measure of security.",effects:{EN:6,FI:-3,GL:2}},right:{id:"b",label:"Leave the apps alone so prices stay cheap.",tooltip:"Cheap rides and easy work are their own reward.",reveal:"You leave the platforms free. Fares stay low and the apps expand, and the young riders and drivers keep working without a floor, a benefit, or a safety net beneath them.",effects:{FI:2,EN:-10}}},{id:"finance-0287",location:"finance",arc:"finance-t1-a129",stage:0,speaker:"Commerce Envoy",portrait:"ambassador",tags:["fta","regional","trade"],prompt:"Deep into the reign, the issue demands a final-sounding answer. You can make a deal to trade freely with neighbors. It helps sell your things, but cheap neighbor things might close your own shops.",left:{id:"a",label:"Sign the deal to trade freely with neighbors.",tooltip:"A market opened both ways favours the competitive.",reveal:"You sign the FTA and your exporters gain access to vast new markets. Some domestic industries, undercut by cheaper imports, buckle and shed jobs, and the adjustment is wrenching.",effects:{GL:5,FI:2,EN:-6}},right:{id:"b",label:"Say no to protect your own small shops.",tooltip:"Free trade with a giant is a flood with a treaty.",reveal:"You decline the deal to shield domestic industry. The home producers are protected and the jobs held, but your exporters lose the access, and the integration the region is moving toward leaves you behind.",effects:{EN:2,FI:-3,GL:-6}}},{id:"finance-0288",location:"finance",arc:"finance-t1-a130",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["stamp-duty","property","informality"],prompt:"The reckoning you postponed has matured into a crisis. The tax to buy a house is so high that everyone lies about the price. If you lower the tax, more people might be honest.",left:{id:"a",label:"Lower the tax to make people honest.",tooltip:"A rate too high is a rate evaded.",reveal:"You slash the stamp duty. Declarations jump toward honesty, the property market quickens, and after a brief dip the revenue actually rises as the under-declaration racket collapses.",effects:{FI:3,EN:3,GL:2}},right:{id:"b",label:"Keep the high tax just in case.",tooltip:"A rate cut is a revenue cut I cannot risk now.",reveal:"You keep the duty high. The headline rate looks lucrative, and the universal under-declaration keeps fuelling black money while the treasury collects on fictional sale prices.",effects:{FI:-3,EN:-3}}},{id:"finance-0289",location:"finance",arc:"finance-t1-a131",stage:0,speaker:"Industries Secretary",portrait:"people",tags:["sme","manufacturing","cluster"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. Poor, tiny workshops make important parts for your machines. You can give them training and money to grow big, or ignore them for flashier things.",left:{id:"a",label:"Help the tiny workshops grow and become better.",tooltip:"A nation that makes its own parts depends on no one's.",reveal:"You back the workshops with credit, training, and standards. The transformation is slow and unglamorous, but an import-substituting manufacturing base — and skilled jobs — takes root.",effects:{EN:5,FI:-6,RE:2}},right:{id:"b",label:"Ignore them and focus on big, shiny projects.",tooltip:"Workshops do not make headlines.",reveal:"You steer support to glossier projects instead. The flagship announcements dazzle, and the unsung workshops that actually keep industry running stay starved and stuck.",effects:{GL:2,FI:-3,EN:-3}}},{id:"finance-0290",location:"finance",arc:"finance-t1-a132",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["adb","loan","megaproject"],prompt:"The old fault line widens; this time there is no quiet option. A bank offers cheap money to build a road, but they demand you build it perfectly without any cheating or stealing by your builders.",left:{id:"a",label:"Take the money and build the road perfectly.",tooltip:"Cheap money and clean procurement together.",reveal:"You take the soft loan and accept the rigorous conditions. The build is slower and the contractors are denied their padding, but the corridor is cheaply financed and honestly built.",effects:{FI:3,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Use your own money so your builders can do what they want.",tooltip:"I will not let a bank's auditors run my project.",reveal:"You skip the conditional loan and finance it domestically. The contractors get their padding and the speed they want, and the project costs more, runs dirtier, and strains the budget.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0291",location:"finance",arc:"finance-t1-a133",stage:0,speaker:"Central Bank Governor",portrait:"shadow",tags:["currency","high-note","black-money"],prompt:"Time has not healed it — the conflict comes back armed. You can print a really big piece of money. It makes carrying cash easy, but also makes it super easy for bad guys to hide stolen money.",left:{id:"a",label:"Print the really big piece of money.",tooltip:"A bigger note is a smaller suitcase.",reveal:"You print the big note. Large cash deals get easier for everyone, including the hoarders, bribers, and launderers who can now move fortunes in a slim envelope.",effects:{FI:2,EN:-6,GL:-3}},right:{id:"b",label:"Don't print it.",tooltip:"A big note is a bribe's best friend.",reveal:"You refuse the high-denomination note. Large cash deals stay bulky and a little harder to hide, a small friction against the corruption that thrives on portable wealth.",effects:{GL:2,EN:2}}},{id:"finance-0292",location:"finance",arc:"finance-t1-a134",stage:0,speaker:"Urban Economy Officer",portrait:"people",tags:["vendors","informal","licensing"],prompt:"Once again, and with the whole house holding its breath. People selling food on the street have to pay bad police officers every day to not get kicked out. You can give them real licenses.",left:{id:"a",label:"Give the street sellers real licenses so they are safe.",tooltip:"A hawker licensed is a hawker freed from the mastan.",reveal:"You license the vendors and assign them zones. The police and mastans lose their daily extortion and resent it, but the vendors gain legal standing and the footpaths get some order.",effects:{EN:6,FI:2,MI:-3,FA:-3}},right:{id:"b",label:"Keep kicking them out of the streets.",tooltip:"The footpaths belong to the pedestrian.",reveal:"You keep mounting eviction drives that scatter the vendors for a day before they return. The bribes keep flowing to police and mastans, and nothing actually changes but the optics.",effects:{MI:2,FI:-3,EN:-10}}},{id:"finance-0293",location:"finance",arc:"finance-t1-a135",stage:0,speaker:"Railway Finance Secretary",portrait:"people",tags:["railway","losses","subsidy"],prompt:"The matter resurfaces in a harder year, patience exhausted. Government trains lose money on every ride because tickets are so cheap. But poor people need those cheap trains.",left:{id:"a",label:"Make the tickets cost more and fire extra workers.",tooltip:"A railway that bankrupts itself serves no one long.",reveal:"You raise fares, curb the ticketless, and trim the bloat. The losses narrow and the service steadies, but the poor who depend on cheap travel feel the pinch and the unions strike.",effects:{FI:5,EN:-10,FA:-3}},right:{id:"b",label:"Keep the tickets super cheap and lose money.",tooltip:"The train is the poor man's only affordable distance.",reveal:"You keep fares low and the trains rolling at a loss. The poor keep their cheap lifeline, and the railway keeps draining the budget, its graft and overstaffing untouched.",effects:{EN:5,FI:-10}}},{id:"finance-0294",location:"finance",arc:"finance-t1-a136",stage:0,speaker:"Industries Secretary",portrait:"doctor",tags:["pharma","api","self-reliance"],prompt:"A later season of rule, the stakes now openly existential. Your medicine makers buy all their magic ingredients from other countries. You can build a special park to make the ingredients at home.",left:{id:"a",label:"Build the special park to make the magic ingredients.",tooltip:"An industry that imports its core imports its fate.",reveal:"You commit to the API park. The investment is heavy and the payoff years away, but the pharma industry begins to make its own ingredients and an export edge sharpens.",effects:{FI:-6,EN:3,GL:2,RE:2}},right:{id:"b",label:"Keep buying them from other countries.",tooltip:"Why build what I can buy?",reveal:"You keep relying on imported ingredients. The capital is saved, and the industry stays one foreign supply-shock away from a shortage of the medicines the country and its exports depend on.",effects:{FI:2,EN:-3,GL:-3}}},{id:"finance-0295",location:"finance",arc:"finance-t1-a137",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["sim-tax","internet","access"],prompt:"It comes around again, and the margin for error is gone. Phones and internet are taxed heavily to get the government money. But this makes it too expensive for poor people to use the internet.",left:{id:"a",label:"Keep the high taxes to make the government rich.",tooltip:"A connected nation can spare a few taka per gigabyte.",reveal:"You raise the connectivity taxes and the revenue flows easily. Data and phones get dearer, the rural poor and the digital economy both feel it, and a regressive levy deepens.",effects:{FI:5,EN:-10}},right:{id:"b",label:"Lower the taxes so poor people can use the internet.",tooltip:"A tax on data is a tax on the future.",reveal:"You cut the SIM and data taxes. The easy revenue is forgone, but cheaper connectivity spreads to the rural poor and feeds the digital economy that pays back many times over.",effects:{EN:5,GL:2,FI:-6}}},{id:"finance-0296",location:"finance",arc:"finance-t1-a138",stage:0,speaker:"Cottage Industry Director",portrait:"people",tags:["handloom","heritage","artisans"],prompt:"The same demand, but the reign is older and the knives sharper. People who make beautiful clothes by hand are going out of business because machines are faster. You can step in to save their art.",left:{id:"a",label:"Give them money and help so they can keep making clothes by hand.",tooltip:"A craft lost is a heritage no money rebuilds.",reveal:"You back the weavers with credit, design, and a protected heritage label. The cost is modest and the market still hard, but a dying craft and the communities who keep it get a fighting chance.",effects:{EN:5,GL:2,FI:-6}},right:{id:"b",label:"Do nothing and let the machines win.",tooltip:"Nostalgia cannot outcompete a power loom.",reveal:"You let the handloom communities fend for themselves. The cheaper power-loom goods win, the looms fall silent one village at a time, and a centuries-old craft fades toward memory.",effects:{FI:2,EN:-6}}},{id:"finance-0297",location:"finance",arc:"finance-t1-a139",stage:0,speaker:"Export Zone Authority Chief",portrait:"people",tags:["epz","wages","investment"],prompt:"Years deep, the unresolved returns to be resolved for good. Special factory zones ban workers from grouping up to ask for better pay. If you let them group up, the foreign owners might get scared and leave.",left:{id:"a",label:"Let the workers group up and ask for better pay.",tooltip:"A showcase built on suppressed wages shames the show.",reveal:"You lift the EPZ wage and permit unions. Some investors grumble and threaten to look elsewhere, but the zone workers gain dignity and pay, and the showcase stops being a sweatshop with landscaping.",effects:{EN:6,GL:3,FI:-6,FA:-3}},right:{id:"b",label:"Keep the ban so the foreign owners stay happy.",tooltip:"The investors came for the cheap, calm labour.",reveal:"You keep the zones cheap and union-free. The investors stay content and the FDI flows, and the zone workers keep earning below the national floor with no voice to change it.",effects:{FI:5,FA:2,EN:-13,GL:-3}}},{id:"finance-0298",location:"finance",arc:"finance-t1-a140",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["advance-tax","compliance","burden"],prompt:"The conflict reignites, and the world is watching this time. The government secretly takes a little tax money from almost everything people do. It's easy money, but it is very unfair to poor people.",left:{id:"a",label:"Fix the taxes so they are fair to everyone.",tooltip:"A tax collected before profit is a tax on existence.",reveal:"You prune the tangle of advance taxes. Collection gets a little harder and revenue dips short-term, but the hidden burden on the small and the consumer eases and the system grows fairer.",effects:{EN:5,GL:2,FI:-6}},right:{id:"b",label:"Keep taking the easy, secret tax money.",tooltip:"A tax collected at source is a tax that does not escape.",reveal:"You keep the advance-tax web intact. Collection stays easy and leak-proof, and the hidden, regressive burden goes on falling hardest on those least able to reclaim it.",effects:{FI:3,EN:-6}}},{id:"finance-0299",location:"finance",arc:"finance-t1-a141",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["budget","deficit","populism"],prompt:"A familiar crisis, escalated by everything you let slide. Your friends want to promise to give away tons of free stuff right before an election to win votes, even though you don't have the money.",left:{id:"a",label:"Promise to give away tons of free stuff to win.",tooltip:"A budget is a promise, and promises win votes.",reveal:"You unveil the record-shattering budget to fanfare. The schemes dazzle and the votes warm, and the fantastical revenue forecasts collapse within months, forcing painful cuts you will own.",effects:{EN:5,FI:-13,GL:-6}},right:{id:"b",label:"Be honest and only promise what you can afford.",tooltip:"A budget built on fantasy is a crisis with a launch date.",reveal:"You table a realistic budget the numbers actually support. The cabinet grumbles that it lacks fireworks for the campaign, but the lenders trust it and no mid-year reckoning lies in wait.",effects:{GL:5,FI:3,EN:-3}}},{id:"finance-0300",location:"finance",arc:"finance-t1-a141",stage:1,speaker:"Budget Secretary",portrait:"fixer",tags:["budget","deficit","populism"],prompt:"The fault line cracks wider; the decision can no longer wait. You promised to build lots of things, but the money is gone. You can just announce more fake projects to look good, or quietly finish the old ones.",left:{id:"a",label:"Announce more fake projects to look good.",tooltip:"A ribbon cut is worth more than a road finished.",reveal:"You keep launching glittering new schemes over the unfinished ones. The headlines flow, the backlog of half-built promises grows, and the public learns that an announcement here rarely becomes a thing.",effects:{FA:2,EN:-10,FI:-3}},right:{id:"b",label:"Finish what you started and don't make new promises.",tooltip:"A promise kept quietly beats ten announced loudly.",reveal:"You stop the announcement treadmill and fund the existing commitments to completion. There are fewer ribbons to cut, but the schools, roads, and clinics already promised actually get built.",effects:{EN:6,GL:2,FI:-6}}}];export{e as f};
